IF NOT EXISTS (SELECT * FROM sys.triggers WHERE object_id = OBJECT_ID(N'[dbo].[TRDOCARD1R]'))
EXEC dbo.sp_executesql @statement = N'/* Création du trigger de mise à jour de la table d''exportation (DDA1TT) */
/* lorsque le code document archivé est mis-à-jour.                      */
CREATE TRIGGER [dbo].[TRDOCARD1R] ON [dbo].[ARAPREP]
FOR INSERT, UPDATE
AS
/* Contrôle si le code document archivé est modifié */
IF UPDATE(APBAST)
	BEGIN

	/* Test si la valeur en entrée est égale à oui            */
	/* pour cela, on compte les éléments de la table INSERTED */
	/* ayant le code document archivé à la valeur ''O''         */
	IF ((SELECT COUNT (*) FROM INSERTED WHERE APBAST = ''O'') > 0) 
		BEGIN 

		/* Déclaration d''une variable temporaire pour l''affectation dans la table DDA1TT */
		DECLARE @DocumentName char(12)
		DECLARE @DocumentType char(8)
		
		/* Déclaration du curseur pour la recherche du nom et */
		/* du type de document dans la table insert           */
		/* il est possible d''avoir plusieurs records dans les */
		/* tables INSERTED et DELETED                         */
		DECLARE cur_doc_ins CURSOR
		FOR
		SELECT APASVN, APAFCD FROM INSERTED
		
		/* Création du curseur */
		OPEN cur_doc_ins

		/* Si aucun élément se trouve dans la table insert, on arrête la procédure */
		IF @@CURSOR_ROWS = 0
			BEGIN
				DEALLOCATE cur_doc_ins
				RETURN
			END

		/* se positionne sur la première ligne du curseur */
		FETCH NEXT FROM cur_doc_ins INTO @DocumentName, @DocumentType


		/* Parcour tous les éléments stockés dans la table d''insertion */
		WHILE @@FETCH_STATUS = 0
			BEGIN


			/* pour remplir la condition, il faut que le nombre de documents ayant le code  */
			/* archivé (APBAST) à Oui (O) pour le document en cours de la table d''insertion */
			/* soit plus grand que zéro ou que le document en cours n''existe pas dans la    */
			/* table de suppression                                                         */	
			IF (((SELECT COUNT(*) FROM DELETED WHERE APBAST <> ''O'' AND APASVN = @DocumentName) > 0)  
				OR ((SELECT COUNT(*) FROM DELETED WHERE APASVN = @DocumentName) = 0))
				BEGIN

			
				/* Recherche dans la table des types de documents si */
				/* un type de document correspondant existe          */
				IF ((SELECT COUNT(*) FROM ARAHREP WHERE ARAHREP.AHAFCD  = @DocumentType 
					AND ARAHREP.AHAFPA <> '''') > 0)
					BEGIN
					
					/* Ajout du document dans la table de conversion */
					INSERT INTO DDA1TT (DD10A, DD1RA, DDA1UA, DDA1VA, DDCXCA, DDCM3A, DDEO9A)
						VALUES( '''', @DocumentName, 0, '''', ''R'', '''', '''')

					/* Modification de la table des documents pour    */
					/* bloquer les options de la GED                  */
					UPDATE ARAPREP
						SET APKCST = ''C''
						FROM ARAPREP t1, INSERTED t2
						WHERE t1.APASVN = t2.APASVN	

					END

				END
				/* Positionne le curseur sur le prochain élément */
				FETCH NEXT FROM cur_doc_ins INTO @DocumentName, @DocumentType
					
			END
			
		/* Ferme le curseur et le libère la mémoire */
		CLOSE cur_doc_ins
		DEALLOCATE cur_doc_ins

		END
		
	END
'
GO
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
