/*-----------------------------------------------------------------------------------------------------*/

IF NOT EXISTS (SELECT * FROM dbo.sysindexes WHERE name = N'ARG0CPL1_IX' and id = object_id(N'[dbo].[ARG0CPP]'))
 CREATE NONCLUSTERED INDEX [ARG0CPL1_IX] ON [dbo].[ARG0CPP] 
(
	[DDr68A] ASC
)WITH (PAD_INDEX  = OFF, STATISTICS_NORECOMPUTE  = OFF, SORT_IN_TEMPDB = OFF, IGNORE_DUP_KEY = OFF, 
DROP_EXISTING = OFF, ONLINE = OFF, ALLOW_ROW_LOCKS  = ON, ALLOW_PAGE_LOCKS  = ON) ON [PRIMARY]
GO

/*------------------------------------------------------------------------------------------------------*/
/* Ajout heure de création sur ARARREP      						 */
/*-----------------------------------------------------------------------------------------------------*/

IF NOT EXISTS ( SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME='ARARREP' AND COLUMN_NAME='ARACTM' ) 
begin
ALTER TABLE ARARREP ADD ARACTM NUMERIC (6,0) NOT NULL DEFAULT 0
end



/*------------------------------------------------------------------------------------------------------*/
/* Création des nouvelles tables commentaires                                                             */
/*-----------------------------------------------------------------------------------------------------*/

IF NOT EXISTS (SELECT * FROM dbo.sysobjects WHERE id = object_id(N'[DDCLOB]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
BEGIN
CREATE TABLE [dbo].[DDCLOB](
	[TSCID] [numeric](9, 0) NOT NULL,
	[TSCSEQ] [numeric](4, 0) NOT NULL,
	[TSCTYPE] [char](5) NULL,
	[TSCLOB] [text] NULL,
PRIMARY KEY CLUSTERED 
(
	[TSCID] ASC,
	[TSCSEQ] ASC
)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON) ON [PRIMARY]
) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]
END
GO

