IF NOT EXISTS (SELECT * FROM dbo.sysobjects WHERE id = object_id(N'[DDrhvT]') and OBJECTPROPERTY(id, N'IsUserTable') = 1)
BEGIN
CREATE TABLE [dbo].[DDrhvT](
	[DD1rA] [varchar](12) NOT NULL,
