/*------------------------------------------------------------------------------------------------------*/
/* Mise à jour ARARREP (problème de mise à jour du type de document)                   */
/*-----------------------------------------------------------------------------------------------------*/

UPDATE ARARREP SET ARARREP.ARASCD = ARAPREP.APAFCD FROM ARARREP INNER JOIN ARAPREP ON ARARREP.ARASVN = ARAPREP.APASVN WHERE ARARREP.ARASVN = ARAPREP.APASVN AND ARARREP.ARASCD != ARAPREP.APAFCD



