-- These queries are used to update OP8wT and long name support columns
DECLARE @tmp varchar(200)
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'OP8wT'
						AND COLUMN_NAME = 'OP1K9A')
	BEGIN
		--only add default value when it does not exist
		IF NOT EXISTS
	 		(SELECT default_constraints.name FROM
		    sys.all_columns,sys.tables,sys.schemas,sys.default_constraints
			WHERE   all_columns.object_id = tables.object_id and
				tables.schema_id = schemas.schema_id and
				all_columns.default_object_id = default_constraints.object_id and
		    	tables.name = 'OP8wT' and
		    	all_columns.name = 'OP1K9A')
			ALTER TABLE OP8wT ADD CONSTRAINT OP1K9A_VALUE_DEFAULT DEFAULT N'' FOR OP1K9A
		ELSE
			IF (SELECT DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'OP8wT' AND COLUMN_NAME = 'OP1K9A') <> 'varchar'
				BEGIN
					-- we do not use index OP8WT_IX1 anymore so there is no need to create it again
					IF EXISTS (SELECT name FROM sys.indexes WHERE name='OP8WT_IX1' AND object_id = OBJECT_ID('OP8wT'))
						DROP INDEX OP8WT_IX1 ON OP8wT
					SET @tmp = (SELECT default_constraints.name FROM
												sys.all_columns,sys.tables,sys.schemas,sys.default_constraints
												WHERE   all_columns.object_id = tables.object_id and
													tables.schema_id = schemas.schema_id and
													all_columns.default_object_id = default_constraints.object_id and
		    										tables.name = 'OP8wT' and
		    										all_columns.name = 'OP1K9A')
					IF @tmp <> '' EXEC('ALTER TABLE OP8wT DROP CONSTRAINT ' + @tmp)
					ALTER TABLE OP8wT ALTER COLUMN OP1K9A varchar(1024) NOT NULL
					IF @tmp <> '' EXEC('ALTER TABLE OP8wT ADD CONSTRAINT ' + @tmp + ' DEFAULT N'''' FOR OP1K9A')
				END
	END
ELSE
	ALTER TABLE OP8wT ADD OP1K9A VARCHAR (1024) NOT NULL DEFAULT ''

IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'OP8wT'
						AND COLUMN_NAME = 'OP1KAA')
