				BEGIN
					SET @tmp = (SELECT default_constraints.name FROM
												sys.all_columns,sys.tables,sys.schemas,sys.default_constraints
												WHERE   all_columns.object_id = tables.object_id and
													tables.schema_id = schemas.schema_id and
													all_columns.default_object_id = default_constraints.object_id and
													tables.name = 'OP8wT' and
													all_columns.name = 'OP1KAA')
					IF @tmp <> '' EXEC('ALTER TABLE OP8wT DROP CONSTRAINT ' + @tmp)
					ALTER TABLE OP8wT ALTER COLUMN OP1KAA varchar(1024) NOT NULL
					IF @tmp <> '' EXEC('ALTER TABLE OP8wT ADD CONSTRAINT ' + @tmp + ' DEFAULT N'''' FOR OP1KAA')
				END
	END
ELSE
	ALTER TABLE OP8wT ADD OP1KAA VARCHAR (15) NOT NULL DEFAULT ''

IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'OP8wT'
