	BEGIN
		--only add default value when it does not exist
		IF NOT EXISTS
	 		(SELECT default_constraints.name FROM
				sys.all_columns,sys.tables,sys.schemas,sys.default_constraints
				WHERE   all_columns.object_id = tables.object_id and
