			ALTER TABLE dbo.OP8wT ADD CONSTRAINT OP1KBA_VALUE_DEFAULT DEFAULT N'' FOR OP1KBA
		ELSE
			IF (SELECT DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'OP8wT' AND COLUMN_NAME = 'OP1KBA') <> 'varchar'
				BEGIN
					SET @tmp = (SELECT default_constraints.name FROM
