-- ADD column isBlocked for ECM_FADDL table
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ECM_FADDL')
	IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'ECM_FADDL'
						AND COLUMN_NAME = 'isBlocked')
		ALTER TABLE ECM_FADDL ADD isBlocked bit NOT NULL DEFAULT 0
	ELSE
	BEGIN
		IF (SELECT LOWER(DATA_TYPE) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ECM_FADDL' AND COLUMN_NAME = 'isBlocked' ) <> 'bit'
			BEGIN
				ALTER TABLE ECM_FADDL ALTER COLUMN isBlocked bit NOT NULL
				ALTER TABLE ECM_FADDL ADD DEFAULT 0 FOR isBlocked
			END
		IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'ECM_FADDL' and COLUMN_NAME = 'isBlocked' AND COLUMN_DEFAULT IS NOT NULL)
			ALTER TABLE ECM_FADDL ADD DEFAULT 0 FOR isBlocked
	END
GO

-- ADD column expirationDate for ECM_FADDL table
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ECM_FADDL')
	IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'ECM_FADDL'
						AND COLUMN_NAME = 'expirationDate')
		BEGIN
			ALTER TABLE ECM_FADDL ADD expirationDate DATE NULL
			-- Migrate old expry date to new column
			CREATE TABLE #FOLDER_TEMP (
				[folderId] 	NUMERIC(15),
				[delay]		VARCHAR(10),
				[endDate] DATE
			)
			CREATE INDEX IX_01 on #FOLDER_TEMP (folderId ASC)
			INSERT INTO #FOLDER_TEMP
			SELECT FOLDER.EZBUNU, CONSERVATION.delay, CONSERVATION.endDate
			FROM AREZCPP FOLDER,
				ECM_FCONS CONSERVATION
			WHERE CONVERT(VARCHAR(15), FOLDER.EZBUNU) = CONSERVATION.folderId
			AND FOLDER.EZN9ST = '1'

			UPDATE ECM_FADDL
				SET expirationDate = (CASE
									WHEN folder.delay IS NOT NULL THEN
										dateadd(month, CAST(folder.delay AS INT), folder.endDate)
									END)
			FROM #FOLDER_TEMP folder
			WHERE folder.folderId = ECM_FADDL.folderId

			DROP TABLE #FOLDER_TEMP
		END
GO

-- Backup old data to change the column FOLDERID to NUMERIC
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ECM_FADDL')
	IF (SELECT LOWER(DATA_TYPE) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ECM_FADDL' AND COLUMN_NAME = 'folderId' ) <> 'NUMERIC'
	BEGIN
		-- in some environments, the table ECM_FADDL_BK cannot be dropped
		IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ECM_FADDL_BK')
		BEGIN
			DROP TABLE ECM_FADDL_BK
		END

		CREATE TABLE [dbo].[ECM_FADDL_BK] (
			[folderId] NUMERIC(15) NOT NULL ,
			[folderType] varchar(10) NULL,
			[category] varchar(10) NULL,
			[isConfidential] bit NOT NULL DEFAULT 0,
			[isBlocked] bit NOT NULL DEFAULT 0,
			[ruleId] bigint NULL,
            [expirationDate] DATE
		)
		INSERT INTO ECM_FADDL_BK (folderId, folderType, category, isConfidential, isBlocked, ruleId, expirationDate)
		    SELECT folderId, folderType, category, isConfidential, isBlocked, ruleId, expirationDate FROM ECM_FADDL
		DROP TABLE ECM_FADDL
		EXEC sys.sp_rename 'ECM_FADDL_BK','ECM_FADDL'
		ALTER TABLE ECM_FADDL ADD CONSTRAINT folderAdditionalAttr_PRIMARY PRIMARY KEY (folderId)
	END
GO

