						WHERE TABLE_NAME = 'OPb5T'
						AND COLUMN_NAME = 'MODIFICATION_DATE')
ALTER TABLE OPb5T ADD MODIFICATION_DATE datetime

--last folder id
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ARGKCPP')
IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'ARGKCPP'
						AND COLUMN_NAME = 'MODIFICATION_DATE')
ALTER TABLE ARGKCPP ADD MODIFICATION_DATE datetime

--last clob id
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'DDd3sT')
IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'DDd3sT'
						AND COLUMN_NAME = 'MODIFICATION_DATE')
ALTER TABLE DDd3sT ADD MODIFICATION_DATE datetime

--last document number
IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'DDENUMERAT')
IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
						WHERE TABLE_NAME = 'DDENUMERAT'
						AND COLUMN_NAME = 'MODIFICATION_DATE')
ALTER TABLE DDENUMERAT ADD MODIFICATION_DATE datetime

