BEGIN
	INSERT INTO DDd3sT(TSTABNAM,TSSURRGT) VALUES('DDCLOB',1)
END
GO

-- ----------------------------
--INSERT THE MAXIMUM FOLDER TECHNICAL ID TO THE "GENERATE NEW FOLDER TECHNICAL ID" TABLE
-- ----------------------------
IF NOT EXISTS (select DDaefA from ARGKCPP WITH (READUNCOMMITTED) where DDebxA = '*NONE' AND DDebyA = 'BASE' AND  DDaefA = 'FOLDERPARAMETERS' AND DDaegA = 'LASTFOLDERKEYNUMBER')
	BEGIN
		INSERT INTO ARGKCPP(DDebxA,DDebyA,DDaefA,DDaegA,DDpncA,DDpndA,DDpneA) VALUES('*NONE','BASE','FOLDERPARAMETERS','LASTFOLDERKEYNUMBER', (select isnull(max(EZBUNU) + 1, 1) from AREZCPP WITH (READUNCOMMITTED)),'','')
	END
ELSE IF (select isnull(CAST(DDpncA AS INT), 1) from ARGKCPP WITH (READUNCOMMITTED) where DDebxA = '*NONE' AND DDebyA = 'BASE' AND  DDaefA = 'FOLDERPARAMETERS' AND DDaegA = 'LASTFOLDERKEYNUMBER') < (select max(EZBUNU) from AREZCPP WITH (READUNCOMMITTED))
	BEGIN
		update ARGKCPP set DDpncA = (select isnull(max(EZBUNU) + 1, 1) from AREZCPP WITH (READUNCOMMITTED)) where  DDebxA = '*NONE' AND DDebyA = 'BASE' AND  DDaefA = 'FOLDERPARAMETERS' AND DDaegA = 'LASTFOLDERKEYNUMBER'
	END
ELSE IF (select DDpncA from ARGKCPP where  DDebxA = '*NONE' AND DDebyA = 'BASE' AND  DDaefA = 'FOLDERPARAMETERS' AND DDaegA = 'LASTFOLDERKEYNUMBER') is null
	BEGIN
		update ARGKCPP set DDpncA = (select isnull(max(EZBUNU) + 1, 1) from AREZCPP WITH (READUNCOMMITTED)) where  DDebxA = '*NONE' AND DDebyA = 'BASE' AND  DDaefA = 'FOLDERPARAMETERS' AND DDaegA = 'LASTFOLDERKEYNUMBER'
	END
GO

-- INSERT THE MAXIMUM Init first document id with value 1AAAAAAA if there is no record on table OPb5T
-- ----------------------------
IF (SELECT COUNT(US1wA) FROM OPb5T) = 0
BEGIN
	INSERT INTO OPb5T(US1wA, OP5oA) VALUES (99999999999, '1AAAAAAA')
END
GO
