			 [depDesc] [varchar](200) NOT NULL,
			 [pacId] [varchar](200) NOT NULL,
			 [pacDesc] [varchar](200) NOT NULL
		) ON [PRIMARY]
	END
ELSE
	BEGIN
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'env', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [env] [char](10)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'baseId', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [baseId] [char](5)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'baseDesc', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [baseDesc] [varchar](200)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'orgId', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [orgId] [varchar](200)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'orgDesc', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [orgDesc] [varchar](200)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'depId', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [depId] [char](3)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'depDesc', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [depDesc] [varchar](200)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'pacDesc', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [pacDesc] [varchar](200)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'pacId', 'ColumnId') IS NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref ADD [pacId] [varchar](200)
		END
		IF COLUMNPROPERTY(OBJECT_ID(N'[dbo].[ecm_pacref]'), 'pacDescription', 'ColumnId') IS NOT NULL
		BEGIN
			ALTER TABLE [dbo].ecm_pacref DROP COLUMN pacDescription
		END
	END
GO
IF NOT EXISTS (SELECT CONSTRAINT_NAME FROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS WHERE CONSTRAINT_TYPE = 'PRIMARY KEY' AND TABLE_NAME = 'ecm_pacref')
BEGIN
	UPDATE [dbo].[ecm_pacref] SET [env] = '' where [env] IS NULL
	UPDATE [dbo].[ecm_pacref] SET [orgId] = '' where [orgId] IS NULL
	UPDATE [dbo].[ecm_pacref] SET [pacId] = '' where [pacId] IS NULL
	ALTER TABLE [dbo].[ecm_pacref] ALTER COLUMN [env] [char](10) NOT NULL
	ALTER TABLE [dbo].[ecm_pacref] ALTER COLUMN [orgId] [varchar](200) NOT NULL
	ALTER TABLE [dbo].[ecm_pacref] ALTER COLUMN [pacId] [varchar](200) NOT NULL
	ALTER TABLE [dbo].[ecm_pacref] ALTER COLUMN [depId] [varchar](200) NOT NULL
END
