-- ECM USER - update from varchar(10) to varchar(256)
IF (10 = (SELECT CHARACTER_MAXIMUM_LENGTH FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'ecm_udesc' AND COLUMN_NAME = 'name'))
BEGIN
	IF EXISTS (SELECT object_id FROM sys.indexes WHERE object_id = OBJECT_ID(N'[dbo].[ecm_udesc]') AND name = N'IX_01')
	BEGIN
		-- Drop index
		DROP INDEX [IX_01] ON [dbo].[ecm_udesc]
	END
	DECLARE
		@CONSTRAINT_NAME sysname
	BEGIN
		SET @CONSTRAINT_NAME = (SELECT CONSTRAINT_NAME FROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS WHERE TABLE_NAME = 'ecm_udesc' AND CONSTRAINT_TYPE='PRIMARY KEY')
		-- Drop PK
		IF @CONSTRAINT_NAME <> ''
			EXEC('ALTER TABLE [dbo].[ecm_udesc] DROP CONSTRAINT ' + @CONSTRAINT_NAME )
	END
	ALTER TABLE [dbo].[ecm_udesc] ALTER COLUMN [name] VARCHAR(256) NOT NULL -- username
	-- Re-create PK
	ALTER TABLE [dbo].[ecm_udesc] ADD CONSTRAINT [ecm_udesc_PRIMARY] PRIMARY KEY ([name])
	-- Re-create index
	CREATE NONCLUSTERED INDEX [IX_01] ON [dbo].[ecm_udesc] (name ASC, fullname ASC)
		WITH (PAD_INDEX = OFF, FILLFACTOR = 100, SORT_IN_TEMPDB = OFF, IGNORE_DUP_KEY = OFF, STATISTICS_NORECOMPUTE = OFF, ONLINE = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON)
		ON [PRIMARY]
END
GO

