----------------------------------------------------------------------------------
-- QUERY TO CLEAN ALL AND INSERT INDEXATION FOLDERS STATUS FOR ALL OLD FOLDERS IN DB. IT MAKE SURE THAT WHEN USER UPDATE OR DELETE FOLDER COMMENTS, FOLDER LINK CONCERN TO THE OLD FOLDERS THAT FOLDERS WILL BE REINDEXED BY FOLDER INDEXATION BEAN--
----------------------------------------------------------------------------------
INSERT INTO [dbo].[ecm_idx_f]
(folderId, databaseId, busnsFldId, status)
SELECT EZBUNU, EZAWCD, EZF8TX, 'F'
FROM [dbo].[AREZCPP] WITH (READUNCOMMITTED)
WHERE EZBUNU NOT IN (SELECT folderId FROM [dbo].[ecm_idx_f])
GO

--PART 3: remove triggers
--#              THIS PART CONTAINS TRIGGERS ON ECM TABLE :					    											    #
--#  + TRIGGER 1: ARAPREPFullText trigger on document table				        												#
--#  + TRIGGER 3: ARAUREPFullText trigger on keyword table                       												#
