--PART 4: handle enumerator DDENUMERAT tables
DECLARE @statement varchar(3000)

--DROP TABLE
IF NOT EXISTS( SELECT * FROM sys.tables WHERE name = 'DDENUMERAT')
BEGIN
	-- CREATE TABLE
	SET @statement = 'CREATE TABLE DDENUMERAT(
	ID varchar(50) NOT NULL,
	LASTNUMBER bigint NOT NULL,
	RDMNUMBER varchar(40) NOT NULL,
    MODIFICATION_DATE datetime,
	CONSTRAINT PK_DDENUMERAT PRIMARY KEY CLUSTERED
	(
	[ID] ASC
	)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON) ON [PRIMARY]
	) ON [PRIMARY]'

	EXECUTE(@statement)

	-- INSERT DATA
	SET @statement =
	'DECLARE @exist_AREZCPP int

	SELECT @exist_AREZCPP = count(*) FROM sys.tables WHERE name = ''AREZCPP''

	IF @exist_AREZCPP > 0
			BEGIN
				DECLARE @hasData int
				SELECT @hasData = count(*) FROM  AREZCPP WITH (READUNCOMMITTED)
				IF @hasData > 0
					BEGIN
						INSERT INTO  DDENUMERAT (ID, LASTNUMBER, RDMNUMBER)
							SELECT ''folderId'', MAX(EZBUNU), ''1'' FROM  AREZCPP WITH (READUNCOMMITTED)
					END
				ELSE
					BEGIN
						INSERT INTO  DDENUMERAT (ID, LASTNUMBER, RDMNUMBER) VALUES (''folderId'', ''1'', ''1'')
					END
			END
	ELSE
			BEGIN
			    INSERT INTO  DDENUMERAT (ID, LASTNUMBER, RDMNUMBER) VALUES (''folderId'', ''1'', ''1'')
			END'

	EXECUTE(@statement)

	SET @statement =
	'DECLARE @exist_ARAPREP int

	SELECT @exist_ARAPREP = count(*) FROM  sys.tables WHERE name = ''ARAPREP''

	IF @exist_ARAPREP > 0
			BEGIN
				DECLARE @hasData int
				SELECT @hasData = count(*) FROM  ARAPREP WITH (READUNCOMMITTED)
				IF @hasData > 0
					BEGIN
						INSERT INTO  DDENUMERAT (ID, LASTNUMBER, RDMNUMBER)
							SELECT ''documentNumber'', MAX(APXINB), ''1'' FROM ARAPREP WITH (READUNCOMMITTED)
					END
	            ELSE
					BEGIN
						INSERT INTO  DDENUMERAT (ID, LASTNUMBER, RDMNUMBER) VALUES (''documentNumber'', ''1'', ''1'')
					END
			END
	ELSE
			BEGIN
			    INSERT INTO  DDENUMERAT (ID, LASTNUMBER, RDMNUMBER) VALUES (''documentNumber'', ''1'', ''1'')
			END
	 '
	EXECUTE(@statement)
END
ELSE
BEGIN
    --last document number
    IF EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'DDENUMERAT')
        IF NOT EXISTS (SELECT * FROM INFORMATION_SCHEMA.COLUMNS
                       WHERE TABLE_NAME = 'DDENUMERAT'
                         AND COLUMN_NAME = 'MODIFICATION_DATE')
        ALTER TABLE DDENUMERAT ADD MODIFICATION_DATE datetime
END

--PART : statistics missing index part
-- /**
-- 	Steps to create missing indexes:
-- 	1. Run the script
-- 	   For example, the result likes this :
--    	   Table							Equality Columns		Inequality Columns			Included Columns
-- 	   [xlinedtaJ30].[dbo].[ARG0CPP]	[DDHZ9A]				[DDr68A]					[DD1rA], [DDr67A]
--
-- 	2. Create missing index by running the following sample script
-- 	   The values of 'Equality Columns' and 'Inequality Columns' will be put after 'ON' keyword on create index statement.
-- 	   The values of 'Included Columns' will be put after 'INCLUDE' keyword on create index statement.
--
-- 	   Template script:
-- 	   IF EXISTS (SELECT name FROM sys.indexes WHERE name='INDEX_NAME' AND object_id = OBJECT_ID('TABLE_NAME'))
-- 			DROP INDEX INDEX_NAME ON TABLE_NAME
-- 			CREATE INDEX INDEX_NAME ON ARG0CPP (COLUMN1, COLUMN2) INCLUDE (COLUMN3, COLUMN4)
-- 			GO
--
-- 	   Sample script:
-- 	   IF EXISTS (SELECT name FROM sys.indexes WHERE name='IX_ARG0CPP_DDHZ9A_DDr68A' AND object_id = OBJECT_ID('ARG0CPP'))
-- 			DROP INDEX IX_ARG0CPP_DDHZ9A_DDr68A ON TABLE_NAME
-- 			CREATE INDEX IX_ARG0CPP_DDHZ9A_DDr68A ON ARG0CPP (DDHZ9A, DDr68A) INCLUDE (DD1rA, DDr67A)
-- 			GO
--
-- 	   Note: - Index name is unique.
-- 	   		 - The values of 'Equality Columns' or 'Inequality Columns' can be empty.
-- 	   		 - If the values of 'Included Columns' are empty, do not use 'INCLUDE' keyword.
--
-- SELECT
-- 	mid.statement AS 'Table',
-- 	mid.equality_columns AS 'Equality Columns',
-- 	mid.inequality_columns AS 'Inequality Columns',
-- 	mid.included_columns AS 'Included Columns',
-- 	migs.unique_compiles AS 'Unique Compiles',
-- 	migs.user_seeks AS 'User Seeks',
-- 	migs.avg_total_user_cost AS 'Avg Total User Cost',
-- 	migs.avg_user_impact AS 'Avg User Impact',
-- 	migs.user_seeks * migs.avg_total_user_cost * (migs.avg_user_impact * 0.01) as 'Index Advantage'
-- FROM sys.dm_db_missing_index_group_stats AS migs
-- INNER JOIN sys.dm_db_missing_index_groups AS mig
-- ON migs.group_handle = mig.index_group_handle
-- INNER JOIN sys.dm_db_missing_index_details AS mid
-- ON mig.index_handle = mid.index_handle
-- WHERE mid.database_id = DB_ID()
-- ORDER BY 'Index Advantage' DESC
-- */
