-- /**
--  * FUNCTION *convertDate7StringsToDate*
--  * return a string with format 'YYYY-MM-DD HH24:MI:SS' from date and time input parameters
--  * Input:
--  * 		DATE_AS_STRING : date with format '1YYMMDD' or 'YYMMDD', example: '1150203','970203'
--  *  	TIME_AS_STRING : time with format "HHMISS", example: '100502','90502'
--  * Output:
--  *		return the string with format: 'YYYY-MM-DD HH24:MI:SS'
--  *
--  *	Example:
--  *		convertDate7StringsToDate('1150203','100502') => output : '2015-02-03 10:05:02'
--  *		convertDate7StringsToDate('970203','100502') => output : '1997-02-03 10:05:02'
--  * Exception:
--  * 		return empty string if invalid date and time
--  *
--  */

IF OBJECT_ID (N'dbo.convertDate7StringsToDate', N'FN') IS NOT NULL
    DROP FUNCTION dbo.convertDate7StringsToDate
GO

CREATE FUNCTION dbo.convertDate7StringsToDate (@DATE_AS_STRING VARCHAR(20),@TIME_AS_STRING VARCHAR(10))
RETURNS VARCHAR(100)
WITH EXECUTE AS CALLER
AS
BEGIN
   	DECLARE @V_DATE_AS_STRING VARCHAR(100)
	DECLARE @V_TIME_AS_STRING VARCHAR(100)

	SELECT @V_DATE_AS_STRING = @DATE_AS_STRING
	SELECT @V_TIME_AS_STRING = @TIME_AS_STRING

	 IF  LEN(@DATE_AS_STRING) = 7
		SET @V_DATE_AS_STRING = '20'+ SUBSTRING(@V_DATE_AS_STRING,2,10)
	 ELSE
       SET @V_DATE_AS_STRING = '19'+ @V_DATE_AS_STRING

	 IF LEN(@V_DATE_AS_STRING) != 8
		RETURN ''
	IF LEN (@V_TIME_AS_STRING) = 5
		SET @V_TIME_AS_STRING = '0' + @V_TIME_AS_STRING

	 IF LEN (@V_TIME_AS_STRING) != 6
		SET @V_TIME_AS_STRING = '000000'

	--RETURN FORMAT 'YYYY-MM-DD HH24:MI:SS
	RETURN SUBSTRING(@V_DATE_AS_STRING,1,4) + '-' + SUBSTRING(@V_DATE_AS_STRING,5,2) + '-' + SUBSTRING(@V_DATE_AS_STRING,7,2) + ' ' + SUBSTRING(@V_TIME_AS_STRING,1,2) + ':' + SUBSTRING(@V_TIME_AS_STRING,3,2) + ':' + SUBSTRING(@V_TIME_AS_STRING,5,2)
END

GO


-- /**
--  * FUNCTION *convertDate7StringToDate*
--  * return a string with format 'YYYYMMDD' from input parameters
--  * Input:
--  * 		DATE_AS_STRING : date with format '1YYMMDD' or 'YYMMDD', example: '1150203','970203'
--  * Output:
--  *		return the string with format: 'YYYYMMDD'
--  *
--  *	Example:
--  *		convertDate7StringToDate('1150203') => output : '20150203'
--  *		convertDate7StringToDate('970203') => output : '19970203'
--  * Exception:
--  * 		return empty string if invalid date and time
--  *
--  */

IF OBJECT_ID (N'dbo.convertDate7StringToDate', N'FN') IS NOT NULL
    DROP FUNCTION dbo.convertDate7StringToDate
GO
CREATE FUNCTION dbo.convertDate7StringToDate (@DATE_AS_STRING varchar(50))
RETURNS VARCHAR(50)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_DATE_AS_STRING VARCHAR(50)
	SET @V_DATE_AS_STRING = @DATE_AS_STRING

	 IF  LEN(@V_DATE_AS_STRING) = 7
		SELECT @V_DATE_AS_STRING = '20'+ SUBSTRING(@V_DATE_AS_STRING,2,10)
	 ELSE
       SELECT @V_DATE_AS_STRING = '19'+ @V_DATE_AS_STRING

    --@tempDate YYYYMMDD
	IF LEN(@V_DATE_AS_STRING) != 8
		RETURN '0'
	RETURN @V_DATE_AS_STRING
END

GO
-- /**
--  * FUNCTION *convertDate7StringsToISODate*
--  * return a ISO date string
--  * Input:
--  * 		DATE_AS_STRING : date with format '1YYMMDD' or 'YYMMDD', example: '1150203','970203'
--  *  	    TIME_AS_STRING : time with format "HHMISS", example: '100502','90502'
--  * Output:
--  *		return the string with format,example: 2020-09-14T12:31:58.000Z
--  *
--  */
IF OBJECT_ID (N'dbo.convertDate7StringsToISODate', N'FN') IS NOT NULL
    DROP FUNCTION dbo.convertDate7StringsToISODate
GO
CREATE FUNCTION dbo.convertDate7StringsToISODate (@DATE_AS_STRING VARCHAR(100),@TIME_AS_STRING VARCHAR(100))
RETURNS varchar(500)
WITH EXECUTE AS CALLER
AS
BEGIN
    DECLARE @V_DATE_AS_STRING VARCHAR(100)
	DECLARE @V_TIME_AS_STRING VARCHAR(100)
	DECLARE @createDatetime varchar(20)

	SELECT @V_DATE_AS_STRING = @DATE_AS_STRING
	SELECT @V_TIME_AS_STRING = @TIME_AS_STRING

	SET @createDatetime = dbo.convertDate7StringsToDate(@V_DATE_AS_STRING,@V_TIME_AS_STRING)

    DECLARE @TimeZone VARCHAR(50)
    EXEC master.dbo.xp_regread 'HKEY_LOCAL_MACHINE','SYSTEM\CurrentControlSet\Control\TimeZoneInformation','TimeZoneKeyName',@TimeZone OUT
    -- convert from date in server timezon to UTC (this allow to correct in DST)
    return format((CONVERT(datetime, @createDatetime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z'
END

GO
-- /**
--  * FUNCTION *getDistinctSecurityClass*
--  * return the distinct security classes from list of security classes
--  * Input:
--  * 		sec : list of security class name
--  * Output:
--  *		return list of security class name without duplicate
--  *	Example:
--  *		getDistinctSecurityClass('"XDOC3","XDOC3","XDOC4","XDOC5","XDOC3"')	=> "XDOC3","XDOC4","XDOC5"
--  *		getDistinctSecurityClass('"XDOC3","XDOC4","XDOC5"')                 =>  "XDOC3","XDOC4","XDOC5"
--  *		getDistinctSecurityClass('"XDOC3"')                     			=>	"XDOC3"
--  *		getDistinctSecurityClass(',')                     					=> ""
--  *
--  */
IF OBJECT_ID (N'dbo.getDistinctSecurityClass', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getDistinctSecurityClass
GO

CREATE FUNCTION dbo.getDistinctSecurityClass (@sec varchar(max))
RETURNS varchar(max)
WITH EXECUTE AS CALLER
AS
BEGIN
	declare @i integer
	declare @part varchar(max)
	declare @sec_temp varchar(max)

	declare @result_sec  varchar(max)
	IF (@sec IS NULL)
	RETURN ''
	set @sec_temp = @sec
	set @i = CHARINDEX (',',@sec)
	if @i <=0
		return @sec
	else
		begin
			while @i > 0
				begin
					set @part = SUBSTRING (@sec_temp, 0,@i)
					if @part = ''
						begin
							set @sec_temp = SUBSTRING (@sec_temp, @i+1,len(@sec_temp))
							set @i = CHARINDEX (',',@sec_temp)
						CONTINUE
						end
					set @sec_temp = SUBSTRING (@sec_temp, @i+1,len(@sec_temp))
					set @sec_temp = REPLACE (@sec_temp,@part,'')

					if @result_sec is null
						set @result_sec = @part
					else
						set @result_sec = @result_sec + ',' +  @part
					set @i = CHARINDEX (',',@sec_temp)
				end
				if @sec_temp != ''
					begin
					if @result_sec is null
							set @result_sec = @sec_temp
						else
							set @result_sec = @result_sec + ',' +  @sec_temp
					end
			end

	return @result_sec
END

GO
-- /**
--  * FUNCTION *getDocumentSecurityClass*
--  * get security class for one document by make the intersection
--  * between the security classes of folder entries and security classes
--  * of the document.
--  * Input:
--  * 		folder_sec : list of security class of folder
--  * 		doc_sec    : list of security class of document
--  * Output:
--  *		return list of security class
--  *	Example:
--  *		getDocumentSecurityClass('"_ALL_"'	,	'"XDOC1","XDOC2",""XDOC3"')             => "XDOC1","XDOC2",""XDOC3"
--  *		getDocumentSecurityClass('"_ALL_"	,	"XDOC1"','"XDOC1","XDOC2",""XDOC3"')     => "XDOC1","XDOC2",""XDOC3"
--  *		getDocumentSecurityClass('','"XDOC1",	"XDOC2",""XDOC3"')                    => ""
--  *		getDocumentSecurityClass('"XDOC1"'	,	'"XDOC1","XDOC2",""XDOC3"')             => "XDOC1"
--  *		getDocumentSecurityClass('"XDOC2"'	,	'"XDOC1","XDOC2",""XDOC3"')             => "XDOC2"
--  *		getDocumentSecurityClass('"XDOC3"'	,	'"XDOC1","XDOC2",""XDOC3"')             => "XDOC3"
--  *		getDocumentSecurityClass('"XDOC3"'	,	'')  							       => ""
--  *		getDocumentSecurityClass('"XDOC3"'	,	'"XDOC3"')             					=> "XDOC3"
--  *		getDocumentSecurityClass('"XDOC3"'	,	'_NONE_')             					=> "_NONE_"
--  *		getDocumentSecurityClass('"XDOC3","XDOC4"'	,	'"XDOC5","XDOC4"')              => "XDOC4"
--  *		getDocumentSecurityClass('"XDOC3","XDOC4"'	,	'"XDOC5","_NONE_"')             => "_NONE_"
--  *
--  */

IF OBJECT_ID (N'dbo.getDocumentSecurityClass', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getDocumentSecurityClass
GO


-- /*
--  * FUNCTION *formatFolderDescription*
--  * return the folder description by removing the unnecessary separator character.
--  * Input:
--  * 		STRING : folder description contains SEPARATOR_STRING. For example: "desc1#V_FLDDESC#desc2#V_FLDDESC#desc3#V_FLDDESC#desc4"
--  * 		SEPARATOR_STRING : the technique folder description separator will be replaced by the REPLACEMENT_SEPARATOR_STRING. For example: #V_FLDDESC#
--  * 		REPLACEMENT_SEPARATOR_STRING : the folder description separator. For example: "-"
--  * Output:
--  *		folder description. For example: desc1-desc2-desc3-desc4
--  *	For example:
--  * 	dbo.formatFolderDescription('LV5#V_FLDDESC##V_FLDDESC##V_FLDDESC#','#V_FLDDESC#',' - ')					=> "LV5"
--  * 	dbo.formatFolderDescription('#V_FLDDESC##V_FLDDESC##V_FLDDESC#','#V_FLDDESC#',' - ')						=> ""
--  * 	dbo.formatFolderDescription('LV5#V_FLDDESC#DESC2#V_FLDDESC#DESC3#V_FLDDESC#DESC4','#V_FLDDESC#',' - ')	=> "LV5 - DESC2 - DESC3 - DESC4"
--  * 	dbo.formatFolderDescription('LV5#V_FLDDESC##V_FLDDESC##V_FLDDESC#DESC4','#V_FLDDESC#',' - ')				=> "LV5 - DESC4"
--  * 	dbo.formatFolderDescription('LV5#V_FLDDESC##V_FLDDESC#DESC3#V_FLDDESC#','#V_FLDDESC#',' - ')				=>	"LV5 - DESC3"
--  * 	dbo.formatFolderDescription('#V_FLDDESC##V_FLDDESC#DESC3#V_FLDDESC#','#V_FLDDESC#',' - ')				=>	"DESC3"
--  *
-- */

IF OBJECT_ID (N'dbo.formatFolderDescription', N'FN') IS NOT NULL
    DROP FUNCTION dbo.formatFolderDescription
GO
CREATE FUNCTION dbo.formatFolderDescription (@STRING varchar(5000),@SEPARATOR_STRING varchar(100),@REPLACEMENT_SEPARATOR_STRING varchar(100))
RETURNS VARCHAR(5000)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_STRING VARCHAR(5000)
	DECLARE @V_SEPARATOR_STRING VARCHAR(100)
	DECLARE @V_REPLACEMENT_SEPARATOR_STRING VARCHAR(100)
	DECLARE @V_SEPARATE_LEN_STRING VARCHAR(100)
	SET @V_STRING = RTRIM(@STRING)
	SET @V_SEPARATOR_STRING = @SEPARATOR_STRING
	SET @V_REPLACEMENT_SEPARATOR_STRING = @REPLACEMENT_SEPARATOR_STRING
	SET @V_SEPARATE_LEN_STRING = DATALENGTH(@V_SEPARATOR_STRING)
	SET @V_STRING = REPLACE (@V_STRING,@V_SEPARATOR_STRING + @V_SEPARATOR_STRING,@V_SEPARATOR_STRING)
	SET @V_STRING = REPLACE (@V_STRING,@V_SEPARATOR_STRING + @V_SEPARATOR_STRING,@V_SEPARATOR_STRING)
	SET @V_STRING = REPLACE (@V_STRING,@V_SEPARATOR_STRING + @V_SEPARATOR_STRING,@V_SEPARATOR_STRING)
	IF LEFT(@V_STRING,@V_SEPARATE_LEN_STRING) = @V_SEPARATOR_STRING
		SET @V_STRING = RIGHT(@V_STRING,DATALENGTH(@V_STRING)- @V_SEPARATE_LEN_STRING)
	IF RIGHT(@V_STRING,@V_SEPARATE_LEN_STRING) = @V_SEPARATOR_STRING
		SET @V_STRING = LEFT(@V_STRING,(DATALENGTH (@V_STRING) - @V_SEPARATE_LEN_STRING))
	SET @V_STRING = REPLACE (@V_STRING,@V_SEPARATOR_STRING,@V_REPLACEMENT_SEPARATOR_STRING)
	RETURN 	@V_STRING
END

GO

-- /**
--  * FUNCTION *escapeXMLCharacters*
--  * replace all XML characters from input string
--  * Example: & - &amp
--  *          < - &lt
--  *			> - &gt
--  *			" - &quot
--  *			' - &apos
--  * Input:
--  * 		STR : string with special characters
--  * Output:
--  *		return the string
--  *
--  */
IF OBJECT_ID (N'dbo.escapeXMLCharacters', N'FN') IS NOT NULL
    DROP FUNCTION dbo.escapeXMLCharacters
GO
CREATE FUNCTION dbo.escapeXMLCharacters (@STR VARCHAR(MAX))
RETURNS VARCHAR(MAX)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @STR_OUT VARCHAR(MAX)
	IF @STR IS NULL OR DATALENGTH(@STR) = 0
	RETURN NULL
  	SET @STR_OUT = REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(@STR,'&amp;','&' ),'&lt;','<'),'&gt;','>'),'&quot;','"'),'&apos;','''')
	RETURN @STR_OUT
END
GO
-- /**
--  * FUNCTION *extractObjectDescription*
--  * return a json string as description of document
--  * Input:
--  * 		documentDescription : document description
--  * 		createdOn			: CMS string
--  * 		byString			: CMS string
--  * 		creationUserId		: create user id
--  * 		changedOn			: CMS string
--  * 		modificationUserId	:	modification user id
--  * 		documentId			: document id
--  * 		creationDate		: create date of document
--  *		creationTime		: create time of document
--  *		modificationDate	: modification date of document
--  * 		modificationTime	: modification time of document
--  * 		isConfidentialUserRestricted	: is confidential user restricted. Accepted values: true / false
--  *
--  * Output:
--  *		json string
--  *
--  */
IF OBJECT_ID (N'dbo.extractObjectDescription', N'FN') IS NOT NULL
    DROP FUNCTION dbo.extractObjectDescription
GO
CREATE FUNCTION dbo.extractObjectDescription (
	@documentDescription VARCHAR(256),
	@createdOn VARCHAR(20),
	@byString VARCHAR(10),
	@creationUserId VARCHAR(256),
	@changedOn VARCHAR (20),
	@modificationUserId varchar(256),
	@documentId varchar(40),
	@creationDate varchar(20),
	@creationTime varchar(6),
	@modificationDate varchar(20),
	@modificationTime varchar(6),
	@isConfidentialUserRestricted char(10))
RETURNS VARCHAR(4000)
WITH EXECUTE AS CALLER
AS
BEGIN
     DECLARE @createDatetime varchar(20)
     DECLARE @modificationDatetime varchar(20)

	 --validate parameters
	 SET @creationUserId  = CASE WHEN @creationUserId IS NULL THEN '' ELSE @creationUserId END
	 SET @modificationUserId  = CASE WHEN @modificationUserId IS NULL THEN '' ELSE @modificationUserId END
	 SET @creationDate  = CASE WHEN @creationDate IS NULL THEN '' ELSE @creationDate END
	 SET @creationTime  = CASE WHEN @creationTime IS NULL THEN '' ELSE @creationTime END
	 SET @modificationDate  = CASE WHEN @modificationDate IS NULL THEN '' ELSE @modificationDate END
	 SET @modificationTime  = CASE WHEN @modificationTime IS NULL THEN '' ELSE @modificationTime END
	--end validate parameters

	 SET @createDatetime = dbo.convertDate7StringsToDate(@creationDate,@creationTime)
	 SET @modificationDatetime = dbo.convertDate7StringsToDate(@modificationDate,@modificationTime)
	DECLARE @TimeZone VARCHAR(50)
    EXEC master.dbo.xp_regread 'HKEY_LOCAL_MACHINE','SYSTEM\CurrentControlSet\Control\TimeZoneInformation','TimeZoneKeyName',@TimeZone OUT

	RETURN '"objectDescription":{"preview":"' +
			@documentDescription +
			 '\n' +
			@createdOn +
			' ' +
			@createDatetime +
			' ' +
			@byString +
			' ' +
			RTRIM(@creationUserId) +
			'\n' +
			@changedOn +
			' ' +
			@modificationDatetime +
			 ' ' +
			 @byString +
			 ' ' +
			RTRIM(@modificationUserId) +
			'","businessObjectId":"' +
			dbo.escapeSpecialCharacters(@documentId) +
			'","objectName":"' +
			@documentDescription +
			'","objectNameLocale":[{"locale":"fr","value":"'+@documentDescription+'"},{"locale":"de","value":"'+@documentDescription+'"},{"locale":"it","value":"'+@documentDescription+'"},{"locale":"en","value":"'+@documentDescription+'"}]' +
			',"audit":{"creationUser":"' +
			RTRIM(@creationUserId) +
			'",' +
			CASE WHEN LEN(@createDatetime) = 19 THEN
                -- convert from date in server timezon to UTC (this allow to correct in DST)
                '"creationDateTime":"' + format((CONVERT(datetime, @createDatetime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' +
			'",'
			ELSE ''
			END +
			'"modificationUser":"' +
			RTRIM(@modificationUserId) +'"' +
			CASE WHEN LEN(@modificationDatetime) = 19 THEN
                -- convert from date in server timezon to UTC (this allow to correct in DST)
                ',"modificationDateTime":"' + format((CONVERT(datetime, @modificationDatetime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' +
			'"'
			ELSE ''
			END +
			'}'
			+
			CASE WHEN LEN(@createDatetime) = 19 THEN
                -- convert from date in server timezon to UTC (this allow to correct in DST)
                ',"objectFilterDate":"' + format((CONVERT(datetime, @createDatetime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' +
			'"'
			ELSE ''
			END
			+
			case when @isConfidentialUserRestricted is not null and @isConfidentialUserRestricted !='' then ',"isConfidentialUserRestricted":'+ RTRIM(@isConfidentialUserRestricted) else '' end
			+
			'}'

END

GO
-- /**
--  * FUNCTION *escapeSpecialCharacters*
--  * replace all special characters from input string
--  * Input:
--  * 		STR : string with special characters
--  * Output:
--  *		return the string
--  *
--  */
IF OBJECT_ID (N'dbo.escapeSpecialCharacters', N'FN') IS NOT NULL
    DROP FUNCTION dbo.escapeSpecialCharacters
GO
CREATE FUNCTION dbo.escapeSpecialCharacters (@STR VARCHAR(MAX))
RETURNS VARCHAR(MAX)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @STR_OUT VARCHAR(MAX)
	IF (@STR IS NULL)
	RETURN ''
  	SET @STR_OUT = REPLACE(
  			REPLACE(
			REPLACE(
			REPLACE(
			REPLACE(
			REPLACE(
			  REPLACE(@STR,char('92'),'\\' ),
			'\"','\\\\\\\"'),
			'"','\\\"'),
		 CHAR(10),'\n'),
         CHAR(13),'\r'),
         '\\u','\\\\u'),-- \u is special character in GSON
         CHAR(09),'\t')
    -- when the end is \, add more \t to make JSON well-form
    IF RIGHT(@STR_OUT,1) = '\'
		SET @STR_OUT = @STR_OUT + '\t'
	RETURN @STR_OUT
	--'
END
GO

-- /**
--  * FUNCTION *escapeDescriptionSpecialCharacters*
--  * replace special characters from description input string
--  * Input:
--  * 		STR : string with special characters quote
--  * Output:
