CREATE FUNCTION dbo.escapeDescriptionSpecialCharacters (@STR VARCHAR(MAX))
RETURNS VARCHAR(MAX)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @STR_OUT VARCHAR(MAX)
	IF (@STR IS NULL)
	RETURN ''
  	SET @STR_OUT = REPLACE(@STR,'"','&#34;')
	RETURN @STR_OUT
END
GO
