-- /**
--  * FUNCTION *convertDateField*
--  * return the json format like [,"FIELD_VALUE_AS_DATE":"20140101"] if the given FIELD_VALUE_AS_DATE is well-form, otherwise return []
--  * Input:
--  * 		FIELD_NAME : the JSON field name, example : expiryDate
--  * 		FIELD_VALUE_AS_DATE : the value as date, example : 1120201
--  * Output:
--  *		return the JSON string
--  *
--  */
IF OBJECT_ID (N'dbo.convertDateField', N'FN') IS NOT NULL
    DROP FUNCTION dbo.convertDateField
GO
CREATE FUNCTION dbo.convertDateField (@FIELD_NAME VARCHAR(100),@FIELD_VALUE_AS_DATE VARCHAR(50))
RETURNS VARCHAR(150)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @DATE_VALUE VARCHAR(50)
	SET @DATE_VALUE = dbo.convertDate7StringToDate(@FIELD_VALUE_AS_DATE)
	RETURN CASE
				WHEN @DATE_VALUE IS NULL OR @DATE_VALUE = '0'
				THEN ''
				ELSE ',\"' + @FIELD_NAME + '\":\"' + @DATE_VALUE + '\"'
			END

END
GO
-- /**
--  * FUNCTION *convertKeywordDate*
--  * return format yyyy-MM-ddTHH:mm:ssZ
--  * Input:
--  * 		DATE_AS_STRING : keyword date value
--  * 		TYPE : keyword data date types: 03,04,05,07,08
--  * Output:
--  *		return the JSON string
--  *
--  */
IF OBJECT_ID (N'dbo.convertKeywordDate', N'FN') IS NOT NULL
    DROP FUNCTION dbo.convertKeywordDate
GO
CREATE FUNCTION dbo.convertKeywordDate (@DATE_AS_STRING VARCHAR(20),@TYPE CHAR(2))
RETURNS VARCHAR(20)
WITH EXECUTE AS CALLER
AS
BEGIN
   	DECLARE @V_DATE_AS_STRING VARCHAR(100)
	DECLARE @V_TYPE CHAR(2)
	DECLARE @V_RESULT CHAR(20)

	SELECT @V_DATE_AS_STRING = @DATE_AS_STRING
	SELECT @V_TYPE = @TYPE
	-- IF DATALENGTH(@V_DATE_AS_STRING) != 8 RETURN  ''
	--return format yyyy-MM-ddTHH:mm:ssZ, example: 2010-12-27T14:53:18Z
	SELECT  @V_RESULT = CASE
		WHEN @V_TYPE = '03' --DDMMYY
		THEN
		-- convert DDMMYY => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		-- CONVERT (varchar(10),CONVERT(date,SUBSTRING(@V_DATE_AS_STRING ,5,2)+SUBSTRING(@V_DATE_AS_STRING ,3,2)+SUBSTRING(@V_DATE_AS_STRING ,1,2),12)) + 'T00:00:00Z'
		-- JYPE September 2016 : the dates are stored by client with YYMMDD, so call convert YYMMDD => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		CONVERT (varchar(10),CONVERT(date,@V_DATE_AS_STRING,12)) + 'T00:00:00Z'


		WHEN @V_TYPE = '04' --YYMMDD
		THEN
		-- convert YYMMDD => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		CONVERT (varchar(10),CONVERT(date,@V_DATE_AS_STRING,12)) + 'T00:00:00Z'

		WHEN @V_TYPE = '05' --MMDDYY
		THEN
		-- convert MMDDYY => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		-- CONVERT(varchar(10),CONVERT(date,SUBSTRING(@V_DATE_AS_STRING,5,2)+SUBSTRING(@V_DATE_AS_STRING,1,2)+SUBSTRING(@V_DATE_AS_STRING,3,2),12))+ 'T00:00:00Z'
		-- JYPE September 2016 : the dates are stored by client with YYMMDD, so call convert YYMMDD => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		CONVERT (varchar(10),CONVERT(date,@V_DATE_AS_STRING,12)) + 'T00:00:00Z'

		WHEN @V_TYPE = '07' --DDMMYYYY
		THEN
		-- convert DDMMYYYY => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		-- CONVERT(varchar(10),SUBSTRING(@V_DATE_AS_STRING,5,4) +'-'+ SUBSTRING(@V_DATE_AS_STRING,3,2)+'-'+SUBSTRING(@V_DATE_AS_STRING,1,2)) + 'T00:00:00Z'
		-- JYPE September 2016 : the dates are stored by client with YYYYMMDD, so call convert YYYYMMDD => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		CONVERT(varchar(10),SUBSTRING(@V_DATE_AS_STRING,0,5) +'-'+ SUBSTRING(@V_DATE_AS_STRING,5,2)+'-'+SUBSTRING(@V_DATE_AS_STRING,7,2)) + 'T00:00:00Z'

		WHEN @V_TYPE = '08' --YYYYMMDD
		THEN
		-- convert YYYYMMDD => YYYY-MM-DD => YYYY-MM-DDT00:00:00Z
		CONVERT(varchar(10),SUBSTRING(@V_DATE_AS_STRING,0,5) +'-'+ SUBSTRING(@V_DATE_AS_STRING,5,2)+'-'+SUBSTRING(@V_DATE_AS_STRING,7,2)) + 'T00:00:00Z'
	END
	RETURN @V_RESULT
END
GO
-- /**
--  * FUNCTION *getFolderKeywordDescriptor*
--  * return the folder keyword field as ,\"Keyword.AUTEU_str\":[\"Jame\"]
--  * Input:
--  * 		DATATYPE : keyword data type. Example: AUTEU, NODOC
--  * 		TYPE : kind of data type. One of: 02,03,04,05,07,08,09
--  * 		KW_VALUE:  keyword value. Example: Jame
--  * Output:
--  *		return the string. Example: ,\"Keyword.AUTEU_str\":[\"Jame\"]
--  * Example: select dbo.getFolderKeywordDescriptor('AUTEU','02', 'Jame') => return ,\"Keyword.AUTEU_str\":[\"Jame\"]
--  * 			select dbo.getFolderKeywordDescriptor('DTASG','07','20171208') => return ,\"Keyword.DTASG_dat\":[\"2017-12-08T00:00:00Z\"]
--  */
IF OBJECT_ID (N'dbo.getFolderKeywordDescriptor', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getFolderKeywordDescriptor
GO
CREATE FUNCTION dbo.getFolderKeywordDescriptor (@DATATYPE varchar(10) , @TYPE VARCHAR(10), @KW_VALUE varchar(40))
RETURNS VARCHAR(200)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @STR_OUT VARCHAR(200)
	SET @STR_OUT = ''
	IF @TYPE IS NULL OR DATALENGTH(@TYPE) = 0 OR @DATATYPE IS NULL OR DATALENGTH(@DATATYPE) = 0 OR @KW_VALUE IS NULL OR DATALENGTH(@KW_VALUE) = 0
	RETURN @STR_OUT
  	SET @STR_OUT =  CASE
						WHEN  @TYPE = '01' AND ISNUMERIC(@KW_VALUE) = 1
						THEN  '_lng' + '\":[\"' + CONVERT(VARCHAR(100), CAST(@KW_VALUE AS NUMERIC))
						WHEN  @TYPE = '02'
						THEN  '_str' + '\":[\"' + RTRIM(dbo.escapeSpecialCharacters(@KW_VALUE))
						WHEN  CAST(@TYPE AS INT) > 2 AND CAST(@TYPE AS INT) < 9 AND ISDATE(@KW_VALUE) = 1
						THEN  '_dat' + '\":[\"' + dbo.convertKeywordDate(@KW_VALUE,@TYPE)
						WHEN  @TYPE = '09'
						THEN  '_cur' + '\":[\"' + dbo.escapeSpecialCharacters(@KW_VALUE)
						ELSE ''
					END
	RETURN CASE
				WHEN @STR_OUT = ''
				THEN ''
				ELSE ',\"Keyword.' + RTRIM(@DATATYPE) + @STR_OUT + '\"]'
			END
END
GO

-- /**
--  * FUNCTION *buildFolderObjectKeyValues*
--  * return concatination of two input
--  * Input:
--  * 		FIRST_VALUE : current value of object key value.
--  * 		SECOND_VALUE : built folder search text without zero prefix value
--  * Output:
--  *		return the string. Example: \"27198#EXMAR\",\"123 456 789 12 345\"
--  * Example: select dbo.buildFolderObjectKeyValues('\"27198#EXMAR\"','\"123 456 789 12 345\"') => return \"27198#EXMAR\",\"123 456 789 12 345\"
--  * 			select dbo.buildFolderObjectKeyValues('\"27198#EXMAR\"',NULL) => return \"27198#EXMAR\"
--  * 			select dbo.buildFolderObjectKeyValues('','\"123 456 789 12 345\"') => return \"123 456 789 12 345\"
--  */
IF OBJECT_ID (N'dbo.buildFolderObjectKeyValues', N'FN') IS NOT NULL
    DROP FUNCTION dbo.buildFolderObjectKeyValues
GO
CREATE FUNCTION dbo.buildFolderObjectKeyValues (@FIRST_VALUE VARCHAR(MAX) , @SECOND_VALUE VARCHAR(200))
RETURNS VARCHAR(MAX)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @STR_OUT VARCHAR(MAX)
	SET @STR_OUT = ''
	IF @FIRST_VALUE IS NOT NULL AND @FIRST_VALUE !=''
	SET @STR_OUT = @FIRST_VALUE
	IF @SECOND_VALUE IS NOT NULL AND @SECOND_VALUE !='' AND @STR_OUT !=''
	SET @STR_OUT = @STR_OUT + ',' + @SECOND_VALUE
	IF @SECOND_VALUE IS NOT NULL AND @SECOND_VALUE !='' AND @STR_OUT =''
	SET @STR_OUT = @SECOND_VALUE
	RETURN @STR_OUT
END
GO

-- /**
--  * FUNCTION *buildFolderBusinessIdAndDescription1234WithoutZeroPrefix*
--  * return the text without zero prefix of business id, description 1,2,3,4
--  * Input:
--  * 	ESCAPE_JSON : return json as string characters
--  * 	BUSINESS_ID : folder business id
--  * 	DESCRIPTION1 : folder description 1
--  * 	DESCRIPTION2 : folder description 2
--  *  	DESCRIPTION3 : folder description 3
--  *  	DESCRIPTION4 : folder description 4
--  * Output:
--  *		return the string. Example: \"123 456 789 12 345\" or "123 456 789 12 345"
--  * Example: select dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix(1, '0000123','000456', '000789', '00012','000345') => returns \"123 456 789 12 345\"
--  * 			select dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix(0, 'PL123','000456', '000789', 'PL012','000345') => returns "456 789 345"
--  * 			select dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix(0, 'PL123','PL456', 'PL789', 'PL012','PL345') => returns ''
--  * Reference links:
--  * The function ISNUMERIC returns 1 for some characters that are not numbers: https://docs.microsoft.com/en-us/sql/t-sql/functions/isnumeric-transact-sql
--  * Use another way to check the value is numberic: https://stackoverflow.com/questions/4603292/check-if-a-varchar-is-a-number-tsql
--  */
IF OBJECT_ID (N'dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix', N'FN') IS NOT NULL
    DROP FUNCTION dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix
GO
CREATE FUNCTION dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix (@ESCAPE_JSON bit, @BUSINESS_ID varchar(40) , @DESCRIPTION1 VARCHAR(30), @DESCRIPTION2 varchar(30), @DESCRIPTION3 varchar(30), @DESCRIPTION4 varchar(30))
RETURNS VARCHAR(200)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @STR_OUT VARCHAR(200)
	SET @STR_OUT = ''
	IF @BUSINESS_ID IS NOT NULL AND @BUSINESS_ID LIKE '0%' AND @BUSINESS_ID NOT LIKE '%[^0-9]%'
	SET @STR_OUT = SUBSTRING(@BUSINESS_ID, PATINDEX('%[^0]%', @BUSINESS_ID+'.'), LEN(@BUSINESS_ID))
	IF @DESCRIPTION1 IS NOT NULL AND @DESCRIPTION1 LIKE '0%' AND @DESCRIPTION1 NOT LIKE '%[^0-9]%'
	SET @STR_OUT = @STR_OUT + ' ' + SUBSTRING(@DESCRIPTION1, PATINDEX('%[^0]%', @DESCRIPTION1+'.'), LEN(@DESCRIPTION1))
	IF @DESCRIPTION2 IS NOT NULL AND @DESCRIPTION2 LIKE '0%' AND @DESCRIPTION2 NOT LIKE '%[^0-9]%'
	SET @STR_OUT = @STR_OUT + ' ' + SUBSTRING(@DESCRIPTION2, PATINDEX('%[^0]%', @DESCRIPTION2+'.'), LEN(@DESCRIPTION2))
	IF @DESCRIPTION3 IS NOT NULL AND @DESCRIPTION3 LIKE '0%' AND @DESCRIPTION3 NOT LIKE '%[^0-9]%'
	SET @STR_OUT = @STR_OUT + ' ' + SUBSTRING(@DESCRIPTION3, PATINDEX('%[^0]%', @DESCRIPTION3+'.'), LEN(@DESCRIPTION3))
	IF @DESCRIPTION4 IS NOT NULL AND @DESCRIPTION4 LIKE '0%' AND @DESCRIPTION4 NOT LIKE '%[^0-9]%'
	SET @STR_OUT = @STR_OUT + ' ' + SUBSTRING(@DESCRIPTION4, PATINDEX('%[^0]%', @DESCRIPTION4+'.'), LEN(@DESCRIPTION4))
	IF @STR_OUT != ''
        IF @ESCAPE_JSON IS NOT NULL AND @ESCAPE_JSON = '1'
            SET @STR_OUT =  '\"' + LTRIM(@STR_OUT) + '\"'
        ELSE
            SET @STR_OUT =  '"' + LTRIM(@STR_OUT) + '"'
	RETURN @STR_OUT
END
GO

