-- /**
--  * FUNCTION *getDefaultDescriptions*
--  * return descriptions with same value for four languages
--  * Input:
--  * 		json_data: json data
--  * 		lang : language code
--  * Output:
--  *		return four descriptions
--  * For example: select dbo.getDefaultDescriptions('departmentDescription_', 'ADM') => return \"departmentDescription_fr\":\"ADM\",\"departmentDescription_de\":\"ADM\",\"departmentDescription_it\":\"ADM\",\"departmentDescription_en\":\"ADM\"
--  */
IF OBJECT_ID (N'dbo.getDefaultDescriptions', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getDefaultDescriptions
GO
CREATE FUNCTION dbo.getDefaultDescriptions(@PREFIX_DESCRIPTION VARCHAR(255), @DEFAULT_VALUE VARCHAR(255))
RETURNS VARCHAR(MAX)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(MAX)
	SELECT @V_RESULT = '\"' + @PREFIX_DESCRIPTION + 'fr\":\"' + @DEFAULT_VALUE + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'de\":\"' + @DEFAULT_VALUE + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'it\":\"' + @DEFAULT_VALUE + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'en\":\"' + @DEFAULT_VALUE + '\"'
	RETURN ISNULL(@V_RESULT, '')
END
GO

-- /**
--  * FUNCTION *getReferencingStatus*
--  * return referencing status based on status code and language code
--  * Input:
--  * 		status_code
--  * 		lang
--  * Output:
--  *		return status based on language
--  * For example: select dbo.getReferencingStatus('C', 'fr') => return Aucun
--  */
IF OBJECT_ID (N'dbo.getReferencingStatus', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getReferencingStatus
GO
CREATE FUNCTION dbo.getReferencingStatus(@STATUS_CODE VARCHAR(1), @LANG VARCHAR(2))
RETURNS VARCHAR(500)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(500)

	IF (@LANG = 'fr' OR @LANG = 'FR')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)
					WHEN 'C' THEN 'Aucun'
					WHEN '9' THEN 'Différé'
					WHEN '0' THEN 'Brouillon'
					WHEN '2' THEN 'Périmé'
					WHEN '3' THEN 'Publié'
					WHEN '1' THEN 'Validé'
					WHEN '4' THEN 'En contrôle'
					ELSE 'Aucun'
				END
		END
	ELSE IF (@LANG = 'de' OR @LANG = 'DE')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)
					WHEN 'C' THEN 'Keine'
					WHEN '9' THEN 'Verspätet'
					WHEN '0' THEN 'Entwurf'
					WHEN '2' THEN 'Veraltet'
					WHEN '3' THEN 'Veröffentlicht'
					WHEN '1' THEN 'Validiert'
					WHEN '4' THEN 'Kontrolle'
					ELSE 'Keine'
				END
		END
	ELSE IF (@LANG = 'it' OR @LANG = 'IT')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)
					WHEN 'C' THEN 'No'
					WHEN '9' THEN 'Ritardato'
					WHEN '0' THEN 'Bozza'
					WHEN '2' THEN 'Obsoleto'
					WHEN '3' THEN 'Pubblicato'
					WHEN '1' THEN 'Convalidato'
					WHEN '4' THEN 'Nel controllo'
					ELSE 'No'
				END
		END
	ELSE IF (@LANG = 'en' OR @LANG = 'EN')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)
					WHEN 'C' THEN 'None'
					WHEN '9' THEN 'Delayed'
					WHEN '0' THEN 'Draft'
					WHEN '2' THEN 'Overdue'
					WHEN '3' THEN 'Published'
					WHEN '1' THEN 'Validated'
					WHEN '4' THEN 'In control'
					ELSE 'None'
				END
		END

	RETURN @V_RESULT
END
GO

-- /**
--  * FUNCTION *getReferencingStatusDescriptions*
--  * return four referencing status descriptions based on status code
--  * Input:
--  * 		status_code
--  * Output:
--  *		return description based on language
--  * For example: select dbo.getReferencingStatusDescriptions('C') => return
--  \"referencingStatusDescription_fr\":\"Aucun\",\"referencingStatusDescription_de\":\"Keine\",\"referencingStatusDescription_it\":\"No\",\"referencingStatusDescription_en\":\"Aucun\"
--  */
IF OBJECT_ID (N'dbo.getReferencingStatusDescriptions', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getReferencingStatusDescriptions
GO
CREATE FUNCTION dbo.getReferencingStatusDescriptions(@STATUS_CODE VARCHAR(1))
RETURNS VARCHAR(500)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(500)
	DECLARE @PREFIX_DESCRIPTION VARCHAR(29)
	SELECT @PREFIX_DESCRIPTION = 'referencingStatusDescription_'

	SELECT @V_RESULT = '\"' + @PREFIX_DESCRIPTION + 'fr\":\"' + dbo.getReferencingStatus(@STATUS_CODE, 'fr') + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'de\":\"' + dbo.getReferencingStatus(@STATUS_CODE, 'de') + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'it\":\"' + dbo.getReferencingStatus(@STATUS_CODE, 'it') + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'en\":\"' + dbo.getReferencingStatus(@STATUS_CODE, 'en') + '\"'
	RETURN @V_RESULT
END
GO

-- /**
--  * FUNCTION *getKindGroupDescriptions*
--  * return kind group descriptions including folder type and kind group description with multiple languages
--  *
--  * Output:
--  *		return kind group descriptions with multiple languages
--  * For example: select dbo.getKindGroupDescriptions('5PGPHO01') => return
--  \"kindGroupDescription_fr\":\"Identité ensemble immobilier - 5Sao Great Group 1 - fr\",\"kindGroupDescription_de\":\"Identité ensemble immobilier - 5Sao Great Group 1 - de\",\"kindGroupDescription_it\":\"Identité ensemble immobilier - 5Sao Great Group 1 - en\",\"kindGroupDescription_en\":\"Identité ensemble immobilier - 5Sao Great Group 1 - en\"
--  */
-- -- Please find the function named getKindGroupDescriptions in this script because the function needs the view named KITYDOV executed firstly
--
-- /**
--  * FUNCTION *getDescriptionByLanguage*
--  * return description based on language
--  * Input:
--  *		- formatted json
--  *		- prefix
--  *		- lang
--  * Output:
--  *		return description based on language
--  * For example: SELECT dbo.getDescriptionByLanguage(formatted_json, 'kindGroupDescription_', 'en') => return 5Sao Great Group 1 - en
--  */
IF OBJECT_ID (N'dbo.getDescriptionByLanguage', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getDescriptionByLanguage
GO
CREATE FUNCTION dbo.getDescriptionByLanguage(@V_JSON_STRING VARCHAR(2000), @V_PREFIX VARCHAR(255), @LANG CHAR(2))
RETURNS VARCHAR(500)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(500)
	DECLARE @TEMP_POSITION INT
	SELECT @TEMP_POSITION = CHARINDEX(@V_PREFIX + @LANG, @V_JSON_STRING)
	SELECT @V_RESULT = SUBSTRING(@V_JSON_STRING, @TEMP_POSITION + DATALENGTH(@V_PREFIX + @LANG + '":"'), DATALENGTH(@V_JSON_STRING))

	SELECT @TEMP_POSITION = CHARINDEX('","', @V_RESULT)
	IF @TEMP_POSITION <> 0
		BEGIN
			SELECT @V_RESULT = SUBSTRING(@V_RESULT, 1, (@TEMP_POSITION) - 1)
		END
	ELSE
		-- get the last prefix
		SELECT @V_RESULT = SUBSTRING(@V_RESULT, 1, DATALENGTH(@V_RESULT) - 1)
	RETURN @V_RESULT
END
GO

-- /**
--  * FUNCTION *buildDocumentDescriptionLocale*
--  * return document descriptions with multiple languages
--  *
--  * Input:
--  * 		V_JSON_STRING : default description json
--  * 		V_DEFAULT_DESCRIPTION : default description string
--  * Output:
--  *		return document descriptions locale with multiple languages
--  * For example: select dbo.buildDocumentDescriptionLocale('"description_fr":"Audio Video Interleave 3 fr","description_de":"Audio Video Interleave 3 de","description_it":"Audio Video Interleave 3 it"','AA') => return
--  * return "objectNameLocale":"objectNameLocale":[{"locale":"fr","value":"Audio Video Interleave 2 fr"},{"locale":"de","value":"Audio Video Interleave 2 fr"},{"locale":"it","value":"Audio Video Interleave 2 fr"},{"locale":"en","value":"Audio Video Interleave 2 fr"}]
--  * For example: select dbo.buildDocumentDescriptionLocale('','AA') => return
--  * return "objectNameLocale":"objectNameLocale":[{"locale":"fr","value":"AA"},{"locale":"de","value":"AA"},{"locale":"it","value":"AA"},{"locale":"en","value":"AA"}]
--  */
IF OBJECT_ID (N'dbo.buildDocumentDescriptionLocale', N'FN') IS NOT NULL
    DROP FUNCTION dbo.buildDocumentDescriptionLocale
GO
CREATE FUNCTION dbo.buildDocumentDescriptionLocale (@V_JSON_STRING VARCHAR(max), @V_DEFAULT_DESCRIPTION VARCHAR(256))
RETURNS VARCHAR(max)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(max)
	SELECT @V_RESULT = '"objectNameLocale":'
	IF @V_JSON_STRING is null or @V_JSON_STRING = ''
		BEGIN
			SELECT @V_RESULT = @V_RESULT +'[{"locale":"fr","value":"' + dbo.escapeSpecialCharacters(REPLACE(@V_DEFAULT_DESCRIPTION, '"', '&#34;')) +'"},'
			SELECT @V_RESULT = @V_RESULT +'{"locale":"de","value":"' + dbo.escapeSpecialCharacters(REPLACE(@V_DEFAULT_DESCRIPTION, '"', '&#34;')) +'"},'
			SELECT @V_RESULT = @V_RESULT +'{"locale":"it","value":"' + dbo.escapeSpecialCharacters(REPLACE(@V_DEFAULT_DESCRIPTION, '"', '&#34;')) +'"},'
			SELECT @V_RESULT = @V_RESULT +'{"locale":"en","value":"' + dbo.escapeSpecialCharacters(REPLACE(@V_DEFAULT_DESCRIPTION, '"', '&#34;')) +'"}]'
		END
	ELSE
		SELECT @V_RESULT = @V_RESULT + @V_JSON_STRING --dbo.escapeSpecialCharacters(REPLACE(@V_JSON_STRING, '"', '&#34;'))

	RETURN @V_RESULT
END
GO

