CREATE FUNCTION dbo.getMultipleLanguageFields(@V_PREFIX VARCHAR(255), @V_FR_CONTENT VARCHAR(500), @V_DE_CONTENT VARCHAR(500), @V_IT_CONTENT VARCHAR(500), @V_EN_CONTENT VARCHAR(500))
RETURNS VARCHAR(2000)
WITH EXECUTE AS CALLER
