	SELECT @V_RESULT = @V_RESULT + '\"' + @V_PREFIX + 'it\":\"' + @V_IT_CONTENT + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @V_PREFIX + 'en\":\"' + @V_EN_CONTENT + '\"'

	RETURN @V_RESULT
END
GO

