-- /**
--  * FUNCTION *getDataTypeDescriptions*
--  * return json string of descriptions
--  * Input:
--  *		- formatted_json
--  *		- default description
--  * Output:
--  *		return json string of descriptions with # at the at
--  * For example: select dbo.getDataTypeDescriptions('"dataType_fr":"VNBAH1 [FR-Display]","dataType_de":"VNBAH1 [DE-Display]","dataType_it":"VNBAH1 [FR-Display]","dataType_en":"VNBAH1 [EN-Display]"', 'desc') => return {\"dataType_fr\":\"VNBAH1 [FR-Display]\",\"dataType_de\":\"VNBAH1 [DE-Display]\",\"dataType_it\":\"VNBAH1 [FR-Display]\",\"dataType_en\":\"VNBAH1 [EN-Display]\"}#
-- 				select dbo.getDataTypeDescriptions('', 'desc') = return {\"dataType_fr\":\"desc\",\"dataType_de\":\"desc\",\"dataType_it\":\"desc\",\"dataType_en\":\"desc\"}#
--  */
IF OBJECT_ID (N'dbo.getDataTypeDescriptions', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getDataTypeDescriptions
GO
CREATE FUNCTION dbo.getDataTypeDescriptions(@V_JSON VARCHAR(2000), @V_DEFAULT_DESCRIPTION VARCHAR(500))
RETURNS VARCHAR(2000)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(2000)
	IF @V_JSON is null or @V_JSON = ''
		SELECT @V_RESULT = dbo.getDefaultDescriptions('description_', @V_DEFAULT_DESCRIPTION)
	ELSE
		SELECT @V_RESULT = replace(@V_JSON, '"', '\"')
	RETURN @V_RESULT
END
GO

