			(SELECT TOP(1) baseDesc
					FROM ecm_pacref WITH (READUNCOMMITTED)
					WHERE  ecm_pacref.baseId = ECM_PACREF_GRP.baseId AND  ecm_pacref.depId = ECM_PACREF_GRP.depId) BaseDesc,
