					WHERE  ecm_pacref.baseId = ECM_PACREF_GRP.baseId AND  ecm_pacref.depId = ECM_PACREF_GRP.depId) DepDesc,
			(SELECT TOP(1) orgId
					FROM ecm_pacref WITH (READUNCOMMITTED)
					WHERE  ecm_pacref.baseId = ECM_PACREF_GRP.baseId AND  ecm_pacref.depId = ECM_PACREF_GRP.depId) orgId,
			(SELECT TOP(1) orgDesc
					FROM ecm_pacref WITH (READUNCOMMITTED)
					WHERE  ecm_pacref.baseId = ECM_PACREF_GRP.baseId AND  ecm_pacref.depId = ECM_PACREF_GRP.depId) orgDesc
	FROM ecm_pacref ECM_PACREF_GRP  WITH (READUNCOMMITTED) group by baseId, depId'
	+')')


	-----------------------------------------------------------------------
	--handle TPACREF_DB: columns from ecm_pacref based on baseId
	exec('CREATE VIEW TPACREF_DB
			AS
			(
				SELECT baseId,
					(SELECT TOP (1) s.pacDesc
					FROM ecm_pacref s WITH (READUNCOMMITTED)
