					(SELECT TOP (1) s.depDesc
					FROM ecm_pacref s WITH (READUNCOMMITTED)
					WHERE s.baseId = m.baseId) DepDesc,
					(SELECT TOP (1) s.pacId
					FROM ecm_pacref s WITH (READUNCOMMITTED)
					WHERE s.baseId = m.baseId) PacId,
					(SELECT TOP (1) s.baseDesc
					FROM ecm_pacref s WITH (READUNCOMMITTED)
					WHERE s.baseId = m.baseId
					) BaseDesc,
					(SELECT TOP (1) s.orgId
					FROM ecm_pacref s WITH (READUNCOMMITTED)
					WHERE s.baseId = m.baseId) OrgId,
					(SELECT TOP (1) s.orgDesc
					FROM ecm_pacref s WITH (READUNCOMMITTED)
					WHERE s.baseId = m.baseId) OrgDesc
