			 	ecm_fldkw.ds1 DS1,
			 	ISNULL((SELECT ARALREP.ALAUCD FROM ARALREP WITH (READUNCOMMITTED) WHERE ARALREP.ALATCD = ecm_fldkw.ds1),'''') DS1_TYPE,
			 	ecm_fldkw.ds2 DS2,
			 	ISNULL((SELECT ARALREP.ALAUCD FROM ARALREP WITH (READUNCOMMITTED) WHERE ARALREP.ALATCD = ecm_fldkw.ds2),'''') DS2_TYPE,
			 	ecm_fldkw.ds3 DS3,
			 	ISNULL((SELECT ARALREP.ALAUCD FROM ARALREP WITH (READUNCOMMITTED) WHERE ARALREP.ALATCD = ecm_fldkw.ds3),'''') DS3_TYPE,
				ecm_fldkw.ds4 DS4,
			 	ISNULL((SELECT ARALREP.ALAUCD FROM ARALREP WITH (READUNCOMMITTED) WHERE ARALREP.ALATCD = ecm_fldkw.ds4),'''') DS4_TYPE,
			 	ecm_fldtyp.typeNme as type_id,
