	-- beginning of getKindGroupDescriptions function
	IF OBJECT_ID (N'dbo.getKindGroupDescriptions', N'FN') IS NOT NULL
		DROP FUNCTION dbo.getKindGroupDescriptions
	GO
	CREATE FUNCTION dbo.getKindGroupDescriptions(@DOC_TYPE_ID CHAR(8), @FORMATTED_JSON_FOLDER_TYPE VARCHAR(900), @FORMATTED_JSON_KIND_GROUP VARCHAR(900))
		RETURNS VARCHAR(900)
		WITH EXECUTE AS CALLER
		AS
		BEGIN
			DECLARE @V_RESULT VARCHAR(max)
			DECLARE @V_FOLDER_TYPE_ID CHAR(2)
			DECLARE @V_KIND_GROUP_ID VARCHAR(200)

			select @V_KIND_GROUP_ID = (select kindGrId from KITYDOV where docTyId = @DOC_TYPE_ID)
			select @V_FOLDER_TYPE_ID = (select fldTyId from ecm_kitydo where kindId in (select kindId from KITYDOV where docTyId = @DOC_TYPE_ID) and docTyId = @DOC_TYPE_ID)

			IF @V_KIND_GROUP_ID is null or @V_KIND_GROUP_ID = ''
				BEGIN
					select @V_RESULT = REPLACE(dbo.escapeSpecialCharacters(REPLACE((select formatted_json from ecm_param where param_id = @V_FOLDER_TYPE_ID and param_type = 'FOLDERTYPE'), 'type', 'kindGroupDescription')), '\\\"', '\"')
				END
			ELSE
				BEGIN
					SELECT @V_RESULT = ('\"kindGroupDescription_fr\":\"' + (dbo.getDescriptionByLanguage(@FORMATTED_JSON_FOLDER_TYPE, 'type_', 'fr')) + ' - ' +
																		   (dbo.getDescriptionByLanguage(@FORMATTED_JSON_KIND_GROUP, 'kindGroupDescription_', 'fr')) + '\",')
					SELECT @V_RESULT = @V_RESULT + ('\"kindGroupDescription_de\":\"' + (dbo.getDescriptionByLanguage(@FORMATTED_JSON_FOLDER_TYPE, 'type_', 'de')) + ' - ' +
																					   (dbo.getDescriptionByLanguage(@FORMATTED_JSON_KIND_GROUP, 'kindGroupDescription_', 'de')) + '\",')
					SELECT @V_RESULT = @V_RESULT + ('\"kindGroupDescription_it\":\"' + (dbo.getDescriptionByLanguage(@FORMATTED_JSON_FOLDER_TYPE, 'type_', 'it')) + ' - ' +
																					   (dbo.getDescriptionByLanguage(@FORMATTED_JSON_KIND_GROUP, 'kindGroupDescription_', 'it')) + '\",')
					SELECT @V_RESULT = @V_RESULT + ('\"kindGroupDescription_en\":\"' + (dbo.getDescriptionByLanguage(@FORMATTED_JSON_FOLDER_TYPE, 'type_', 'en')) + ' - ' +
																					   (dbo.getDescriptionByLanguage(@FORMATTED_JSON_KIND_GROUP, 'kindGroupDescription_', 'en')) + '\"')
				END

			-- IF the value is null, set it to empty
			RETURN ISNULL(@V_RESULT, '')
		END
	GO
	-- end of getKindGroupDescriptions function

	DECLARE @LANG VARCHAR(2) = 'fr'
 	DECLARE @V_VISA_DECISION_A VARCHAR(15)
	DECLARE @V_VISA_DECISION_R VARCHAR(15)

	IF @LANG = 'en' OR @LANG = 'EN'
		BEGIN
			SET @V_VISA_DECISION_A 				= 'Accepted'
			SET @V_VISA_DECISION_R 				= 'Refused'
		END


	IF  @LANG = 'fr' OR @LANG = 'FR'
		BEGIN
			SET @V_VISA_DECISION_A 				= 'Accepté'
			SET @V_VISA_DECISION_R  			= 'Refusé'
		END

		IF  @LANG = 'de' OR @LANG = 'DE'
		BEGIN
			SET @V_VISA_DECISION_A 				= 'Angenommen'
			SET @V_VISA_DECISION_R  			= 'Abgelehnt'
		END

	DECLARE @V_DYNAMICSQL VARCHAR(MAX)
