	-----------------------------------------------------------------------
	--get list of visa and insert into visas temp table
	SET @V_DYNAMICSQL = 'SELECT ARCKREP.CKASVN document_id,
		   ''{\"visaTypeId\":\"'' + CKIGST + ''\",\"visaTypeDescription\":\"'' + dbo.escapeSpecialCharacters(SE11mA) + ''\"''+
		   CASE WHEN CKB4DT IS NULL THEN '''' ELSE dbo.convertDateField(''date'',CKB4DT) END +'',\"userName\":\"'' +
		   RTRIM(CKKZCD) + ''\",\"userDescription\":\"''' + ' + (select top(1) ISNULL(MAX(fullname),'''') from TUSERDES WITH (READUNCOMMITTED) where name=RTRIM(CKKZCD)) + ' + '''\",\"decisionCode\":\"'' + CKIFST + ''\",\"decisionDescription\":\"'' + (CASE WHEN CKIFST IS NULL
	OR CKIFST = ''''
	OR CKIFST = ''A'' THEN '''+@V_VISA_DECISION_A+''' WHEN CKIFST = ''R'' THEN '''+@V_VISA_DECISION_R+''' END) + ''\"}'' json
	FROM ARCKREP WITH (READUNCOMMITTED) ,
		 SE11uT WITH (READUNCOMMITTED)
	WHERE ARCKREP.CKIGST = SE11uT.SE11kA'
	exec('CREATE VIEW TVISA_HELPER AS (' + @V_DYNAMICSQL +')')

	------------------------------------------------------------------------
	--create views to prevent duplicate value in ecm_KwDe table
	SET @V_DYNAMICSQL = 'SELECT DISTINCT kwdid FROM ecm_KwDe WITH (READUNCOMMITTED) '
	exec('CREATE VIEW KWDEIDV AS ('+@V_DYNAMICSQL+')')

	SET @V_DYNAMICSQL = 'SELECT t1.kwdid , (select top(1) t2.KwdLbl from ecm_KwDe t2  WITH (READUNCOMMITTED) where t1.kwdid=t2.kwdid) kwdlbl FROM KWDEIDV t1 WITH (READUNCOMMITTED) '
	exec('CREATE VIEW KWDEV AS ('+@V_DYNAMICSQL+')')
	------------------------------------------------------------------------------
	--create view for ecm_fldtyp
	exec('CREATE VIEW FLDTYPV AS (
	SELECT base, typeID, type, typeNme, prefixDs1, prefixDs2, prefixDs3, label_folder_id, label_description_1, label_description_2, label_description_3
		   FROM ecm_fldtyp WITH (READUNCOMMITTED)
		  GROUP BY base, typeID, type, typeNme, prefixDs1, prefixDs2, prefixDs3, label_folder_id, label_description_1, label_description_2, label_description_3)')

	------------------------------------------------------------------------------
	--create view contains [Master-document-id] [version-document-id]
	-- if A.PDF is base document, 		view contains [A.PDF] [A.PDF]
	-- if C.PDF is a version of A.PDF,	view contains [A.PDF] [C.PDF]
	-- select all [version-document-id] == select APASVN from ARAPREP
	exec('CREATE VIEW BASE_VERV AS ('+
			'select APASVN BASE,APASVN VERSION from ARAPREP WITH (READUNCOMMITTED) where APBBST!=''V''
			UNION ALL
			select BMG7NA BASE,BMASVN VERSION from ARBMREP WITH (READUNCOMMITTED) ,ARAPREP WITH (READUNCOMMITTED) where  APBBST=''V'' and BMASVN=APASVN'
		+')')

	exec('CREATE VIEW TVISA AS (
	SELECT document_id,
					dbo.escapeXMLCharacters(substring(
						(SELECT '',''+json
						 FROM TVISA_HELPER t2 WITH (READUNCOMMITTED)
						 WHERE t1.document_id = t2.document_id
						   FOR XML PATH('''')),2,214483647)) json
	FROM TVISA_HELPER t1  WITH (READUNCOMMITTED) group by document_id)')

	------------------------------------------------------------------------------
	--get list of document comments and insert into comments temp table with new comment table DDRHVT
	exec('CREATE VIEW TCOMMENT_HELPER AS (
		SELECT  DD1rA document_id,
				''{\"typeId\":\"''+DD40A+
				''\",\"typeDescription\":\"''+ARATREP.ATANNA+
				''\",\"creationUserName\":\"''+isnull(rtrim(DDri3A),'''')+
				''\",\"creationUserDescription\":\"''+isnull((select top(1) fullname from TUSERDES  WITH (READUNCOMMITTED) where name=RTRIM(DDri3A)),'''')+
				''\",\"creationDatetime\":\"''+dbo.convertDate7StringsToISODate(DDriiA,DDrijA)+
				''\",\"modificationUserName\":\"''+isnull(rtrim(DD43A),'''')+
				''\",\"modificationUserDescription\":\"''+isnull((select top(1) fullname from TUSERDES  WITH (READUNCOMMITTED) where name=RTRIM(DD43A)),'''')+
				''\",\"modificationDatetime\":\"''+dbo.convertDate7StringsToISODate(DD44A,DDrikA)+
				''\",\"comment\":\"'' + dbo.escapeSpecialCharacters(TSCLOB) + ''\"}'' json
				FROM DDrhvT WITH (READUNCOMMITTED) ,DDCLOB WITH (READUNCOMMITTED) ,ARATREP WITH (READUNCOMMITTED) WHERE DDrhvT.DDpp7A = DDCLOB.TSCID and DDrhvT.DD40A = ARATREP.ATAVCD
	)')
	exec('CREATE VIEW TCOMMENT AS (SELECT document_id,
					  dbo.escapeXMLCharacters(substring((SELECT '',''+json
					   FROM TCOMMENT_HELPER t2 WITH (READUNCOMMITTED)
					   WHERE t1.document_id = t2.document_id
						 FOR XML PATH('''')),2,214483647)) json
	  FROM TCOMMENT_HELPER t1  WITH (READUNCOMMITTED) group by document_id)')
	------------------------------------------------------------------------------
	--security user name
	SET @V_DYNAMICSQL = 'SELECT DD1RA document_id,
					dbo.escapeXMLCharacters(substring((SELECT '',"'' + DDCHPA + ''"'' FROM DDDCRSTACC t2 WITH (READUNCOMMITTED)
								 WHERE t1.DD1RA = t2.DD1RA FOR XML PATH('''')),2,214483647)) json
	FROM DDDCRSTACC t1 WITH (READUNCOMMITTED) group by DD1RA'
	exec('CREATE VIEW TSECUNAME AS (' + @V_DYNAMICSQL +')')

	-----------------------------------------------------------------------
	--readLinkedDocumentAndVersionIds
	exec('CREATE VIEW TLINK_HELPER AS (SELECT  ARAPREP.APASVN document_id,
		   ARBMREP.BMASVN link_document_id,
		  (SELECT APBBST
		   FROM ARAPREP WITH (READUNCOMMITTED)
		   WHERE APASVN = ARBMREP.BMASVN) AS link_document_type
		FROM ARBMREP WITH (READUNCOMMITTED),
			 ARAPREP WITH (READUNCOMMITTED)
		WHERE ARBMREP.BMG7NA = ARAPREP.APASVN)')

	exec('CREATE VIEW TLINK AS (SELECT document_id,
					dbo.escapeXMLCharacters(substring(
						(SELECT '',\"'' + link_document_id + ''\"''
						 FROM TLINK_HELPER t2 WITH (READUNCOMMITTED)
						 WHERE t1.document_id = t2.document_id
						   AND t2.link_document_type !=''V''
						   FOR XML PATH('''')),2,214483647)) json_link,
					dbo.escapeXMLCharacters(substring(
						(SELECT '',\"'' + link_document_id + ''\"''
						 FROM TLINK_HELPER t2 WITH (READUNCOMMITTED)
						 WHERE t1.document_id = t2.document_id
						   AND (t2.link_document_type IS NULL
								OR t2.link_document_type=''V'')
						   FOR XML PATH('''')),2,214483647)) json_version
	FROM TLINK_HELPER t1  WITH (READUNCOMMITTED) group by document_id)')

	-----------------------------------------------------------------------
	-- organization parameter setting
	exec('CREATE VIEW ORG_PARAM_V AS (SELECT param_data, param_id, formatted_json, param_type FROM ecm_param WITH (READUNCOMMITTED) WHERE param_type = ''ORGANIZATION'')')

------------------------------------------------------------------------------
--  + PART 6 : CREATE STORE PROCEDURE USED TO READ ALL DOCUMENT INFOMATION   --
------------------------------------------------------------------------------
-- /*
-- * this store will export documents for indexation.
-- * to execute this procedure for single document, run:
-- * declare @OBJECT_DESCRIPTOR VARCHAR(MAX)
-- * EXEC exportdoc @OBJECT_DESCRIPTOR = @OBJECT_DESCRIPTOR output,@DOCUMENTID = '5ZWD0H4S.PDF',@SEC_ENVIRONMENT='', @ENVIRONMENT='Default'
-- * select @OBJECT_DESCRIPTOR
-- *
-- * to execute this procedure for all documents (mass indexation), run:
-- * declare @OBJECT_DESCRIPTOR VARCHAR(MAX)
-- * EXEC exportdoc @OBJECT_DESCRIPTOR = @OBJECT_DESCRIPTOR output,@DOCUMENTID = '_ALL_',@SEC_ENVIRONMENT='', @ENVIRONMENT='Default'
-- * Notes: all data will be put into table TOBJDESC
-- *
-- * to export data from TOBJDESC to physical file, run:
-- * exec xp_cmdshell 'bcp "select document_descriptor from xlinedtaJ30.dbo.TOBJDESC ORDER BY indexation_id" queryout \\vntiws03\TI-5Star\descriptors.txt -w -T -r \n'
-- */

SET QUOTED_IDENTIFIER ON
GO
SET ANSI_NULLS ON
GO

EXEC ('IF EXISTS (SELECT * FROM sysobjects WHERE id = object_id(N''exportdoc'') AND OBJECTPROPERTY(id, N''IsProcedure'') = 1)
		BEGIN
			DROP PROCEDURE exportdoc
		END')
GO

CREATE PROCEDURE exportdoc
	@DOCUMENTID VARCHAR(12) = '',					-- The identifier of document to export. If given value is '_ALL_', export all XECM documents
	@SEC_ENVIRONMENT VARCHAR(10),					-- Temporary variable, keep it for now to avoid the change JAVA code in XOST where it called by XECMDataImportProcessor
	@ENVIRONMENT VARCHAR(500), 						-- This variable contains the tenant: Example: Default, 001
 	@LANG VARCHAR(2) = 'en',						-- Language code. Available: 'en','fr','EN','FR','de','DE'
 	@ACTION VARCHAR(10) = 'CONTINUE',				-- An argument to let procedure continue (or not) from the last mass exportation. Available: 'RESTART' or 'CONTINUE'. Default: CONTINUE
	@SESSION_ID VARCHAR(100) = 'ALL',				-- Unique ID to identify the indexation processor call and avoid to mix indexations
	@CPU_NR SMALLINT = 1,                           -- number of CPUs
	@CPU_TO_USE SMALLINT = 0,                       -- CPU to use
    @MAXIMUM_DESCRIPTOR_SIZE INT = 0,               -- Maximum descriptor in TOBJDESC at a time
	@OBJECT_DESCRIPTOR TEXT  OUTPUT					-- The object descriptors will be returned. If given @DOCUMENTID is '_ALL_' (mean mass indexation), no ouptput is returned
AS
BEGIN

   -- Script version name: 3.5.0 23q1
      -- The version mentioned here doesn't necessarily match the EAR version
      -- Check the "Minimal required script version number" section within the ReadMe.html file distributed with the project to know if the procedure has to be updated
   -- Script last modificationDate(dd/mm/yyyy): 24/04/2022 09:34

 	DECLARE @V_CLIENTHOSTNAME VARCHAR(50) = case when @ENVIRONMENT is null then 'Default' else @ENVIRONMENT end
	DECLARE @V_ACTION VARCHAR(10)
	DECLARE @V_DOCUMENTID VARCHAR(12) = @DOCUMENTID
	DECLARE @V_IS_READ_SINGLE_DOCUMENT BIT = 0
	DECLARE @HAS_FOLDER_TYPE BIT = 0
	DECLARE @IS_PAC_MODE BIT = 0
	DECLARE @V_ISDEBUGGING BIT = 0 -- set to 1 to debug procedure
	DECLARE @V_ISDEBUGGING_DETAILED BIT = 0 -- set to 1 to debug procedure
	DECLARE @INDEXATION_START DATETIME
	DECLARE @PRIORITY TINYINT = 1 -- @V_ACTION = 'RESTART' OR @V_ACTION = 'CONTINUE'
	DECLARE @V_DYNAMICSQL NVARCHAR(MAX)
	DECLARE @DOCUMENT_TO_INDEX INT = 1
	SET language English -- fix for issue invalid date (month and day is switch together in French language -- make export process always run with english)

	DECLARE @V_SEPARATOR CHAR(1) = '/'
        DECLARE @V_PROCESS_TIME_STAMP VARCHAR(50)

    DECLARE @TimeZone VARCHAR(50)
    EXEC master.dbo.xp_regread 'HKEY_LOCAL_MACHINE','SYSTEM\CurrentControlSet\Control\TimeZoneInformation','TimeZoneKeyName',@TimeZone OUT

	--set the flag is read single document or read all documents( for mass indexation)
	SET @V_IS_READ_SINGLE_DOCUMENT = CASE WHEN @DOCUMENTID = '_ALL_' THEN 0 ELSE 1 END

	-- check has folder type
	SET @HAS_FOLDER_TYPE = CASE WHEN (SELECT COUNT(*) FROM ecm_fldtyp WITH (READUNCOMMITTED) )> 0 THEN 1 ELSE 0 END

	-- check PAC mode
	SET @IS_PAC_MODE = CASE WHEN (SELECT COUNT(*) FROM ecm_pacref WITH (READUNCOMMITTED) WHERE orgId IS NOT NULL AND orgId <> '') >0 THEN 1 ELSE 0 END

	--set default action
	SET @V_ACTION = UPPER(@ACTION)
	IF @V_ACTION != 'RESTART' AND @V_ACTION != 'CONTINUE' AND @V_ACTION != 'PROCESSOR' AND @V_ACTION != 'EXPORTJSON'
		SET @V_ACTION = 'CONTINUE'

	-- to increase performance, don't return the count
	SET NOCOUNT ON

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT NULL, '1'

	IF ( @V_ACTION = 'PROCESSOR' )
		BEGIN
			IF ( SELECT COUNT(*) FROM ECM_DOCIDX WITH (READUNCOMMITTED) WHERE SESSION_ID = @SESSION_ID ) > 0  -- A process indexation is already running
				SET @DOCUMENT_TO_INDEX = 0
		END

