	BEGIN TRAN
		DECLARE @Semaphore INT
		SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )
		CREATE TABLE #KEYWORD (
			document_id				VARCHAR(12) NULL,
			datatype_id 			VARCHAR(200) NULL,
			json					VARCHAR(MAX) NULL,
			dynamic_key_pair		VARCHAR(MAX) NULL,
			search_type				VARCHAR(MAX) NULL,
			is_folder_keyword       bit NULL
		)

		CREATE NONCLUSTERED INDEX #KEYWORD_IX1 ON #KEYWORD (document_id)
			   INCLUDE (search_type)
		CREATE NONCLUSTERED INDEX #KEYWORD_IX2 ON #KEYWORD (document_id)
			   INCLUDE (dynamic_key_pair)
		CREATE NONCLUSTERED INDEX #KEYWORD_IX3 ON #KEYWORD (document_id, datatype_id, is_folder_keyword)
			   INCLUDE (json)
			   WHERE json is not null and json != '' and datatype_id != '!GNDO'
	COMMIT

