		datatype_type				CHAR(2) NULL,
		datatype_lstid				VARCHAR(MAX) NULL,
		datatype_value_fr			VARCHAR(MAX) NULL,
		datatype_value_de			VARCHAR(MAX) NULL,
		datatype_value_it			VARCHAR(MAX) NULL,
		datatype_value_en			VARCHAR(MAX) NULL,
		datatype_value_fr_evaluated	VARCHAR(MAX) NULL,
		datatype_value_de_evaluated	VARCHAR(MAX) NULL,
		datatype_value_it_evaluated	VARCHAR(MAX) NULL,
		datatype_value_en_evaluated	VARCHAR(MAX) NULL,
		formatted_json				VARCHAR(MAX) NULL,
		is_folder_keyword       	bit NULL
	)

	CREATE TABLE #KEYWORD2 (
		document_id				VARCHAR(12) NULL,
		datatype_id 			VARCHAR(5) NULL,
