			   WHERE value_it != ''
		CREATE NONCLUSTERED INDEX #ECM_KWLST_IX5 on #ECM_KWLST ( document_id, kwid )
			   INCLUDE (value_en)
			   WHERE value_en != ''
	COMMIT

