	CREATE TABLE #ECM_KWDE
	(
		kwdid VARCHAR(5),
		kwdlbl VARCHAR(200)
	)

	INSERT INTO #ECM_KWDE SELECT kwdid, dbo.escapeSpecialCharacters(MIN(KwdLbl)) FROM ecm_KwDe WITH (READUNCOMMITTED) GROUP BY kwdid

	CREATE NONCLUSTERED INDEX #KWDEV_IX1 ON #ECM_KWDE
	(
		kwdid ASC
	)
	INCLUDE (kwdlbl)

	-- end create work tables
	-----------------------------------------------------------------------

	DECLARE @batch_id int
    DECLARE @Semaphore_indexation_batch INT

	WHILE @DOCUMENT_TO_INDEX > 0
	BEGIN
	IF @V_IS_READ_SINGLE_DOCUMENT = 0
		BEGIN
			IF ( @V_ACTION = 'RESTART' AND @CPU_TO_USE = 0 )
				BEGIN
					IF ( @SESSION_ID is NULL )
						SET @SESSION_ID = 'ALL'
					DELETE FROM TOBJDESC WHERE SESSION_ID = @SESSION_ID
					DELETE FROM INDEXATION_BATCH WHERE SESSION_ID = @SESSION_ID
				END

			IF ( @V_ACTION = 'CONTINUE' AND @SESSION_ID is NULL )
				SET @SESSION_ID = 'ALL'

			IF ( @V_ACTION = 'PROCESSOR' )
				BEGIN
					IF EXISTS ( SELECT * FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DDr68A = 'S' ) AND NOT EXISTS ( SELECT * FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DDr68A = 'L' ) -- The processor is stopped
						RETURN

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1a'

                    BEGIN TRAN
                        -- gitlab#130
                        SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                        IF ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1a1'
                        BEGIN
                            DELETE FROM TOBJDESC WHERE BATCH_ID IN (SELECT BATCH_ID FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 0)
                            DELETE FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 0
                        END
                    COMMIT

					BEGIN TRAN
					SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1b'

					SELECT @PRIORITY = MAX(DDHZ9A) FROM ARG0CPP WHERE DDr68A IN ( 'R', 'M', 'N', 'U' ) AND DD1rA NOT IN ( SELECT DOCUMENT_ID FROM ECM_DOCIDX )

					if ( @PRIORITY IS NOT NULL )
						BEGIN
							INSERT INTO ECM_DOCIDX SELECT TOP 3000 @SESSION_ID, DD1rA, DDr68A FROM ARG0CPP WHERE DDr68A IN ( 'R', 'M', 'N', 'U' ) AND DD1rA NOT IN ( SELECT DOCUMENT_ID FROM ECM_DOCIDX ) AND DDHZ9A = @PRIORITY
							if ( @PRIORITY < 2 ) SET @PRIORITY = 2
						END
					ELSE
						SET @PRIORITY = 2

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1c'

					SELECT @INDEXATION_START = MAX( DDr67A ) FROM ARG0CPP, ECM_DOCIDX WHERE SESSION_ID = @SESSION_ID AND DOCUMENT_ID = DD1rA

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1d'

					INSERT INTO ECM_DOCIDX SELECT TOP 1000 @SESSION_ID, BMASVN, 'R' FROM ECM_DOCIDX, ARBMREP WHERE DOCUMENT_ID = BMG7NA AND DOCUMENT_ID <> BMASVN AND BMASVN NOT IN ( SELECT DOCUMENT_ID FROM ECM_DOCIDX )

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1e'

					COMMIT

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '1f'
				END
					ELSE SET @DOCUMENT_TO_INDEX = 0

			IF ( @V_ACTION = 'RESTART' OR @V_ACTION = 'PROCESSOR' )
				BEGIN
					DECLARE @first_document_id VARCHAR(50)
					DECLARE @last_document_id VARCHAR(50)
					DECLARE @document_batch_max int
					DECLARE @document_position bigint

					SELECT @first_document_id = null
					SELECT @document_position = 1
					SELECT @document_batch_max = 1000

					IF ( @V_ACTION = 'RESTART' AND @CPU_TO_USE = 0 )
						DECLARE document_cursor CURSOR FOR SELECT APASVN FROM ARAPREP ORDER BY APASVN
					ELSE
 						DECLARE document_cursor CURSOR FOR SELECT DOCUMENT_ID FROM ECM_DOCIDX WHERE ECM_DOCIDX.SESSION_ID = @SESSION_ID ORDER BY DOCUMENT_ID

					OPEN document_cursor

					FETCH document_cursor INTO @last_document_id

					WHILE @@FETCH_STATUS = 0
						BEGIN
							IF ( @document_position = @document_batch_max )
								BEGIN
									INSERT INTO INDEXATION_BATCH (SESSION_ID, BATCH_START, BATCH_END, PRIORITY, COMPUTED, SOLR_STATUS, HOST_NAME, TIMESTAMP ) VALUES ( @SESSION_ID, @first_document_id, @last_document_id, @PRIORITY, 0, 0, null, null )

									SELECT @document_position = 0

									FETCH document_cursor INTO @last_document_id

									SELECT @first_document_id = @last_document_id

									SELECT @last_document_id = null

									SELECT @document_position = @document_position + 1
								END
							ELSE
								BEGIN
									IF ( @first_document_id is null )
										SELECT @first_document_id = @last_document_id

									FETCH document_cursor INTO @last_document_id

									SELECT @document_position = @document_position + 1
								END
						END

					CLOSE document_cursor
					DEALLOCATE document_cursor

					IF ( @first_document_id is not null AND @last_document_id is not null )
						INSERT INTO INDEXATION_BATCH (SESSION_ID, BATCH_START, BATCH_END, PRIORITY, COMPUTED, SOLR_STATUS, HOST_NAME, TIMESTAMP ) VALUES ( @SESSION_ID, @first_document_id, @last_document_id, @PRIORITY, 0, 0, null, null )
				END
		END
			ELSE SET @DOCUMENT_TO_INDEX = 0

	--SET @V_DOCUMENTID = masterDocumentId if the given document is version to calculate folder entries and keywords
	IF @V_IS_READ_SINGLE_DOCUMENT = 1 AND (SELECT APBBST FROM ARAPREP WITH (READUNCOMMITTED) WHERE APASVN = @DOCUMENTID) = 'V'
		SET @V_DOCUMENTID = (SELECT BMG7NA FROM ARBMREP WITH (READUNCOMMITTED) WHERE BMASVN = @DOCUMENTID)

	------------------------------------------------------------------------------
	--	process each batch
	DECLARE @batch_start VARCHAR(400)
	DECLARE @batch_end VARCHAR(400)
	DECLARE @FETCH_STATUS INT
    DECLARE @REMAIN_PROCESSING_DESCRIPOR INT

	IF @V_IS_READ_SINGLE_DOCUMENT = 0
		BEGIN
			IF ( @V_ACTION = 'PROCESSOR' )
				DECLARE batch_cursor CURSOR LOCAL FOR
					SELECT BATCH_ID, BATCH_START, BATCH_END FROM INDEXATION_BATCH WHERE SESSION_ID = @SESSION_ID and PRIORITY >= 2 and COMPUTED = 0 FOR UPDATE OF COMPUTED
			ELSE -- @V_ACTION = 'RESTART' OR @V_ACTION = 'CONTINUE'
            -- @MAXIMUM_DESCRIPTOR_SIZE > 0 continue from the stopped batch with priority 1 or higher
				DECLARE batch_cursor CURSOR LOCAL FOR
                    SELECT BATCH_ID, BATCH_START, BATCH_END FROM INDEXATION_BATCH WHERE SESSION_ID = @SESSION_ID AND PRIORITY = 1 and COMPUTED = 0 ORDER BY BATCH_ID DESC FOR UPDATE OF COMPUTED

			OPEN batch_cursor

			FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end

			SET @FETCH_STATUS = @@FETCH_STATUS

			WHILE ( @FETCH_STATUS = 0 AND @batch_id % @CPU_NR != @CPU_TO_USE )
			BEGIN
				FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end
				SET @FETCH_STATUS = @@FETCH_STATUS
			END
		END
	ELSE
		BEGIN
			SET @FETCH_STATUS = 0
			SET @batch_start = @DOCUMENTID
			SET @batch_end = @DOCUMENTID
		END

	IF OBJECT_ID( 'tempdb..#ECM_PARAM' ) IS NULL
		BEGIN
			CREATE TABLE #ECM_PARAM (
				param_id		VARCHAR(50) NOT NULL,
				param_type		VARCHAR(225) NOT NULL,
				value_fr		VARCHAR(500) NULL,
				value_de		VARCHAR(500) NULL,
				value_en		VARCHAR(500) NULL,
				value_it		VARCHAR(500) NULL,
				formatted_json	VARCHAR(2000) NULL )

			CREATE TABLE #ECM_FLDTYP (
				base				CHAR(5)	 NOT NULL,
				typeID				VARCHAR(200) NOT NULL,
				type				VARCHAR(200) NOT NULL,
				typeNme				VARCHAR(200) NOT NULL,
				prefixDs1			CHAR(6) NOT NULL,
				prefixDs2			CHAR(6) NULL,
				prefixDs3			CHAR(6) NULL,
				prefixDs4			CHAR(6) NULL,
				label_folder_id		VARCHAR(256) NULL,
				label_description_1	VARCHAR(256) NULL,
				label_description_2	VARCHAR(256) NULL,
				label_description_3	VARCHAR(256) NULL,
				label_description_4	VARCHAR(256) NULL )

			CREATE TABLE #ECM_PACREF (
				BASE		CHAR(5) NOT NULL,
				depId		CHAR(3) NULL,
				pacDesc		VARCHAR(200) NOT NULL,
				pacId		VARCHAR(200) NOT NULL,
				baseDesc	VARCHAR(200) NOT NULL,
				depDesc		VARCHAR(200) NOT NULL,
				orgId		VARCHAR(200) NOT NULL,
				orgDesc		VARCHAR(200) NOT NULL )

			INSERT INTO #ECM_PACREF
			SELECT baseId,
                   depId,
                   pacDesc,
                   pacId,
                   baseDesc,
				REPLACE(depDesc, '"', '&#34;'),
				orgId,
				orgDesc
			FROM ecm_pacref WITH (READUNCOMMITTED)
			GROUP BY baseId, depId, pacDesc, pacId, baseDesc, depDesc, orgId, orgDesc

			CREATE NONCLUSTERED INDEX #ECM_PACREF_IX1 on #ECM_PACREF ( BASE )
			CREATE NONCLUSTERED INDEX #ECM_PACREF_IX2 on #ECM_PACREF ( BASE, depId )

			INSERT INTO #ECM_PARAM
			SELECT param_id,
				param_type,
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'type_', 'fr')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'type_', 'de')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'type_', 'en')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'type_', 'it')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
			FROM ecm_param WITH (READUNCOMMITTED)
			WHERE param_type = 'FOLDERTYPE'

			INSERT INTO #ECM_PARAM
			SELECT param_id,
				param_type,
				'',
				'',
				'',
				'',
				REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
			FROM ecm_param WITH (READUNCOMMITTED)
			WHERE param_type = 'DATABASE'

			INSERT INTO #ECM_PARAM
			SELECT param_id,
				param_type,
				'',
				'',
				'',
				'',
				REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
			FROM ecm_param WITH (READUNCOMMITTED)
			WHERE param_type = 'PAC'

			INSERT INTO #ECM_FLDTYP
			SELECT base, typeID, type, typeNme, prefixDs1, prefixDs2, prefixDs3, prefixDs4, label_folder_id, label_description_1, label_description_2, label_description_3, label_description_4
			FROM ecm_fldtyp WITH (READUNCOMMITTED)
			GROUP BY base, typeID, type, typeNme, prefixDs1, prefixDs2, prefixDs3, prefixDs4, label_folder_id, label_description_1, label_description_2, label_description_3, label_description_4

			CREATE NONCLUSTERED INDEX #ECM_FLDTYP_IX1 on #ECM_FLDTYP ( base, typeID )
			CREATE NONCLUSTERED INDEX #ECM_FLDTYP_IX2 on #ECM_FLDTYP ( base, typeNme )
			CREATE NONCLUSTERED INDEX #ECM_FLDTYP_IX3 on #ECM_FLDTYP ( base, prefixDs1 )

			INSERT INTO #ECM_PARAM
			SELECT param_id,
				param_type,
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'dataType_', 'fr')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'dataType_', 'de')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'dataType_', 'en')), '\\\"', '\"'),
				REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'dataType_', 'it')), '\\\"', '\"'),
				REPLACE(REPLACE(REPLACE(dbo.escapeSpecialCharacters(STUFF(formatted_json, LEN(formatted_json), 0, ' ')), '\\\"', '\"'), '":\"', '":\" '), '\",\"', ' \",\"')
			FROM ecm_param WITH (READUNCOMMITTED)
			WHERE param_type = 'DATATYPE'

			IF @V_IS_READ_SINGLE_DOCUMENT = 0
				BEGIN
					INSERT INTO #ECM_PARAM
					SELECT param_id,
						param_type,
						'',
						'',
						'',
						'',
						REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
					FROM ecm_param WITH (READUNCOMMITTED) WHERE param_type = 'KINDDOCUMENT'

					INSERT INTO #ECM_PARAM
					SELECT param_id,
						param_type,
						'',
						'',
						'',
						'',
						REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
					FROM ecm_param WITH (READUNCOMMITTED) WHERE param_type = 'DEPARTMENT'

					INSERT INTO #ECM_PARAM
					SELECT param_id,
						param_type,
						'',
						'',
						'',
						'',
						REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
						FROM ecm_param WITH (READUNCOMMITTED) WHERE param_type = 'EDITOR'
				END
				ELSE
				BEGIN
					INSERT INTO #ECM_PARAM
					SELECT param_id,
						param_type,
						'',
						'',
						'',
						'',
						REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
					FROM ecm_param WITH (READUNCOMMITTED)
					WHERE param_type = 'KINDDOCUMENT'

					INSERT INTO #ECM_PARAM
					SELECT param_id,
						param_type,
						'',
						'',
						'',
						'',
						REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
					FROM ecm_param WITH (READUNCOMMITTED),
						ARAPREP WITH (READUNCOMMITTED)
					WHERE APASVN = @DOCUMENTID AND
						APAOCD = param_id AND
						param_type = 'DEPARTMENT'

					INSERT INTO #ECM_PARAM
					SELECT param_id,
						param_type,
						'',
						'',
						'',
						'',
						REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '\"')
					FROM ecm_param WITH (READUNCOMMITTED),
						ARAPREP WITH (READUNCOMMITTED)
					WHERE APASVN = @DOCUMENTID AND
						APADCD = param_id AND
						param_type = 'EDITOR'
				END

			CREATE NONCLUSTERED INDEX #ECM_PARAM_IX1 on #ECM_PARAM ( param_type, param_id ) INCLUDE (formatted_json)
		END

	WHILE @FETCH_STATUS = 0
		BEGIN
                    if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '2'

                    IF @V_IS_READ_SINGLE_DOCUMENT = 0 AND @MAXIMUM_DESCRIPTOR_SIZE > 0
                        BEGIN
                            SELECT @REMAIN_PROCESSING_DESCRIPOR = count(*) FROM TOBJDESC WITH (READUNCOMMITTED)
                            WHILE @REMAIN_PROCESSING_DESCRIPOR > @MAXIMUM_DESCRIPTOR_SIZE
                                BEGIN
                                    WAITFOR DELAY '00:00:30'
                                    BEGIN TRAN
                                        -- gitlab#203
                                        SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                                        IF ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '2a1'
                                        BEGIN
                                            DELETE FROM TOBJDESC WHERE BATCH_ID IN (SELECT BATCH_ID FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 0)
                                            DELETE FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 0
                                        END
                                    COMMIT
                                    SELECT @REMAIN_PROCESSING_DESCRIPOR = count(*) FROM TOBJDESC WITH (READUNCOMMITTED)
                                END
                        END

                    SET @V_PROCESS_TIME_STAMP = format(getutcdate(),'yyyy-MM-ddTHH:mm:ss.fff') + 'Z'

                    TRUNCATE TABLE #TPARFLD_HELPER1
                    TRUNCATE TABLE #TPARFLD
                    TRUNCATE TABLE #TFOLDER_HELPER
                    TRUNCATE TABLE #TFOLDER_BY_DOCUMENT
                    TRUNCATE TABLE #TDOCID
                    TRUNCATE TABLE #TFOLDER_TEMP
                    TRUNCATE TABLE #TFOLDER_DESCRIPTION
                    TRUNCATE TABLE #VERSION
                    TRUNCATE TABLE #TOBJDESC_SEG
                    TRUNCATE TABLE #ALLVERSN
                    TRUNCATE TABLE #VERDESHP
                    TRUNCATE TABLE #VERSDESC
                    TRUNCATE TABLE #ECM_KWLST
                    TRUNCATE TABLE #KEYWORDV
                    TRUNCATE TABLE #KEYWORD
                    TRUNCATE TABLE #KEYWORD1
                    TRUNCATE TABLE #KEYWORD2
                    TRUNCATE TABLE #KEYWORD3
                    TRUNCATE TABLE #KEYWORD4
                    TRUNCATE TABLE #BASICDOC
                    TRUNCATE TABLE #ORIGINAL_FILENAME

	------------------------------------------------------------------------------
	--get distinct document base document ids from the batch
	--only process folder of the base documents
	-- Update to add condition, to make sure the document exist - 12/06/2019 (dd/mm/yyyy)
	IF ( @V_IS_READ_SINGLE_DOCUMENT = 0 AND @V_ACTION = 'PROCESSOR' )
		BEGIN
			INSERT INTO #TDOCID
			SELECT DISTINCT BASE FROM BASE_VERV WITH (READUNCOMMITTED), ECM_DOCIDX WHERE BASE_VERV.VERSION = ECM_DOCIDX.DOCUMENT_ID AND ECM_DOCIDX.SESSION_ID = @SESSION_ID AND VERSION >= @batch_start AND VERSION <= @batch_end
		END
	ELSE
		BEGIN
			INSERT INTO #TDOCID
			SELECT DISTINCT BASE FROM BASE_VERV WITH (READUNCOMMITTED) WHERE VERSION >= @batch_start AND VERSION <= @batch_end
		END

	IF @V_IS_READ_SINGLE_DOCUMENT = 0
		BEGIN
			IF ( @V_ACTION = 'PROCESSOR' )
				INSERT INTO #ALLVERSN
				SELECT V2.BMG7NA masterDocumentId,
					   V2.BMASVN versionId,
					   V2.BMTENB versionNumber,
					   D2.APBCST referencingStatus
				  FROM ARBMREP V1 WITH (READUNCOMMITTED),
					   ARBMREP V2 WITH (READUNCOMMITTED),
					   ARAPREP D1 WITH (READUNCOMMITTED),
					   ARAPREP D2 WITH (READUNCOMMITTED),
					   ECM_DOCIDX
				 WHERE V1.BMASVN = D1.APASVN AND
					   D1.APBBST = 'V' AND
					   V1.BMG7NA = V2.BMG7NA AND
					   V2.BMASVN = D2.APASVN AND
					   ECM_DOCIDX.DOCUMENT_ID = D1.APASVN AND
					   ECM_DOCIDX.DOCUMENT_ID >= @batch_start AND
					   ECM_DOCIDX.DOCUMENT_ID <= @batch_end
			ELSE -- Global indexation
				INSERT INTO #ALLVERSN
				SELECT V2.BMG7NA masterDocumentId,
					   V2.BMASVN versionId,
					   V2.BMTENB versionNumber,
					   D2.APBCST referencingStatus
				  FROM ARBMREP V1 WITH (READUNCOMMITTED),
					   ARBMREP V2 WITH (READUNCOMMITTED),
					   ARAPREP D1 WITH (READUNCOMMITTED),
					   ARAPREP D2 WITH (READUNCOMMITTED)
				 WHERE V1.BMASVN = D1.APASVN AND
					   D1.APBBST = 'V' AND
					   V1.BMG7NA = V2.BMG7NA AND
					   V2.BMASVN = D2.APASVN AND
					   D1.APASVN >= @batch_start AND
					   D1.APASVN <= @batch_end
		END
	ELSE
		INSERT INTO #ALLVERSN
		SELECT V2.BMG7NA masterDocumentId,
			   V2.BMASVN versionId,
			   V2.BMTENB versionNumber,
			   D2.APBCST referencingStatus
		  FROM ARBMREP V1 WITH (READUNCOMMITTED),
			   ARBMREP V2 WITH (READUNCOMMITTED),
			   ARAPREP D1 WITH (READUNCOMMITTED),
			   ARAPREP D2 WITH (READUNCOMMITTED)
		 WHERE V1.BMASVN = D1.APASVN AND
			   D1.APBBST = 'V' AND
			   V1.BMG7NA = V2.BMG7NA AND
			   V2.BMASVN = D2.APASVN AND
			   D1.APASVN = @batch_start

	SELECT DISTINCT
		   v1.masterDocumentId,
		   v1.versionId
	  INTO #VARELNTVNV
	  FROM #ALLVERSN v1
	 WHERE v1.versionNumber = (SELECT MAX(v2.versionNumber) FROM #ALLVERSN v2 WHERE v1.masterDocumentId = v2.masterDocumentId AND v2.referencingStatus = '1')

	SELECT masterDocumentId INTO #MVARELNTVV FROM #VARELNTVNV GROUP BY masterDocumentId

	SELECT DISTINCT
		   v1.versionId
	  INTO #LVRELNTVNV
	  FROM #ALLVERSN v1
	  LEFT JOIN #MVARELNTVV MASTER ON v1.masterDocumentId = MASTER.masterDocumentId
	 WHERE MASTER.masterDocumentId IS NULL AND v1.versionNumber = (SELECT MAX(v2.versionNumber) FROM #ALLVERSN v2 WHERE v1.masterDocumentId = v2.masterDocumentId)

	SELECT DISTINCT versionId document_id INTO #RELNTVERSV FROM #VARELNTVNV UNION ALL SELECT versionId document_id FROM #LVRELNTVNV

	CREATE NONCLUSTERED INDEX #RELNTVERSV_IX1 ON #RELNTVERSV ( document_id ASC )

	------------------------------------------------------------------------------
	--get list of parent folders and insert them into #TPARFLD

	--get first parent of folders which are in folder entry.
	--ARARREP: FOLDER ENTRY
	--AREZCPP: FOLDER
	--ARAJREP: DEPARTMENT
	--ARAOREP: DATABASE

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '3'

	INSERT INTO #TPARFLD_HELPER
	SELECT DISTINCT ARAPCD CHILD_DB,
		   REPLACE(ARAETX, '"', '&#34;') CHILD_FLD,
		   T2.EZBUNU,
		   GHAWCD PARENT_DB,
		   REPLACE(GHIUNA, '"', '&#34;') PARENT_FLD,
		   T1.EZBUNU, T1.EZAWCD, T1.DD46A, T1.EZF8TX,
		   dbo.escapeSpecialCharacters(REPLACE(CASE WHEN left(ARAETX, 3) = TFLDTYP_HELPER.typeID THEN substring(ARAETX,4,40) ELSE ARAETX END, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.EZB7NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.EZB8NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.EZB9NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.EZH0TX, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.DD8gaA, '"', '&#34;')),
		   T1.EZCXDT,
		   dbo.escapeSpecialCharacters(REPLACE(T1.EZCANA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.DD8gbA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(T1.DD8gcA, '"', '&#34;'))
	  FROM ARARREP WITH (READUNCOMMITTED),
		   ARGHREP WITH (READUNCOMMITTED)
		   LEFT JOIN AREZCPP T1 WITH (READUNCOMMITTED) ON T1.EZAWCD = ARGHREP.GHAWCD AND T1.EZF8TX = ARGHREP.GHIUNA
		   LEFT JOIN AREZCPP T2 WITH (READUNCOMMITTED) ON T2.EZAWCD = ARGHREP.GHQ1CD AND T2.EZF8TX = ARGHREP.GHIWNA
		   LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER ON
								DATALENGTH(T1.EZF8TX) >= 3 AND
								left(T1.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								GHAWCD = TFLDTYP_HELPER.base,
		   #TDOCID
	 WHERE ARARREP.ARAPCD = ARGHREP.GHQ1CD AND
		   ARARREP.ARAETX = ARGHREP.GHIWNA AND
		   ARARREP.ARASVN = #TDOCID.document_id

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '3a'

	INSERT INTO #TFOLDER_DESCRIPTION
	SELECT 	DISTINCT
			EZBUNU,
			CASE
				WHEN
					left(parentfld, 3) = TFLDTYP_HELPER.typeID
				THEN
					substring(dbo.escapeSpecialCharacters(parentfld),4,40)
				ELSE
					dbo.escapeSpecialCharacters(parentfld)
			END,
			CASE
				WHEN
					left(parentfld, 3) = TFLDTYP_HELPER.typeID
				THEN
					TFLDTYP_HELPER.typeID
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					left(EZB7NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6)
				ELSE
					CASE WHEN left(EZB7NA, 5) <> '!USER' THEN EZB7NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					left(EZB8NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6)
				ELSE
					CASE WHEN left(EZB8NA, 5) <> '!USER' THEN EZB8NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					left(EZB9NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6)
				ELSE
					CASE WHEN left(EZB9NA, 5) <> '!USER' THEN EZB9NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZCANA) >= 6 and left(EZCANA, 6) in (TFLDTYP_HELPER.prefixDs4,TFLDTYP_HELPER2.prefixDs4)
				THEN
					left(EZCANA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZCANA) >= 6 and left(EZCANA, 6) in (TFLDTYP_HELPER.prefixDs4,TFLDTYP_HELPER2.prefixDs4)
				THEN
					RIGHT(EZCANA, DATALENGTH(EZCANA)- 6)
				ELSE
					CASE WHEN left(EZCANA, 5) <> '!USER' THEN EZCANA ELSE '' END
			END,
			'' -- DESCRIPTION
	FROM #TPARFLD_HELPER
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER ON
								DATALENGTH(#TPARFLD_HELPER.EZF8TX) >= 3 AND
								left(#TPARFLD_HELPER.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER.base
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER2	ON
										TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(#TPARFLD_HELPER.EZB7NA) >= 6 AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 1) = '!' AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '3b'

	IF ( @IS_PAC_MODE = 0 )
		UPDATE #TFOLDER_DESCRIPTION
		   SET description = RTRIM(description1) +
							 CASE WHEN LEN(description1) > 0 AND LEN(description2) > 0 THEN ' - ' + description2 ELSE description2 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0) AND LEN(description3) > 0 THEN ' - ' + description3 ELSE description3 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0 OR LEN(description3) > 0) AND LEN(description4) > 0 THEN ' - ' + description4 ELSE description4 END
	ELSE
		UPDATE #TFOLDER_DESCRIPTION
		   SET description = RTRIM(description1) +
							 CASE WHEN LEN(description1) > 0 AND LEN(description2) > 0 THEN ' - ' + description2 ELSE description2 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0) AND LEN(description3) > 0 THEN ' - ' + description3 ELSE description3 END

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '3c'

	INSERT INTO #TPARFLD_HELPER1
		SELECT DISTINCT #TPARFLD_HELPER.databaseId, #TPARFLD_HELPER.businessId, #TPARFLD_HELPER.folderId, parentdb, #TPARFLD_HELPER.parentfld, #TFOLDER_DESCRIPTION.parentfld,
			'{' +
			CASE
				WHEN @HAS_FOLDER_TYPE = 0
				THEN '\"type_fr\":\"\",\"type_de\":\"\",\"type_it\":\"\",\"type_en\":\"\",'
				ELSE
					CASE
						WHEN
							TFLDTYP_HELPER0.typeNme IS NOT NULL AND TFLDTYP_HELPER0.type IS NOT NULL
						THEN
							'\"typeId\":\"'+TFLDTYP_HELPER0.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER0.typeID+'\",' +
							CASE
								WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
									THEN '\"type_fr\":\"' + TFLDTYP_HELPER0.type + '\",\"type_de\":\"' + TFLDTYP_HELPER0.type + '\",\"type_it\":\"' + TFLDTYP_HELPER0.type + '\",\"type_en\":\"' + TFLDTYP_HELPER0.type + '\"'
								ELSE folderType_param.formatted_json
							END + ','

						WHEN @IS_PAC_MODE = 1
						THEN
							CASE
								WHEN
									TFLDTYP_HELPER.typeNme IS NOT NULL AND TFLDTYP_HELPER.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER.typeID+'\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER.type + '\",\"type_de\":\"' + TFLDTYP_HELPER.type + '\",\"type_it\":\"' + TFLDTYP_HELPER.type + '\",\"type_en\":\"' + TFLDTYP_HELPER.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
								WHEN
									TFLDTYP_HELPER2.typeNme IS NOT NULL AND TFLDTYP_HELPER2.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER2.typeNme+'\",\"pacTypeId\":\"\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER2.type + '\",\"type_de\":\"' + TFLDTYP_HELPER2.type + '\",\"type_it\":\"' + TFLDTYP_HELPER2.type + '\",\"type_en\":\"' + TFLDTYP_HELPER2.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
								WHEN
									TFLDTYP_HELPER3.typeNme IS NOT NULL AND TFLDTYP_HELPER3.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER3.typeNme+'\",\"pacTypeId\":\"\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER3.type + '\",\"type_de\":\"' + TFLDTYP_HELPER3.type + '\",\"type_it\":\"' + TFLDTYP_HELPER3.type + '\",\"type_en\":\"' + TFLDTYP_HELPER3.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
							ELSE
								'\"typeId\":\"\",\"pacTypeId\":\"\",\"type_fr\":\"Facture\",\"type_de\":\"Facture\",\"type_it\":\"Facture\",\"type_en\":\"Facture\",'
							END
						ELSE
							'\"type_fr\":\"\",\"type_de\":\"\",\"type_it\":\"\",\"type_en\":\"\",'
					END
				END
			+ '\"technicalId\":\"'+ CASE WHEN EZBUNU > 0 THEN UPPER(@ENVIRONMENT) + '-' + convert(varchar,EZBUNU) ELSE '' END +	'\",\"id\":\"' + convert(varchar,EZBUNU) + '\",\"databaseId\":\"' + parentdb +
			'\",\"businessId\":\"' + #TFOLDER_DESCRIPTION.parentfld
			+ '\",' +
			CASE
				WHEN database_param.formatted_json is null or database_param.formatted_json = '' THEN
					CASE
						WHEN ECM_PACREF_DB.pacDesc IS NULL OR ECM_PACREF_DB.pacDesc = '' THEN
							'\"databaseDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\",\"databaseDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) +
							'\",\"databaseDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\",\"databaseDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\"'
						ELSE
							'\"databaseDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\",\"databaseDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) +
							'\",\"databaseDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\",\"databaseDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\"'
						END
				ELSE
					database_param.formatted_json
			END +
			',\"description_fr\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_fr
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_de\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_de
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_it\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_it
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_en\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_en
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
            + '\",\"description1\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description1)
			+ '\",\"description2\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description2)
			+ '\",\"description3\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description3)
			+ '\",\"description4\":\"' + CASE WHEN ( @IS_PAC_MODE = 0 ) THEN RTRIM(#TFOLDER_DESCRIPTION.description4) ELSE '' END
			+ '\",\"descriptionIdentifier_fr\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_fr
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.parentfld) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + #TFOLDER_DESCRIPTION.parentfld +
			'\",\"descriptionIdentifier_de\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_de
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.parentfld) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + #TFOLDER_DESCRIPTION.parentfld +
			'\",\"descriptionIdentifier_it\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_it
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.parentfld) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + #TFOLDER_DESCRIPTION.parentfld
			+ '\",\"descriptionIdentifier_en\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_en
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.parentfld) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + #TFOLDER_DESCRIPTION.parentfld +
			'\",\"searchText\":\"' +
			CASE WHEN EZH0TX IS NOT NULL AND DATALENGTH(EZH0TX) >= 3 AND left(EZH0TX, 3) = TFLDTYP_HELPER.typeID
			THEN RIGHT(EZH0TX, DATALENGTH(EZH0TX)- 3) + ' '
			ELSE
			CASE WHEN EZH0TX is null OR EZH0TX='' THEN '' ELSE EZH0TX + ' ' END
			END
			+
			CASE WHEN DD8gaA is null OR DD8gaA='' THEN '' ELSE DD8gaA + ' ' END +
			CASE WHEN DD8gbA is null OR DD8gbA='' THEN '' ELSE DD8gbA + ' ' END +
			CASE WHEN DD8gcA is null OR DD8gcA='' THEN '' ELSE DD8gcA END +
			'\",\"endDate\":\"' + CASE WHEN conservationAttribute.endDate IS NULL
                THEN ''
                ELSE format((CONVERT(datetime, RTRIM(conservationAttribute.endDate)) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z'
                END
			+
			'\"' + dbo.convertDateField('openingDate',EZCXDT) + '}',
			1,
			CONVERT(VARCHAR(100), EZBUNU)
	FROM #TFOLDER_DESCRIPTION,
		 #TPARFLD_HELPER
	LEFT JOIN ECM_FCONS conservationAttribute WITH (READUNCOMMITTED) ON EZBUNU = conservationAttribute.folderId
    LEFT JOIN ECM_FADDL additionalAttribute WITH (READUNCOMMITTED) ON EZBUNU = additionalAttribute.folderId
	LEFT JOIN #ECM_PACREF ON #ECM_PACREF.BASE = #TPARFLD_HELPER.EZAWCD AND
							 ( #ECM_PACREF.depId = #TPARFLD_HELPER.DD46A OR
							   ( #ECM_PACREF.depId is null AND #TPARFLD_HELPER.DD46A = '' ) OR
							   ( #ECM_PACREF.depId = '' AND  #TPARFLD_HELPER.DD46A is null ) )
	LEFT JOIN #ECM_PACREF ECM_PACREF_DB ON ECM_PACREF_DB.BASE = #TPARFLD_HELPER.EZAWCD AND
							 ( ECM_PACREF_DB.depId = #TPARFLD_HELPER.DD46A OR
							   ( ECM_PACREF_DB.depId is null AND #TPARFLD_HELPER.DD46A = '' ) OR
							   ( ECM_PACREF_DB.depId = '' AND  #TPARFLD_HELPER.DD46A is null ) )
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER0  ON additionalAttribute.folderType = TFLDTYP_HELPER0.typeNme AND
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER0.base AND
										additionalAttribute.folderType IS NOT NULL AND additionalAttribute.folderType <> ''
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER  ON
								DATALENGTH(#TPARFLD_HELPER.EZF8TX) >= 3 AND
								left(#TPARFLD_HELPER.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER.base
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER2  ON
										TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(#TPARFLD_HELPER.EZB7NA) >= 6 AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 1) = '!' AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER3	ON
										TFLDTYP_HELPER.base IS NULL AND 	-- NOT FOUND BY TYPEID
										TFLDTYP_HELPER2.base IS NULL AND 	-- NOT FOUND BY PREFIXDS1
										DATALENGTH(#TPARFLD_HELPER.EZB7NA) >= 1 AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 1) != '!' AND
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER3.base AND
										TFLDTYP_HELPER3.typeID =''
	LEFT JOIN ARAOREP  WITH (READUNCOMMITTED) ON #TPARFLD_HELPER.EZAWCD = ARAOREP.AOAWCD
	LEFT JOIN ARAJREP  WITH (READUNCOMMITTED) ON #TPARFLD_HELPER.DD46A = ARAJREP.AJAOCD
	LEFT JOIN #ECM_PARAM database_param ON parentdb = database_param.param_id and database_param.param_type = 'DATABASE'
	LEFT JOIN #ECM_PARAM folderType_param ON folderType_param.param_id = ISNULL(TFLDTYP_HELPER0.typeNme, CASE WHEN @IS_PAC_MODE = 1 THEN ISNULL(TFLDTYP_HELPER.typeNme,ISNULL(TFLDTYP_HELPER2.typeNme,ISNULL(TFLDTYP_HELPER3.typeNme,'Facture'))) ELSE '' END) and folderType_param.param_type = 'FOLDERTYPE'
	WHERE #TPARFLD_HELPER.EZBUNU = #TFOLDER_DESCRIPTION.folderid

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4'

	-- get all parent folders
	DECLARE @instancesToFetch 	int
	SELECT @instancesToFetch = 1

	WHILE ( @instancesToFetch = 1 )
		BEGIN

	IF EXISTS(SELECT numberofparent FROM #TPARFLD_HELPER1 WHERE numberofparent = 1)
		BEGIN

			if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4a'

	INSERT INTO #TPARFLD_HELPER
	SELECT DISTINCT databaseId CHILD_DB,
		   businessId CHILD_FLD,
		   folderId,
		   GHAWCD PARENT_DB,
		   REPLACE(GHIUNA, '"', '&#34;') PARENT_FLD,
		   EZBUNU, EZAWCD, DD46A, EZF8TX,
		   dbo.escapeSpecialCharacters(REPLACE((CASE WHEN left(EZF8TX, 3) = TFLDTYP_HELPER.typeID THEN substring(EZF8TX,4,40) ELSE EZF8TX END), '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZB7NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZB8NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZB9NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZH0TX, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(DD8gaA, '"', '&#34;')),
		   EZCXDT,
		   dbo.escapeSpecialCharacters(REPLACE(EZCANA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(DD8gbA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(DD8gcA, '"', '&#34;'))
	  FROM #TPARFLD_HELPER1,
		   AREZCPP WITH (READUNCOMMITTED)
		   LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER ON
								DATALENGTH(EZF8TX) >= 3 AND
								left(EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								EZF8TX = TFLDTYP_HELPER.base,
		   ARGHREP WITH (READUNCOMMITTED)
		   WHERE AREZCPP.EZAWCD = GHAWCD AND AREZCPP.EZF8TX = GHIUNA AND parentdb = GHQ1CD AND parentfld = GHIWNA AND numberofparent = 1

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4b'

	DELETE #TPARFLD_HELPER
	  FROM #TPARFLD_HELPER1
	 WHERE #TPARFLD_HELPER.parentdb = #TPARFLD_HELPER1.parentdb AND
		   #TPARFLD_HELPER.databaseId = #TPARFLD_HELPER1.databaseId AND
		   #TPARFLD_HELPER.parentfld = #TPARFLD_HELPER1.parentfld AND
		   #TPARFLD_HELPER.businessId = #TPARFLD_HELPER1.businessId

	UPDATE  #TPARFLD_HELPER1 SET numberofparent = 0 WHERE numberofparent = 1

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4c'

	INSERT INTO #TFOLDER_DESCRIPTION
	SELECT 	DISTINCT
			EZBUNU,
			CASE
				WHEN
					left(parentfld, 3) = TFLDTYP_HELPER.typeID
				THEN
					substring(dbo.escapeSpecialCharacters(parentfld),4,40)
				ELSE
					dbo.escapeSpecialCharacters(parentfld)
			END,
			CASE
				WHEN
					left(parentfld, 3) = TFLDTYP_HELPER.typeID
				THEN
					TFLDTYP_HELPER.typeID
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					left(EZB7NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6)
				ELSE
					CASE WHEN left(EZB7NA, 5) <> '!USER' THEN EZB7NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					left(EZB8NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6)
				ELSE
					CASE WHEN left(EZB8NA, 5) <> '!USER' THEN EZB8NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					left(EZB9NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6)
				ELSE
					CASE WHEN left(EZB9NA, 5) <> '!USER' THEN EZB9NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZCANA) >= 6 and left(EZCANA, 6) in (TFLDTYP_HELPER.prefixDs4,TFLDTYP_HELPER2.prefixDs4)
				THEN
					left(EZCANA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZCANA) >= 6 and left(EZCANA, 6) in (TFLDTYP_HELPER.prefixDs4,TFLDTYP_HELPER2.prefixDs4)
				THEN
					RIGHT(EZCANA, DATALENGTH(EZCANA)- 6)
				ELSE
					CASE WHEN left(EZCANA, 5) <> '!USER' THEN EZCANA ELSE '' END
			END,
			'' -- DESCRIPTION
	FROM #TPARFLD_HELPER
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER ON
								DATALENGTH(#TPARFLD_HELPER.EZF8TX) >= 3 AND
								left(#TPARFLD_HELPER.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER.base
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER2	ON
										TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(#TPARFLD_HELPER.EZB7NA) >= 6 AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 1) = '!' AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
	WHERE NOT EXISTS (SELECT * FROM #TFOLDER_DESCRIPTION WHERE #TFOLDER_DESCRIPTION.folderid = #TPARFLD_HELPER.EZBUNU)

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4d'

	IF ( @IS_PAC_MODE = 0 )
		UPDATE #TFOLDER_DESCRIPTION
		   SET description = RTRIM(description1) +
							 CASE WHEN LEN(description1) > 0 AND LEN(description2) > 0 THEN ' - ' + description2 ELSE description2 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0) AND LEN(description3) > 0 THEN ' - ' + description3 ELSE description3 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0 OR LEN(description3) > 0) AND LEN(description4) > 0 THEN ' - ' + description4 ELSE description4 END
		 WHERE description = ''
	ELSE
		UPDATE #TFOLDER_DESCRIPTION
		   SET description = RTRIM(description1) +
							 CASE WHEN LEN(description1) > 0 AND LEN(description2) > 0 THEN ' - ' + description2 ELSE description2 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0) AND LEN(description3) > 0 THEN ' - ' + description3 ELSE description3 END
		 WHERE description = ''

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4e'

	INSERT INTO #TPARFLD_HELPER1
		SELECT DISTINCT #TPARFLD_HELPER.databaseId, #TPARFLD_HELPER.businessId, #TPARFLD_HELPER.folderId, parentdb, #TPARFLD_HELPER.parentfld, #TFOLDER_DESCRIPTION.parentfld,
			'{' +
			CASE
				WHEN @HAS_FOLDER_TYPE = 0
				THEN '\"type_fr\":\"\",\"type_de\":\"\",\"type_it\":\"\",\"type_en\":\"\",'
				ELSE
					CASE
						WHEN
							TFLDTYP_HELPER0.typeNme IS NOT NULL AND TFLDTYP_HELPER0.type IS NOT NULL
						THEN
							'\"typeId\":\"'+TFLDTYP_HELPER0.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER0.typeID+'\",' +
							CASE
								WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
									THEN '\"type_fr\":\"' + TFLDTYP_HELPER0.type + '\",\"type_de\":\"' + TFLDTYP_HELPER0.type + '\",\"type_it\":\"' + TFLDTYP_HELPER0.type + '\",\"type_en\":\"' + TFLDTYP_HELPER0.type + '\"'
								ELSE folderType_param.formatted_json
							END + ','

						WHEN @IS_PAC_MODE = 1
						THEN
							CASE
								WHEN
									TFLDTYP_HELPER.typeNme IS NOT NULL AND TFLDTYP_HELPER.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER.typeID+'\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER.type + '\",\"type_de\":\"' + TFLDTYP_HELPER.type + '\",\"type_it\":\"' + TFLDTYP_HELPER.type + '\",\"type_en\":\"' + TFLDTYP_HELPER.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
								WHEN
									TFLDTYP_HELPER2.typeNme IS NOT NULL AND TFLDTYP_HELPER2.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER2.typeNme+'\",\"pacTypeId\":\"\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER2.type + '\",\"type_de\":\"' + TFLDTYP_HELPER2.type + '\",\"type_it\":\"' + TFLDTYP_HELPER2.type + '\",\"type_en\":\"' + TFLDTYP_HELPER2.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
								WHEN
									TFLDTYP_HELPER3.typeNme IS NOT NULL AND TFLDTYP_HELPER3.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER3.typeNme+'\",\"pacTypeId\":\"\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER3.type + '\",\"type_de\":\"' + TFLDTYP_HELPER3.type + '\",\"type_it\":\"' + TFLDTYP_HELPER3.type + '\",\"type_en\":\"' + TFLDTYP_HELPER3.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
							ELSE
								'\"typeId\":\"\",\"pacTypeId\":\"\",\"type_fr\":\"Facture\",\"type_de\":\"Facture\",\"type_it\":\"Facture\",\"type_en\":\"Facture\",'
							END
						ELSE
							'\"type_fr\":\"\",\"type_de\":\"\",\"type_it\":\"\",\"type_en\":\"\",'
					END
				END
			+ '\"technicalId\":\"'+ CASE WHEN EZBUNU > 0 THEN UPPER(@ENVIRONMENT) + '-' + convert(varchar,EZBUNU) ELSE '' END + '\",\"id\":\"' + convert(varchar,EZBUNU) + '\",\"databaseId\":\"' + parentdb +
			'\",\"businessId\":\"' + #TFOLDER_DESCRIPTION.parentfld
			+ '\",' +
			CASE
				WHEN database_param.formatted_json is null or database_param.formatted_json = '' THEN
					CASE
						WHEN ECM_PACREF_DB.pacDesc IS NULL OR ECM_PACREF_DB.pacDesc = '' THEN
							'\"databaseDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\",\"databaseDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) +
							'\",\"databaseDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\",\"databaseDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\"'
						ELSE
							'\"databaseDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\",\"databaseDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) +
							'\",\"databaseDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\",\"databaseDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\"'
						END
				ELSE
					database_param.formatted_json
			END +
			',\"description_fr\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_fr
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_de\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_de
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_it\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_it
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_en\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_en
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
            + '\",\"description1\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description1)
			+ '\",\"description2\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description2)
			+ '\",\"description3\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description3)
			+ '\",\"description4\":\"' + CASE WHEN ( @IS_PAC_MODE = 0 ) THEN RTRIM(#TFOLDER_DESCRIPTION.description4) ELSE '' END
			+ '\",\"descriptionIdentifier_fr\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_fr
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"descriptionIdentifier_de\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_de
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"descriptionIdentifier_it\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_it
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			+ '\",\"descriptionIdentifier_en\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_en
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"searchText\":\"' +
			CASE WHEN EZH0TX IS NOT NULL AND DATALENGTH(EZH0TX) >= 3 AND left(EZH0TX, 3) = TFLDTYP_HELPER.typeID
			THEN RIGHT(EZH0TX, DATALENGTH(EZH0TX)- 3) + ' '
			ELSE
			CASE WHEN EZH0TX is null OR EZH0TX='' THEN '' ELSE EZH0TX + ' ' END
			END
			+
			CASE WHEN DD8gaA is null OR DD8gaA='' THEN '' ELSE DD8gaA + ' ' END +
			CASE WHEN DD8gbA is null OR DD8gbA='' THEN '' ELSE DD8gbA + ' ' END +
			CASE WHEN DD8gcA is null OR DD8gcA='' THEN '' ELSE DD8gcA END +
			'\",\"endDate\":\"' + CASE WHEN conservationAttribute.endDate IS NULL
									THEN ''
                                    ELSE format((CONVERT(datetime, RTRIM(conservationAttribute.endDate)) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z'
									END
			+
			'\"' + dbo.convertDateField('openingDate',EZCXDT) + '}',
			1,
			EZBUNU
	FROM #TFOLDER_DESCRIPTION,
		 #TPARFLD_HELPER
	LEFT JOIN ECM_FCONS conservationAttribute WITH (READUNCOMMITTED) ON EZBUNU = conservationAttribute.folderId
    LEFT JOIN ECM_FADDL additionalAttribute WITH (READUNCOMMITTED) ON EZBUNU = additionalAttribute.folderId
	LEFT JOIN #ECM_PACREF ON #ECM_PACREF.BASE = #TPARFLD_HELPER.EZAWCD AND
							 ( #ECM_PACREF.depId = #TPARFLD_HELPER.DD46A OR
							   ( #ECM_PACREF.depId is null AND #TPARFLD_HELPER.DD46A = '' ) OR
							   ( #ECM_PACREF.depId = '' AND  #TPARFLD_HELPER.DD46A is null ) )
	LEFT JOIN #ECM_PACREF ECM_PACREF_DB ON ECM_PACREF_DB.BASE = #TPARFLD_HELPER.EZAWCD AND
							 ( ECM_PACREF_DB.depId = #TPARFLD_HELPER.DD46A OR
							   ( ECM_PACREF_DB.depId is null AND #TPARFLD_HELPER.DD46A = '' ) OR
							   ( ECM_PACREF_DB.depId = '' AND  #TPARFLD_HELPER.DD46A is null ) )
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER0  ON additionalAttribute.folderType = TFLDTYP_HELPER0.typeNme AND
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER0.base AND
										additionalAttribute.folderType IS NOT NULL AND additionalAttribute.folderType <> ''
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER  ON
								DATALENGTH(#TPARFLD_HELPER.EZF8TX) >= 3 AND
								left(#TPARFLD_HELPER.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER.base
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER2  ON
										TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(#TPARFLD_HELPER.EZB7NA) >= 6 AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 1) = '!' AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER3	ON
										TFLDTYP_HELPER.base IS NULL AND 	-- NOT FOUND BY TYPEID
										TFLDTYP_HELPER2.base IS NULL AND 	-- NOT FOUND BY PREFIXDS1
										DATALENGTH(#TPARFLD_HELPER.EZB7NA) >= 1 AND
										LEFT(#TPARFLD_HELPER.EZB7NA, 1) != '!' AND
										#TPARFLD_HELPER.EZAWCD = TFLDTYP_HELPER3.base AND
										TFLDTYP_HELPER3.typeID =''
	LEFT JOIN ARAOREP  WITH (READUNCOMMITTED) ON #TPARFLD_HELPER.EZAWCD = ARAOREP.AOAWCD
	LEFT JOIN ARAJREP  WITH (READUNCOMMITTED) ON #TPARFLD_HELPER.DD46A = ARAJREP.AJAOCD
	LEFT JOIN #ECM_PARAM database_param ON parentdb = database_param.param_id and database_param.param_type = 'DATABASE'
	LEFT JOIN #ECM_PARAM folderType_param ON folderType_param.param_id = ISNULL(TFLDTYP_HELPER0.typeNme,CASE WHEN @IS_PAC_MODE = 1 THEN ISNULL(TFLDTYP_HELPER.typeNme,ISNULL(TFLDTYP_HELPER2.typeNme,ISNULL(TFLDTYP_HELPER3.typeNme,'Facture'))) ELSE '' END) and folderType_param.param_type = 'FOLDERTYPE'
	WHERE #TPARFLD_HELPER.EZBUNU = #TFOLDER_DESCRIPTION.folderid

			UPDATE #TPARFLD_HELPER1 SET numberofparent = 0 WHERE numberofparent = 1 AND parentdb = databaseId AND parentfld = businessId

		   SELECT @instancesToFetch = 1
		END
		ELSE
			SELECT @instancesToFetch = 0
	END

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '5'

	TRUNCATE TABLE #TPARFLD_HELPER

	INSERT INTO #TPARFLD
		select
			databaseId,
			businessId,
			STRING_AGG( parentJson, ',' ),
			STRING_AGG( '"#PARENTFOLDER#' + parentdb + '#' + parentfld_pac + '"', ',' )
		from #TPARFLD_HELPER1 t1
	   group by databaseId, businessId

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '6'

	------------------------------------------------------------------------------
	--get list of folders and insert into folders temp table

	INSERT INTO #TFOLDER_TEMP
	SELECT ARASVN, ARAQCD, ARAPCD, CASE WHEN EZBUNU IS NULL THEN 0 ELSE EZBUNU END, APAOCD, EZAWCD, DD46A, EZF8TX,
		   dbo.escapeSpecialCharacters(REPLACE((CASE WHEN left(ARAETX, 3) = TFLDTYP_HELPER.typeID THEN substring(ARAETX,4,40) ELSE ARAETX END), '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE((CASE WHEN left(ARAETX, 3) = TFLDTYP_HELPER.typeID THEN TFLDTYP_HELPER.typeID ELSE '' END), '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZB7NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZB8NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZB9NA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(EZH0TX, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(DD8gaA, '"', '&#34;')),
		   EZCXDT,
		   dbo.escapeSpecialCharacters(REPLACE(EZCANA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(DD8gbA, '"', '&#34;')),
		   dbo.escapeSpecialCharacters(REPLACE(DD8gcA, '"', '&#34;'))
	  FROM ARARREP WITH (READUNCOMMITTED)
		   LEFT JOIN AREZCPP WITH (READUNCOMMITTED) ON AREZCPP.EZAWCD = ARARREP.ARAPCD AND AREZCPP.EZF8TX = ARARREP.ARAETX
		   LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER ON
								DATALENGTH(EZF8TX) >= 3 AND
								left(EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								ARAPCD = TFLDTYP_HELPER.base,
		   ARAPREP WITH (READUNCOMMITTED),
		   #TDOCID
	 WHERE ARAPREP.APASVN = ARARREP.ARASVN AND ARAPREP.APASVN = #TDOCID.document_id -- AND OP8WT.OP5oA = ARARREP.ARASVN

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '6a'

	INSERT INTO #TFOLDER_DESCRIPTION
	SELECT 	DISTINCT
			EZBUNU,
			ARAETX, --parentfld
			folderType,
			CASE
				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					left(EZB7NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6)
				ELSE
					CASE WHEN left(EZB7NA, 5) <> '!USER' THEN EZB7NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					left(EZB8NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6)
				ELSE
					CASE WHEN left(EZB8NA, 5) <> '!USER' THEN EZB8NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					left(EZB9NA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6)
				ELSE
					CASE WHEN left(EZB9NA, 5) <> '!USER' THEN EZB9NA ELSE '' END
			END,
			CASE
				WHEN DATALENGTH(EZCANA) >= 6 and left(EZCANA, 6) in (TFLDTYP_HELPER.prefixDs4,TFLDTYP_HELPER2.prefixDs4)
				THEN
					left(EZCANA, 6)
				ELSE
					''
			END,
			CASE
				WHEN DATALENGTH(EZCANA) >= 6 and left(EZCANA, 6) in (TFLDTYP_HELPER.prefixDs4,TFLDTYP_HELPER2.prefixDs4)
				THEN
					RIGHT(EZCANA, DATALENGTH(EZCANA)- 6)
				ELSE
					CASE WHEN left(EZCANA, 5) <> '!USER' THEN EZCANA ELSE '' END
			END,
			'' -- DESCRIPTION
	FROM #TFOLDER_TEMP
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER ON
								DATALENGTH(#TFOLDER_TEMP.EZF8TX) >= 3 AND
								left(#TFOLDER_TEMP.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								#TFOLDER_TEMP.ARAPCD = TFLDTYP_HELPER.base
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER2	ON
										TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
										#TFOLDER_TEMP.ARAPCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(#TFOLDER_TEMP.EZB7NA) >= 6 AND
										LEFT(#TFOLDER_TEMP.EZB7NA, 1) = '!' AND
										LEFT(#TFOLDER_TEMP.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
	WHERE NOT EXISTS (SELECT * FROM #TFOLDER_DESCRIPTION WHERE #TFOLDER_DESCRIPTION.folderid = #TFOLDER_TEMP.EZBUNU)

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '6b'

	IF ( @IS_PAC_MODE = 0 )
		UPDATE #TFOLDER_DESCRIPTION
		   SET description = RTRIM(description1) +
							 CASE WHEN LEN(description1) > 0 AND LEN(description2) > 0 THEN ' - ' + description2 ELSE description2 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0) AND LEN(description3) > 0 THEN ' - ' + description3 ELSE description3 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0 OR LEN(description3) > 0) AND LEN(description4) > 0 THEN ' - ' + description4 ELSE description4 END
		 WHERE description = ''
	ELSE
		UPDATE #TFOLDER_DESCRIPTION
		   SET description = RTRIM(description1) +
							 CASE WHEN LEN(description1) > 0 AND LEN(description2) > 0 THEN ' - ' + description2 ELSE description2 END +
							 CASE WHEN (LEN(description1) > 0 OR LEN(description2) > 0) AND LEN(description3) > 0 THEN ' - ' + description3 ELSE description3 END
		 WHERE description = ''

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '6c'

	INSERT INTO #TFOLDER_HELPER
	SELECT	#TFOLDER_TEMP.ARASVN document_id,
			'"#FOLDER#' + RTRIM(ARAPCD) + '#' +
			ARAETX
			+ '"' +
			CASE WHEN parent_folder_temp.objectKeyValuesJson IS NULL THEN '' ELSE ',' + parent_folder_temp.objectKeyValuesJson END
			objectKeyValuesJson,
			'{' +
			CASE
				WHEN @HAS_FOLDER_TYPE = 0
				THEN '\"type_fr\":\"\",\"type_de\":\"\",\"type_it\":\"\",\"type_en\":\"\",'
				ELSE
					CASE
						WHEN
							TFLDTYP_HELPER0.typeNme IS NOT NULL AND TFLDTYP_HELPER0.type IS NOT NULL
						THEN
							'\"typeId\":\"'+TFLDTYP_HELPER0.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER0.typeID+'\",' +
							CASE
								WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
									THEN '\"type_fr\":\"' + TFLDTYP_HELPER0.type + '\",\"type_de\":\"' + TFLDTYP_HELPER0.type + '\",\"type_it\":\"' + TFLDTYP_HELPER0.type + '\",\"type_en\":\"' + TFLDTYP_HELPER0.type + '\"'
								ELSE folderType_param.formatted_json
							END + ','

						WHEN @IS_PAC_MODE = 1
						THEN
							CASE
								WHEN
									TFLDTYP_HELPER.typeNme IS NOT NULL AND TFLDTYP_HELPER.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER.typeID+'\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER.type + '\",\"type_de\":\"' + TFLDTYP_HELPER.type + '\",\"type_it\":\"' + TFLDTYP_HELPER.type + '\",\"type_en\":\"' + TFLDTYP_HELPER.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
								WHEN
									TFLDTYP_HELPER2.typeNme IS NOT NULL AND TFLDTYP_HELPER2.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER2.typeNme+'\",\"pacTypeId\":\"\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER2.type + '\",\"type_de\":\"' + TFLDTYP_HELPER2.type + '\",\"type_it\":\"' + TFLDTYP_HELPER2.type + '\",\"type_en\":\"' + TFLDTYP_HELPER2.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
								WHEN
									TFLDTYP_HELPER3.typeNme IS NOT NULL AND TFLDTYP_HELPER3.type IS NOT NULL
								THEN
									'\"typeId\":\"'+TFLDTYP_HELPER3.typeNme+'\",\"pacTypeId\":\"\",' +
									CASE
										WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
											THEN '\"type_fr\":\"' + TFLDTYP_HELPER3.type + '\",\"type_de\":\"' + TFLDTYP_HELPER3.type + '\",\"type_it\":\"' + TFLDTYP_HELPER3.type + '\",\"type_en\":\"' + TFLDTYP_HELPER3.type + '\"'
										ELSE folderType_param.formatted_json
									END + ','
							ELSE
								'\"typeId\":\"\",\"pacTypeId\":\"\",\"type_fr\":\"Facture\",\"type_de\":\"Facture\",\"type_it\":\"Facture\",\"type_en\":\"Facture\",'
							END
						ELSE
							'\"type_fr\":\"\",\"type_de\":\"\",\"type_it\":\"\",\"type_en\":\"\",'
					END
				END
			+ '\"technicalId\":\"'+ CASE WHEN EZBUNU > 0 THEN UPPER(@ENVIRONMENT) + '-' + convert(varchar,EZBUNU) ELSE '' END + '\",\"id\":\"' + convert(varchar,EZBUNU) + '\",\"databaseId\":\"' + RTRIM(ARAPCD) + '\",\"businessId\":\"' +
			ARAETX
			+ '\",\"isConfidentialUserRestricted\":\"' + CASE WHEN additionalAttribute.isConfidential = '1' THEN 'true' ELSE 'false' END
			+ '\",' +
			CASE
				WHEN database_param.formatted_json is null or database_param.formatted_json = '' THEN
					CASE
						WHEN ECM_PACREF_DB.pacDesc IS NULL OR ECM_PACREF_DB.pacDesc = '' THEN
							'\"databaseDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\",\"databaseDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) +
							'\",\"databaseDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\",\"databaseDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(AOAONA)) + '\"'
						ELSE
							'\"databaseDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\",\"databaseDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) +
							'\",\"databaseDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\",\"databaseDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(ECM_PACREF_DB.pacDesc)) + '\"'
						END
				ELSE
					database_param.formatted_json
			END +
			',\"description_fr\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_fr
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_de\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_de
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_it\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_it
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			'\",\"description_en\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_en
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
            + '\",\"description1\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description1)
			+ '\",\"description2\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description2)
			+ '\",\"description3\":\"' + RTRIM(#TFOLDER_DESCRIPTION.description3)
			+ '\",\"description4\":\"' + CASE WHEN ( @IS_PAC_MODE = 0 ) THEN RTRIM(#TFOLDER_DESCRIPTION.description4) ELSE '' END
			+ '\",\"descriptionIdentifier_fr\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_fr
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(ARAETX) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_fr) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + ARAETX +
			'\",\"descriptionIdentifier_de\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_de
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(ARAETX) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_de) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + ARAETX +
			'\",\"descriptionIdentifier_it\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_it
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(ARAETX) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_it) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + ARAETX +
			'\",\"descriptionIdentifier_en\":\"' +
			CASE
				WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
					THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
				ELSE folderType_param.value_en
			END +
			CASE WHEN LEN(#TFOLDER_DESCRIPTION.description) > 0 THEN CASE WHEN LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1 THEN ' - ' ELSE '' END + RTRIM(#TFOLDER_DESCRIPTION.description) ELSE '' END +
			CASE WHEN LEN(ARAETX) > 0 AND (LEN(#TFOLDER_DESCRIPTION.description) > 0 OR LEN(folderType_param.value_en) > 0 OR @IS_PAC_MODE = 1) THEN ' - ' ELSE '' END + ARAETX +
			'\",\"searchText\":\"' +
			CASE WHEN EZH0TX IS NOT NULL AND DATALENGTH(EZH0TX) >= 3 AND left(EZH0TX, 3) = TFLDTYP_HELPER.typeID
			THEN RIGHT(EZH0TX, DATALENGTH(EZH0TX)- 3) + ' '
			ELSE
			CASE WHEN EZH0TX is null OR EZH0TX='' THEN '' ELSE EZH0TX + ' ' END
			END
			+
			CASE WHEN DD8gaA is null OR DD8gaA='' THEN '' ELSE DD8gaA + ' ' END +
			CASE WHEN DD8gbA is null OR DD8gbA='' THEN '' ELSE DD8gbA + ' ' END +
			CASE WHEN DD8gcA is null OR DD8gcA='' THEN '' ELSE DD8gcA END +
			'\",\"endDate\":\"' + CASE WHEN conservationAttribute.endDate IS NULL
									THEN ''
                                    ELSE format((CONVERT(datetime, RTRIM(conservationAttribute.endDate)) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z'
									END
			+
			'\"' + dbo.convertDateField('openingDate',EZCXDT) +
			CASE
				WHEN EZB8NA is not null and left(EZB8NA, 5) = '!USER'
				THEN ',\"rh_gen\":[\"' + REPLACE(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 5), ',' ,'\",\"') + '\"]'
				ELSE ''
			END +
			CASE
				WHEN EZB9NA is not null and left(EZB9NA, 5) = '!USER'
				THEN ',\"manager_gen\":[\"' + REPLACE(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 5), ',', '\",\"') + '\"]'
				ELSE ''
			END +
			CASE
				WHEN EZCANA is not null and left(EZCANA, 5) = '!USER'
				THEN ',\"employee_gen\":\"' + RIGHT(EZCANA, DATALENGTH(EZCANA)- 5) + '\"'
				ELSE ''
			END +
			',\"parentFolders\":[' +
			CASE WHEN parent_folder_temp.databaseId is null OR parent_folder_temp.databaseId ='' THEN ']' ELSE parent_folder_temp.json + ']' END +
			'}' folderJson,
			CASE
				WHEN additionalAttribute.isConfidential = 1
				THEN 1
				ELSE 0
			END,
			CASE
				WHEN EZBUNU = 0
				THEN -ABS(CAST(CAST(NEWID() AS VARBINARY) AS INT)) -- generate a negative id for non existing folder
				ELSE EZBUNU
			END
	FROM #TFOLDER_DESCRIPTION,
	     #TFOLDER_TEMP
	LEFT JOIN ECM_FCONS conservationAttribute WITH (READUNCOMMITTED) ON EZBUNU = conservationAttribute.folderId
    LEFT JOIN ECM_FADDL additionalAttribute WITH (READUNCOMMITTED) ON EZBUNU = additionalAttribute.folderId
	LEFT JOIN #ECM_PACREF ON #ECM_PACREF.BASE = #TFOLDER_TEMP.ARAPCD AND
							 ( #ECM_PACREF.depId = #TFOLDER_TEMP.DD46A OR
							   ( #ECM_PACREF.depId is null and #TFOLDER_TEMP.DD46A ='' ) OR
							   ( #ECM_PACREF.depId = '' and #TFOLDER_TEMP.DD46A is null ) )
	LEFT JOIN #ECM_PACREF ECM_PACREF_DB ON ECM_PACREF_DB.BASE = #TFOLDER_TEMP.ARAPCD AND
							 ( ECM_PACREF_DB.depId = #TFOLDER_TEMP.DD46A OR
							   ( ECM_PACREF_DB.depId is null and #TFOLDER_TEMP.DD46A ='' ) OR
							   ( ECM_PACREF_DB.depId = '' and #TFOLDER_TEMP.DD46A is null ) )
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER0  ON additionalAttribute.folderType = TFLDTYP_HELPER0.typeNme AND
										#TFOLDER_TEMP.ARAPCD = TFLDTYP_HELPER0.base AND
										additionalAttribute.folderType IS NOT NULL AND additionalAttribute.folderType <> ''
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER  ON
								DATALENGTH(#TFOLDER_TEMP.EZF8TX) >= 3 AND
								left(#TFOLDER_TEMP.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
								#TFOLDER_TEMP.ARAPCD = TFLDTYP_HELPER.base
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER2  ON
										TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
										#TFOLDER_TEMP.ARAPCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(#TFOLDER_TEMP.EZB7NA) >= 6 AND
										LEFT(#TFOLDER_TEMP.EZB7NA, 1) = '!' AND
										LEFT(#TFOLDER_TEMP.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
	LEFT JOIN #ECM_FLDTYP TFLDTYP_HELPER3	ON
										TFLDTYP_HELPER.base IS NULL AND 	-- NOT FOUND BY TYPEID
										TFLDTYP_HELPER2.base IS NULL AND 	-- NOT FOUND BY PREFIXDS1
										DATALENGTH(#TFOLDER_TEMP.EZB7NA) >= 1 AND
										LEFT(#TFOLDER_TEMP.EZB7NA, 1) != '!' AND
										#TFOLDER_TEMP.ARAPCD = TFLDTYP_HELPER3.base AND
										TFLDTYP_HELPER3.typeID =''
	LEFT JOIN #TPARFLD parent_folder_temp ON parent_folder_temp.databaseId = ARAPCD AND parent_folder_temp.businessId = EZF8TX
	LEFT JOIN ARAOREP  WITH (READUNCOMMITTED) ON #TFOLDER_TEMP.ARAPCD = ARAOREP.AOAWCD
	LEFT JOIN ARAJREP  WITH (READUNCOMMITTED) ON #TFOLDER_TEMP.DD46A = ARAJREP.AJAOCD
	LEFT JOIN #ECM_PARAM database_param ON #TFOLDER_TEMP.ARAPCD = database_param.param_id and database_param.param_type = 'DATABASE'
	LEFT JOIN #ECM_PARAM folderType_param ON ISNULL(TFLDTYP_HELPER0.typeNme,ISNULL(TFLDTYP_HELPER.typeNme,ISNULL(TFLDTYP_HELPER2.typeNme,ISNULL(TFLDTYP_HELPER3.typeNme, '')))) = folderType_param.param_id and folderType_param.param_type = 'FOLDERTYPE'
	WHERE ( ( #TFOLDER_TEMP.EZBUNU = #TFOLDER_DESCRIPTION.folderid AND #TFOLDER_TEMP.EZBUNU > 0 ) OR
			( #TFOLDER_TEMP.EZBUNU = #TFOLDER_DESCRIPTION.folderid AND #TFOLDER_TEMP.EZBUNU = 0 AND #TFOLDER_TEMP.ARAETX = #TFOLDER_DESCRIPTION.parentfld ) )

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '7'

	INSERT INTO #TFOLDER_BY_DOCUMENT
	SELECT document_id,
		   STRING_AGG( objectKeyValuesJson, ',' ),
		   STRING_AGG( folderJson, ',' ),
		   MAX( isConfidentialUserRestricted )
	  FROM #TFOLDER_HELPER
	 GROUP BY document_id

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '8'

	IF ( @V_IS_READ_SINGLE_DOCUMENT = 0 )
	BEGIN
		INSERT INTO #ECM_KWLST
		SELECT AUASVN, -- document_id
			   CASE WHEN kwid IS NOT NULL THEN kwid ELSE RTRIM(AUATCD) END,
			   CASE WHEN kwid IS NOT NULL THEN lstid ELSE dbo.escapeSpecialCharacters(REPLACE(AUALNA,'"','&#34;')) END,
			   CASE WHEN kwid IS NOT NULL THEN dbo.escapeSpecialCharacters(RTRIM(lstDesc)) ELSE dbo.escapeSpecialCharacters(REPLACE(AUALNA,'"','&#34;')) END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'fr')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'de')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'it')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'en')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL THEN CASE WHEN lstDesc IS NOT NULL THEN dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '"'), ' ' + lstDesc + ' ') ELSE '' END ELSE '' END
		FROM ARAUREP WITH (READUNCOMMITTED)
			 LEFT JOIN ECM_KWLST WITH (READUNCOMMITTED) ON ARAUREP.AUATCD = ECM_KWLST.kwid AND ARAUREP.AUALNA = ECM_KWLST.lstid,
			 #TDOCID
	   WHERE ARAUREP.AUASVN = #TDOCID.document_id
	END
	ELSE
	BEGIN
		INSERT INTO #ECM_KWLST
		SELECT AUASVN, -- document_id
			   CASE WHEN kwid IS NOT NULL THEN kwid ELSE RTRIM(AUATCD) END,
			   CASE WHEN kwid IS NOT NULL THEN lstid ELSE dbo.escapeSpecialCharacters(REPLACE(AUALNA,'"','&#34;')) END,
			   CASE WHEN kwid IS NOT NULL THEN dbo.escapeSpecialCharacters(RTRIM(lstDesc)) ELSE dbo.escapeSpecialCharacters(REPLACE(AUALNA,'"','&#34;')) END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'fr')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'de')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'it')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL
			   		THEN
			   			CASE WHEN formatted_json IS NULL OR formatted_json = ''
			   				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(ECM_KWLST.lstDesc)))
			   				ELSE REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(formatted_json, 'description_', 'en')), '\\\"', '\"')
			   			END
			   		ELSE ''
			   END,
			   CASE WHEN kwid IS NOT NULL THEN CASE WHEN lstDesc IS NOT NULL THEN dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(formatted_json), '\\\"', '"'), ' ' + lstDesc + ' ') ELSE '' END ELSE '' END
		FROM ARAUREP WITH (READUNCOMMITTED)
			 LEFT JOIN ECM_KWLST WITH (READUNCOMMITTED) ON ARAUREP.AUATCD = ECM_KWLST.kwid AND ARAUREP.AUALNA = ECM_KWLST.lstid
	   WHERE ARAUREP.AUASVN = @V_DOCUMENTID
	END

	if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '8a'

	INSERT INTO #KEYWORD1
	SELECT DISTINCT
		   #ECM_KWLST.document_id,
		   ARALREP.ALATCD, --datatype_id
		   ARALREP.ALAUCD, -- datatype_type
		   #ECM_KWLST.lstid, -- datatype_lstid
		   CASE WHEN #ECM_KWLST.value_fr != '' THEN #ECM_KWLST.value_fr ELSE #ECM_KWLST.lstid END, -- datatype_value_fr
		   #ECM_KWLST.value_de , -- datatype_value_de
		   #ECM_KWLST.value_it , -- datatype_value_it
		   #ECM_KWLST.value_en , -- datatype_value_en
		   CASE WHEN #ECM_KWLST.lstDesc IS NOT NULL THEN
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.lstid, ARALREP.ALAUCD)
					 WHEN #ECM_KWLST.value_fr != '' THEN #ECM_KWLST.value_fr
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_fr_evaluated
				ELSE
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.value_fr, ARALREP.ALAUCD)
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_fr_evaluated
		   END,
		   CASE WHEN #ECM_KWLST.lstDesc IS NOT NULL THEN
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.lstid, ARALREP.ALAUCD)
					 WHEN #ECM_KWLST.value_de != '' THEN #ECM_KWLST.value_de
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_de_evaluated
				ELSE
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.value_de, ARALREP.ALAUCD)
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_de_evaluated
		   END,
		   CASE WHEN #ECM_KWLST.lstDesc IS NOT NULL THEN
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.lstid, ARALREP.ALAUCD)
					 WHEN #ECM_KWLST.value_it != '' THEN #ECM_KWLST.value_it
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_it_evaluated
				ELSE
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.value_it, ARALREP.ALAUCD)
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_it_evaluated
		   END,
		   CASE WHEN #ECM_KWLST.lstDesc IS NOT NULL THEN
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.lstid, ARALREP.ALAUCD)
					 WHEN #ECM_KWLST.value_en != '' THEN #ECM_KWLST.value_en
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_en_evaluated
				ELSE
				CASE WHEN ARALREP.ALAUCD = '01' THEN CAST(CAST(#ECM_KWLST.lstid AS NUMERIC) AS VARCHAR(20))
					 WHEN ARALREP.ALAUCD > '02' AND ARALREP.ALAUCD < '09' THEN dbo.convertKeywordDate(#ECM_KWLST.value_en, ARALREP.ALAUCD)
					 ELSE #ECM_KWLST.lstid
				END -- datatype_value_en_evaluated
		   END,
		   CASE WHEN #ECM_KWLST.formatted_json != '' THEN '"#' + RTRIM(ARALREP.ALATCD) + '#{' + #ECM_KWLST.formatted_json + '}",' ELSE '' END	+
		   '"#' + RTRIM(ARALREP.ALATCD) + '#' + #ECM_KWLST.lstid + '","' +
		   CASE WHEN ARALREP.ALAUCD = '01' THEN '#' + #ECM_KWLST.kwid + '#' + CAST(CAST(#ECM_KWLST.lstid AS BIGINT) AS VARCHAR) + '","' + CAST(CAST(#ECM_KWLST.lstid AS BIGINT) AS VARCHAR) + '","' ELSE '' END
		   + '{' +
		   CASE WHEN #ECM_KWDE.kwdlbl IS NULL THEN
				CASE WHEN #ECM_PARAM.formatted_json IS NOT NULL
					 THEN #ECM_PARAM.formatted_json
					 ELSE '\"dataType_fr\":\" ' + dbo.escapeSpecialCharacters(ARALREP.ALAMNA) + ' \",\"dataType_de\":\" ' + dbo.escapeSpecialCharacters(ARALREP.ALAMNA) +
						  ' \",\"dataType_it\":\" ' + dbo.escapeSpecialCharacters(ARALREP.ALAMNA) + ' \",\"dataType_en\":\" ' + dbo.escapeSpecialCharacters(ARALREP.ALAMNA) + ' \"'
				END
		   ELSE '\"dataType_fr\":\" ' + #ECM_KWDE.kwdlbl + ' \",\"dataType_de\":\" ' + #ECM_KWDE.kwdlbl + ' \",\"dataType_it\":\" ' + #ECM_KWDE.kwdlbl + ' \",\"dataType_en\":\" ' + #ECM_KWDE.kwdlbl + ' \"'
		   END
		   + ',\"value\":\" ' + -- add a space character before keyword value to search with fullText index
		   CASE WHEN #ECM_KWLST.lstDesc IS NOT NULL THEN #ECM_KWLST.lstDesc ELSE #ECM_KWLST.lstid END
		   -- add a space character after keyword value to search with fullText index
		   + ' \"}","' + isnull(ARALREP.ALAUCD,'') + '"' formatted_json,
		   -- MUST keep ARALREP.ALAUCD is in the end of "json" => easy to determine this is the end of keyword.
		   0
	  FROM #ECM_KWLST
		   LEFT JOIN #ECM_KWDE ON #ECM_KWLST.kwid = #ECM_KWDE.kwdid
		   LEFT JOIN #ECM_PARAM ON param_id = #ECM_KWLST.kwid AND param_type = 'DATATYPE',
		   ARALREP WITH (READUNCOMMITTED)
	 WHERE #ECM_KWLST.kwid = ARALREP.ALATCD

