		   #TFOLDER_TEMP.EZAWCD = ecm_fldkw.baseId AND
		   #TFOLDER_DESCRIPTION.description3 != ''

	-- get description 4 of folder
	INSERT INTO #ECM_KWLST
	SELECT #TFOLDER_TEMP.ARASVN,
