							 ',\"typeDescription_fr\":\"'+ ISNULL(RTRIM(kitydo.kindDesc),'') + '\",\"typeDescription_de\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') +
							 '\",\"typeDescription_it\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') + '\",\"typeDescription_en\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') + '\"'
						ELSE ',' + REPLACE(kind_param.formatted_json, 'kindDescription_', 'typeDescription_')
					END
			END
			+ ',\"newExchangeInputDocument\":'+
			CASE
				WHEN (SELECT DDr68A FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DD1rA = basicinfo_temp.document_id) = 'N' AND documentKind != 'V'
				THEN 'true'
				ELSE 'false'
			END
			+ ',\"updateExchangeInputDocument\":'+
			CASE
				WHEN (SELECT DDr68A FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DD1rA = basicinfo_temp.document_id) = 'U'
				THEN 'true'
				ELSE 'false'
			END
			+ ',\"eventGroupId\":\"'+ ISNULL(ecm_daddl.eventGroupId,'') + '\"'
			--#64814 - Yousign
			+ ',\"workflowStatus\":\"' + ISNULL(ecm_daddl.workflowStatus,'') + '\"'
			+ ',\"signatureProcessStatus\":\"' + LTRIM(ISNULL(signatureProcess.status,'')) + '\"'
            --issues/118: Document signature
            + CASE WHEN ecm_daddl.isSigned = 1 THEN ',\"isSigned\": true' ELSE ',\"isSigned\": false' END
			+ ',\"defaultDescriptionId\":\"'+ ISNULL(ECM_DOCDSC.id,'') + '\"'
			+ '}',
			-- part 4
			'","objectSecurityUserNameList":[' +
			CASE
				WHEN sec_user_name_temp.json IS NULL
				THEN ''
				ELSE sec_user_name_temp.json
			END +
			'],"objectSecurityClasses":[' +
			--securityClassList1 DB
			'[],' +
			--securityClassList2 DEP
			'[],' +
			--securityClassList3 KDDOC
			'[],'+
			--securityClassList4 FLRDOC
			'[],'+
			-- securityClassList5 DOC
			CASE
				WHEN documentKind = 'V'
				THEN
					'[' + dbo.getDistinctSecurityClass (
							SUBSTRING((
							SELECT DISTINCT ',"'+ CONVERT(VARCHAR(100),dsc.sec_class)+'"'
								FROM
									DDSECCLASS dsc WITH (READUNCOMMITTED)
							WHERE
									dsc.obj_type= 'DOC' AND
									dsc.obj_id = version_temp.master_document_id
							FOR XML PATH('')
							),2,214483647)
						) + '],'
				ELSE
					'[' + dbo.getDistinctSecurityClass (
								SUBSTRING((
								SELECT DISTINCT ',"'+ CONVERT(VARCHAR(100),dsc.sec_class)+'"'
									FROM
										DDSECCLASS dsc WITH (READUNCOMMITTED)
								WHERE
										dsc.obj_type= 'DOC' AND
										dsc.obj_id = basicinfo_temp.document_id
								FOR XML PATH('')
								),2,214483647)
							) + '],'
			END
			+
			--securityClassList6 PAC
			'[],'+
			--securityClassList7 ORG
			'[],'+
			--securityClassList8 FLRDOC
			'[]],"objectSecurityBusinessObjects":[' +

			--applicationBusinessObjectSecurityList1
			'[' + dbo.getDistinctSecurityClass (
					SUBSTRING((
					SELECT ',"'+ CONVERT(VARCHAR(1020),'/' +esbo.softwareCode + '/' + esbo.objectType + '/' + esbo.objectSubType + '/' + esbo.objectId + '/')+'"'
						FROM
							ecm_secbo esbo WITH (READUNCOMMITTED)
					WHERE
							esbo.documentId = basicinfo_temp.document_id AND esbo.listNumber = 1
					FOR XML PATH('')
					),2,214483647)
				) + '],'
			+
			--applicationBusinessObjectSecurityList2
			'[' + dbo.getDistinctSecurityClass (
					SUBSTRING((
					SELECT ',"'+ CONVERT(VARCHAR(1020),'/' +esbo.softwareCode + '/' + esbo.objectType + '/' + esbo.objectSubType + '/' + esbo.objectId + '/')+'"'
						FROM
							ecm_secbo esbo WITH (READUNCOMMITTED)
					WHERE
							esbo.documentId = basicinfo_temp.document_id AND esbo.listNumber = 2
					FOR XML PATH('')
					),2,214483647)
				) + ']'
			+
			'],"objectKeyValues":[' +

			CASE
				WHEN version_desc.json is null
				THEN ''
				ELSE
				CASE
					WHEN
						documentKind = 'V'
					THEN
						CASE
						WHEN relevant_version.document_id is null or relevant_version.document_id = ''
						THEN
							''
						ELSE
							'"' + version_desc.json
						END
				END
			END
			+
			CASE
				WHEN documentKind = 'V' and relevant_version.document_id is not null and relevant_version.document_id !=''
				THEN ' ' + ISNULL(version_desc.department,'') + ' ' + ISNULL(version_desc.status,'') + ' ' + ISNULL(version_desc.nature,'') + '"'
				ELSE ''
			END
			+
			CASE WHEN keyword_temp.folder_keyword_json is not null
					THEN
						CASE WHEN documentKind = 'V' and relevant_version.document_id is not null and relevant_version.document_id !=''
							THEN ',' + keyword_temp.folder_keyword_json
							ELSE  keyword_temp.folder_keyword_json + ','
						END
				WHEN version_temp.folder_keyword_master_json is not null
					THEN
						CASE WHEN documentKind = 'V' and relevant_version.document_id is not null and relevant_version.document_id !=''
							THEN ',' + version_temp.folder_keyword_master_json
							ELSE version_temp.folder_keyword_master_json + ','
						END
				ELSE ''
			END
			+
			CASE
				WHEN documentKind = 'V'
				THEN
					CASE
						WHEN version_temp.keyword_master_json IS NULL
							OR version_temp.keyword_master_json =''
						THEN
							CASE
								WHEN folder_for_version_temp.objectKeyValuesJson IS NULL
								THEN ''
								ELSE
									CASE
										WHEN relevant_version.document_id is not null and relevant_version.document_id !=''
										THEN ',' + folder_for_version_temp.objectKeyValuesJson
										ELSE folder_for_version_temp.objectKeyValuesJson
									END
							END
						ELSE
							CASE
								WHEN folder_for_version_temp.objectKeyValuesJson IS NULL
									OR folder_for_version_temp.objectKeyValuesJson = ''
								THEN
									CASE
										WHEN relevant_version.document_id is not null and relevant_version.document_id !=''
										THEN ',' + version_temp.keyword_master_json
										ELSE version_temp.keyword_master_json
									END
								ELSE
									CASE
										WHEN relevant_version.document_id is not null and relevant_version.document_id !=''
										THEN ',' + version_temp.keyword_master_json + ',' + folder_for_version_temp.objectKeyValuesJson
										ELSE version_temp.keyword_master_json + ',' + folder_for_version_temp.objectKeyValuesJson
								END
							END
					END
				ELSE
					CASE
						WHEN keyword_temp.json IS NULL OR keyword_temp.json =''
						THEN
							CASE
								WHEN folder_temp.objectKeyValuesJson is null OR folder_temp.objectKeyValuesJson = ''
								THEN ''
								ELSE folder_temp.objectKeyValuesJson
							END
						ELSE
							CASE
								WHEN folder_temp.objectKeyValuesJson IS NULL OR folder_temp.objectKeyValuesJson = ''
								THEN keyword_temp.json
								ELSE keyword_temp.json + ',' + folder_temp.objectKeyValuesJson
							END
					END
			END + ']}}'
			FROM #BASICDOC basicinfo_temp
			LEFT JOIN #KEYWORDV keyword_temp ON basicinfo_temp.document_id = keyword_temp.document_id
			LEFT JOIN #ECM_PACREF ON basicinfo_temp.dbDocumentType = #ECM_PACREF.BASE AND basicinfo_temp.departmentId = #ECM_PACREF.depId
			-- ajout du depid sur la recherche modification du 01/03/2023 par armand
			LEFT JOIN #ECM_PACREF ECM_PACREF_DB ON basicinfo_temp.dbDocumentType = ECM_PACREF_DB.BASE AND
													( ECM_PACREF_DB.depId = departmentId OR
													( ECM_PACREF_DB.depId is null and  departmentId = '' ) OR
													( ECM_PACREF_DB.depId = '' and  departmentId is null ) )
			LEFT JOIN #TFOLDER_BY_DOCUMENT folder_temp ON basicinfo_temp.document_id = folder_temp.document_id
			LEFT JOIN #RELNTVERSV relevant_version ON basicinfo_temp.document_id = relevant_version.document_id
			LEFT JOIN TVISA visa_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = visa_temp.document_id
			LEFT JOIN TCOMMENT comment_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = comment_temp.document_id
			LEFT JOIN ARG1CPP text_extract WITH (READUNCOMMITTED)  ON basicinfo_temp.document_id = text_extract.DD1rA
			LEFT JOIN TSECUNAME sec_user_name_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = sec_user_name_temp.document_id
			LEFT JOIN #VERSION version_temp ON basicinfo_temp.document_id = version_temp.document_id
			LEFT JOIN #TFOLDER_BY_DOCUMENT folder_for_version_temp ON version_temp.master_document_id = folder_for_version_temp.document_id
			LEFT JOIN TLINK link_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = link_temp.document_id
			LEFT JOIN #VERSDESC version_desc ON version_temp.master_document_id = version_desc.master_document_id
			LEFT JOIN KITYDOV kitydo WITH (READUNCOMMITTED) ON basicinfo_temp.docTyId = kitydo.docTyId
			LEFT JOIN ecm_daddl ecm_daddl WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = ecm_daddl.documentId
			LEFT JOIN ECM_DOCDSC ECM_DOCDSC WITH (READUNCOMMITTED) ON ecm_daddl.defaultDescriptionId = ECM_DOCDSC.id
			LEFT JOIN ECM_EXPR signatureProcess WITH (READUNCOMMITTED) on signatureProcess.documentId = basicinfo_temp.document_id
			LEFT JOIN ORG_PARAM_V org_param WITH (READUNCOMMITTED) ON org_param.param_id = ecm_daddl.orgId
			LEFT JOIN ORG_PARAM_V org_param1 WITH (READUNCOMMITTED) ON org_param1.param_id = ECM_PACREF_DB.orgId and org_param1.param_type = 'ORGANIZATION'
			LEFT JOIN #ECM_PARAM kind_param ON kind_param.param_id = kitydo.kindId and kind_param.param_type = 'KINDDOCUMENT'
			LEFT JOIN ecm_param kindGroup_param WITH (READUNCOMMITTED) ON kindGroup_param.param_id = kitydo.kindGrId and kindGroup_param.param_type = 'KINDGROUP'
			LEFT JOIN #ECM_PARAM pac_param ON pac_param.param_id = ECM_PACREF_DB.pacId and pac_param.param_type = 'PAC'
			LEFT JOIN #ECM_PARAM database_param ON database_param.param_id = ECM_PACREF_DB.BASE AND database_param.param_type = 'DATABASE'
			LEFT JOIN ecm_param folderType_param WITH (READUNCOMMITTED) ON folderType_param.param_id in (select fldTyId
																										 from ecm_kitydo WITH (READUNCOMMITTED)
																										 where kindId in (select kindId
																														  from KITYDOV WITH (READUNCOMMITTED)
																														  where docTyId = kitydo.docTyId) and
																											   docTyId = kitydo.docTyId) and
																		   folderType_param.param_type = 'FOLDERTYPE'

			if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12'

            BEGIN TRAN
                SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )

                UPDATE ARAPREP
                    SET processTimeStamp = @V_PROCESS_TIME_STAMP
                    FROM ECM_DOCIDX
                    WHERE ECM_DOCIDX.SESSION_ID = @SESSION_ID AND DOCUMENT_ID = APASVN AND DOCUMENT_ID >= @batch_start AND DOCUMENT_ID <= @batch_end
            COMMIT

            BEGIN TRAN
                -- gitlab#130 - apply semaphore
                SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                BEGIN
                    INSERT INTO TOBJDESC
                        select
                            SESSION_ID,
                            BATCH_ID,
                            INDEXATION_ID,
                            CONCAT(part1, part2, part3, part4),
                            CONCAT(cast(replace(cast(part2 as varchar(max)), '\"', '"') as text),
                                   cast(replace(replace(cast(part3 as varchar(max)), '\"', '"'), '\\"', '\\\"') as text))
                        from #TOBJDESC_SEG

                    UPDATE INDEXATION_BATCH SET COMPUTED = 1 WHERE CURRENT OF batch_cursor
                END
            COMMIT

			DROP TABLE #ECM_DOCIDX
			DROP TABLE #VARELNTVNV
			DROP TABLE #MVARELNTVV
			DROP TABLE #LVRELNTVNV
			DROP TABLE #RELNTVERSV

			FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end
			SET @FETCH_STATUS = @@FETCH_STATUS

		END
	ELSE -- Global indexation
		BEGIN
			-- Extract document original file name and versions file name
            INSERT INTO #ORIGINAL_FILENAME
            SELECT ARAPREP.APASVN,
                   ISNULL(extended.OP1K9A, ''),
                   ISNULL(SUBSTRING((SELECT ',' + ISNULL(doc_extend_original.OP1K9A, '')
                            FROM ARBMREP master_original WITH (READUNCOMMITTED)
                                , ARBMREP version_original WITH (READUNCOMMITTED)
                                , OP8wT doc_extend_original WITH (READUNCOMMITTED)
                                , ARAPREP doc_version WITH (READUNCOMMITTED)
                            WHERE version_original.BMASVN = extended.OP5oA
                                AND master_original.BMG7NA = version_original.BMG7NA
                                AND doc_extend_original.OP5oA = master_original.BMASVN
                                AND doc_version.APASVN = master_original.BMASVN
                                AND doc_version.APBBST = 'V'
                            FOR XML PATH('')
                        ),2,214483647), '')
            FROM ARAPREP WITH (READUNCOMMITTED),
                 OP8wT AS extended WITH (READUNCOMMITTED)
            WHERE ARAPREP.APASVN = extended.OP5oA AND ARAPREP.APASVN >= @batch_start AND ARAPREP.APASVN <= @batch_end

			INSERT INTO #BASICDOC
			SELECT
				APASVN document_id,
				CASE WHEN APBBST IS NULL THEN '' ELSE APBBST END documentKind,
				CASE WHEN APAOCD IS NULL THEN '' ELSE APAOCD END departmentId,
				dbo.escapeSpecialCharacters(AHAHNA) typeDescription,
				CASE WHEN APAFCD IS NULL THEN '' ELSE APAFCD END docTyId,
				CASE WHEN ARAHREP.AHAWCD IS NULL THEN '' ELSE ARAHREP.AHAWCD END dbDocumentType,
				dbo.escapeSpecialCharacters(REPLACE(APACTX, '"', '&#34;')) docDescription,
				CASE WHEN APATVN IS NULL THEN '' ELSE APATVN END creationUserId,
				CASE WHEN APAUVN IS NULL THEN '' ELSE APAUVN END modificationUserId,
				CASE WHEN APAADT IS NULL THEN '' ELSE CASE WHEN APABTM IS NULL THEN '' ELSE dbo.convertDate7StringsToDate( APAADT,APABTM ) END END creationDateTime,
				CASE WHEN APABDT IS NULL THEN '' ELSE CASE WHEN APACTM IS NULL THEN '' ELSE dbo.convertDate7StringsToDate( APABDT,APACTM ) END END modificationDateTime,
				'{\"docTypeDatabaseId\":\"'+ARAHREP.AHAWCD+'\",\"description\":\"' + dbo.escapeSpecialCharacters(REPLACE(APACTX, '"', '&#34;')) + '\",\"typeId\":\"'  +  RTRIM(APAFCD) +  '\",\"departmentId\":\"'  +
				 RTRIM(APAOCD) +  '\",' +
				CASE
					WHEN department_param.formatted_json is null or department_param.formatted_json = '' THEN
						CASE
							WHEN #ECM_PACREF.depDesc is null OR #ECM_PACREF.depDesc = '' THEN
								'\"departmentDescription_fr\":\"' + dbo.escapeSpecialCharacters(RTRIM(REPLACE(AJAJNA, '"', '&#34;'))) +
								'\",\"departmentDescription_de\":\"' + dbo.escapeSpecialCharacters(RTRIM(REPLACE(AJAJNA, '"', '&#34;'))) +
								'\",\"departmentDescription_it\":\"' + dbo.escapeSpecialCharacters(RTRIM(REPLACE(AJAJNA, '"', '&#34;'))) +
								'\",\"departmentDescription_en\":\"' + dbo.escapeSpecialCharacters(RTRIM(REPLACE(AJAJNA, '"', '&#34;'))) + '\"'
							ELSE
								'\"departmentDescription_fr\":\"' + #ECM_PACREF.depDesc + '\",\"departmentDescription_de\":\"' + #ECM_PACREF.depDesc +
								'\",\"departmentDescription_it\":\"' + #ECM_PACREF.depDesc + '\",\"departmentDescription_en\":\"' + #ECM_PACREF.depDesc + '\"'
						END
					ELSE
						department_param.formatted_json
				END
				+
				',\"editorId\":\"'  +  RTRIM(APADCD) + '\",\"fileExtension\":\"'+RTRIM(ADC5NA)+'\",' +
				 CASE
					WHEN editor_param.formatted_json is null or editor_param.formatted_json = '' THEN
						'\"editorDescription_fr\":\"' + dbo.escapeSpecialCharacters(ADAFNA) + '\",\"editorDescription_de\":\"' + dbo.escapeSpecialCharacters(ADAFNA) +
						'\",\"editorDescription_it\":\"' + dbo.escapeSpecialCharacters(ADAFNA) + '\",\"editorDescription_en\":\"' + dbo.escapeSpecialCharacters(ADAFNA) + '\"'
					ELSE
						editor_param.formatted_json
				 END
				+
				',\"originalFileName\":\"' + ISNULL(original_version.originalFileName, '') + '\"'
				+
				',\"originalVersionsFileName\":\"' + ISNULL(original_version.originalVersionsName, '') + '\"'
				+
				',\"creationUserDescription\":\"' +
				(select top(1) ISNULL(MAX(fullname),'') from TUSERDES  WITH (READUNCOMMITTED) where name=RTRIM(APATVN)) + '\",\"modificationUserDescription\":\"' + (select top(1) ISNULL(MAX(fullname),'') from TUSERDES  WITH (READUNCOMMITTED) where name=RTRIM(APAUVN)) +
				'\"'  + CASE WHEN APCLDT is null OR APCLDT = '0' THEN '' ELSE + dbo.convertDateField('expiryDate',convert(VARCHAR,APCLDT)) END  + ',\"documentNumber\":'  +
				CASE WHEN APXINB IS NULL THEN '0' ELSE CAST(APXINB AS VARCHAR) END + ',\"externalProcessingStatus\":\"'  +
				CASE WHEN APKCST is null OR APKCST = '' THEN 'Normal' WHEN APKCST = 'W' THEN 'Visaflow' WHEN APKCST = 'C' THEN 'Conversion'
				WHEN APKCST = 'E' THEN 'Verrouillé'  WHEN APKCST = 'R' THEN 'Réinitialisation' END +
				'\",\"kind\":\"' + CASE WHEN APBBST = 'T' THEN 'Temporaire' WHEN APBBST = 'V' THEN 'Version' ELSE 'Base' END + '\",' +
				CASE WHEN APBCST IS NULL
				THEN ''
				ELSE
				CASE WHEN APBCST NOT IN ('C','0','1','2','3','4','9')
				THEN '\"referencingStatus\":\"C\",' + dbo.getReferencingStatusDescriptions('C') + ','
					ELSE '\"referencingStatus\":\"'+APBCST +'\",' + dbo.getReferencingStatusDescriptions(APBCST) + ','
				END
				END
				+'\"numberOfPages\":' + CASE WHEN OP5qA IS NULL THEN '0' ELSE cast(OP5qA AS varchar) END + ',\"primaryStorageObjectPathAndName\":\"' +
				replace(CASE WHEN extended.OP64A IS NULL OR extended.OP64A = '' OR extended.OP68A IS NULL OR extended.OP68A = '' THEN '' ELSE RTRIM(extended.OP68A + extended.OP64A +
				'/' + SUBSTRING(APASVN,1,CHARINDEX('.',APASVN)-1) +
				'.'  + ADC5NA) END,'\','\\\\')  +  '\",\"secondaryStorageObjectPathAndName\":\"'+replace(CASE WHEN extended.OP65A IS NULL OR extended.OP65A  = '' THEN '' ELSE RTRIM(extended.OP6aA +
				extended.OP65A + '/' + SUBSTRING(APASVN,1,CHARINDEX('.',APASVN)-1) + '.'  + ADC5NA) END ,'\','\\\\') + '\",\"backupStorageObjectPathAndName\":\"'  +
				replace(CASE WHEN OP6xA IS NULL OR OP6xA = '' THEN '' ELSE RTRIM(extended.OP6bA +     OP6xA + '/' + SUBSTRING(APASVN,1,CHARINDEX('.',APASVN)-1) + '.' + ADC5NA) END ,'\','\\\\') +
				'\",\"storageClassId\":\"' + ISNULL(extended.OP5pA, '') + '\",\"storageClassDescription\":\"\",\"fingerPrintType\":\"' +
				CASE WHEN FingerprintType IS NULL OR FingerprintType = '' THEN '' ELSE RTRIM(FingerprintType) END + '\",\"fingerPrintValue\":\"' +
				CASE WHEN Fingerprint IS NULL OR Fingerprint = '' THEN '' ELSE RTRIM(Fingerprint) END + '\",\"cryptographicKeyId\":\"' + CASE WHEN KeyID IS NULL THEN '' ELSE KeyID END + '\"' +
				CASE WHEN APBAST is null OR APBAST !='N' THEN ',\"isArchived\":true' ELSE ',\"isArchived\":false' END json,
				(SELECT CAST(COUNT(*) AS varchar(12)) FROM ARAUREP WITH (READUNCOMMITTED) WHERE AUATCD ='*EFID' AND ARAUREP.AUASVN = ARAPREP.APASVN) AS instancesNumber,
				(SELECT CAST(COUNT(*) AS varchar(12)) FROM ARAUREP WITH (READUNCOMMITTED) WHERE AUATCD ='*EFID' AND ARAUREP.AUASVN =  ARAPREP.APASVN AND AUALNA LIKE 'Active%') AS activeInstancesNumber,
				'UPDATE'
		FROM ARAPREP WITH (READUNCOMMITTED)
				LEFT JOIN #ECM_PARAM department_param ON ARAPREP.APAOCD = department_param.param_id and department_param.param_type = 'DEPARTMENT'
				LEFT JOIN #ECM_PARAM editor_param ON ARAPREP.APADCD = editor_param.param_id and editor_param.param_type = 'EDITOR'
				LEFT JOIN TDOCREF_HELPER ecm_docref  WITH (READUNCOMMITTED) ON ARAPREP.APBCST = ecm_docref.code
				LEFT JOIN #ECM_PACREF ON #ECM_PACREF.BASE = (SELECT TOP(1) ARAHREP.AHAWCD FROM ARAHREP WITH (READUNCOMMITTED) WHERE ARAPREP.APAFCD = ARAHREP.AHAFCD ) AND
										 ( #ECM_PACREF.depId = APAOCD OR
										 ( #ECM_PACREF.depId is null and  APAOCD ='' ) OR
										 ( #ECM_PACREF.depId = '' and  APAOCD is null ) )
				LEFT JOIN #ORIGINAL_FILENAME original_version ON original_version.documentId = ARAPREP.APASVN,
				ARAHREP WITH (READUNCOMMITTED) ,
				ARAJREP WITH (READUNCOMMITTED) ,
				ARADREP WITH (READUNCOMMITTED) ,
				OP8wT AS extended WITH (READUNCOMMITTED)
		WHERE	ARAPREP.APAFCD = ARAHREP.AHAFCD AND ARAPREP.APAOCD = ARAJREP.AJAOCD AND ARAPREP.APADCD = ARADREP.ADADCD AND ARAPREP.APASVN = extended.OP5oA AND
					ARAPREP.APASVN >= @batch_start AND ARAPREP.APASVN <= @batch_end
--             /* \"'' --add this line for development purpose. Text editor has issue when highlighting this file */

		if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '11'

		INSERT INTO #TOBJDESC_SEG
			select @SESSION_ID,
			@batch_id,
			'XECM-DOCUMENT--' + UPPER(@V_CLIENTHOSTNAME) + '-' + basicinfo_temp.document_id indexation_id,
			-- part 1
			'{"objectDescriptors":{"id":"XECM-DOCUMENT--' + UPPER(@V_CLIENTHOSTNAME) + '-' + basicinfo_temp.document_id +
			'","processOperation":"' + processOperation +
			'","processTimeStamp":"' + @V_PROCESS_TIME_STAMP +
			'","objectReference":{"objectKind":{"softwareCode":"XECM","objectType":"Document","objectSubType":""},"objectId":"' + basicinfo_temp.document_id + '"}' + ',"objectSource":{"objectSourceKind":{"type":"Xpert.ECM","name":"' +
			+ @V_CLIENTHOSTNAME + '"}},' +
			'"objectDescription":{"preview":"' + basicinfo_temp.docDescription + '\n' + 'Créé le ' + basicinfo_temp.creationDateTime + ' par ' + RTRIM( basicinfo_temp.creationUserId ) + '\nModifié le ' +
			basicinfo_temp.modificationDateTime + ' par ' + RTRIM( basicinfo_temp.modificationUserId ) + '","businessObjectId":"' + basicinfo_temp.document_id + '","objectName":"' + basicinfo_temp.docDescription +
			'",'+ dbo.buildDocumentDescriptionLocale(ECM_DOCDSC.documentDescription,basicinfo_temp.docDescription)
			-- "objectNameLocale":[{"locale":"fr","value":"' + basicinfo_temp.docDescription + '"},{"locale":"de","value":"' + basicinfo_temp.docDescription + '"},{"locale":"it","value":"' +
			--basicinfo_temp.docDescription + '"},{"locale":"en","value":"' + basicinfo_temp.docDescription + '"}]
			+ ',"audit":{"creationUser":"' + RTRIM( basicinfo_temp.creationUserId ) +
			'",' +
			CASE WHEN LEN(basicinfo_temp.creationDateTime) = 19 THEN
                '"creationDateTime":"' + format((CONVERT(datetime, basicinfo_temp.creationDateTime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' +
			'",'
			ELSE ''
			END +
			'"modificationUser":"' + RTRIM(basicinfo_temp.modificationUserId) + '"' +
			CASE WHEN LEN(basicinfo_temp.modificationDateTime) = 19 THEN
                ',"modificationDateTime":"' + format((CONVERT(datetime, basicinfo_temp.modificationDateTime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' +
			'"'
			ELSE ''
			END +
			'}' +
			CASE WHEN LEN(basicinfo_temp.creationDateTime) = 19 THEN
                ',"objectFilterDate":"' + format((CONVERT(datetime, basicinfo_temp.creationDateTime) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' +
			'"'
			ELSE ''
			END +
			CASE WHEN ( folder_temp.isConfidentialUserRestricted = 1 OR folder_for_version_temp.isConfidentialUserRestricted = 1 ) THEN ',"isConfidentialUserRestricted":true' ELSE ',"isConfidentialUserRestricted":false' END +
			'},"objectAttributes":"',
			-- part 2
			basicinfo_temp.json,
			-- part 3
			',\"eFolder\":{\"instancesNumber\":' +
			CASE
				WHEN documentKind = 'V'
				THEN
					ISNULL(version_temp.instancesNumber, '\"\"')
				ELSE
					ISNULL(basicinfo_temp.instancesNumber, '\"\"')
			END +
            ',\"activeInstancesNumber\":' +
            CASE
				WHEN documentKind = 'V'
				THEN
					ISNULL(version_temp.activeInstancesNumber, '\"\"')
				ELSE
					ISNULL(basicinfo_temp.activeInstancesNumber, '\"\"')
			END +
			'}' +
            ',\"folders\":[' +
			CASE
				WHEN documentKind = 'V'
				THEN
					CASE
						WHEN folder_for_version_temp.folderJson IS NULL
						THEN ''
						ELSE folder_for_version_temp.folderJson
					END
				ELSE
					CASE
						WHEN folder_temp.folderJson IS NULL
						THEN ''
						ELSE folder_temp.folderJson
					END
			END +
			'],\"visas\":[' +
			CASE
				WHEN visa_temp.json IS NULL
				THEN ''
				ELSE visa_temp.json
			END +
			'],\"comments\":[' +
			CASE
				WHEN comment_temp.json IS NULL
				THEN ''
				ELSE comment_temp.json
			END +
			'],\"textExtract\":\"' +
			CASE
				WHEN text_extract.DDr6bA IS NULL
				THEN ''
				ELSE dbo.escapeSpecialCharacters( CAST(text_extract.DDr6bA AS VARCHAR(MAX)) )
			END +
			'\",\"hasVisas\":' +
			CASE
				WHEN visa_temp.json IS NULL
				THEN 'false'
				ELSE 'true'
			END +
			',\"hasVersions\":' +
			CASE
				WHEN documentKind = 'V'
				THEN 'false'
				ELSE
					CASE
						WHEN link_temp.json_version is null OR  link_temp.json_version = ''
						THEN 'false'
						ELSE 'true'
					END
			END +
			',\"controlledVersion\":' +
			CASE
				WHEN documentKind != 'V'
				THEN
					CASE
						WHEN documentKind = 'I'
						THEN 'true'
						ELSE 'false'
					END
				ELSE
					CASE
						WHEN version_temp.master_document_kind = 'I'
						THEN 'true'
						ELSE 'false'
					END
			END +
			',\"hasComments\":' +
			CASE
				WHEN comment_temp.json IS NULL
				THEN 'false'
				ELSE 'true'
			END +
			CASE
				WHEN version_temp.json is NULL
				THEN ''
				ELSE ',' + version_temp.json
			END +
			CASE
				WHEN link_temp.json_version is NULL
				THEN ''
				ELSE ',\"versionDocumentIds\":[' + link_temp.json_version + ']'
			END +
			CASE
				WHEN link_temp.json_link is NULL
				THEN ''
				ELSE ',\"linkedDocumentIds\":[' + link_temp.json_link + ']'
			END +
			CASE
				WHEN link_temp.json_link is NULL
				THEN ',\"hasLinkedDocuments\":false'
				ELSE ',\"hasLinkedDocuments\":true'
			END
			+
			CASE
				WHEN kitydo.kindId IS NOT NULL
				THEN ',\"kindId\":\"' + kitydo.kindId +'\"' +
					CASE
						WHEN kind_param.formatted_json is null or kind_param.formatted_json = ''
						THEN
						',\"kindDescription_fr\":\"'+ ISNULL(RTRIM(kitydo.kindDesc),'') + '\",\"kindDescription_de\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') +
						'\",\"kindDescription_it\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') + '\",\"kindDescription_en\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') + '\"'
						ELSE ',' + kind_param.formatted_json
					END +
					',\"kindGroupId\":\"' + ISNULL(RTRIM(kitydo.kindGrId),'')+ '\"' +
					CASE
						WHEN kindGroup_param.formatted_json is null or kindGroup_param.formatted_json = '' or folderType_param.formatted_json is null or folderType_param.formatted_json = ''
						THEN ',' + dbo.getDefaultDescriptions('kindGroupDescription_', dbo.formatFolderDescription(ISNULL(kitydo.fldTyDesc,'') + '#V_KIND_GRP_DESC#' + ISNULL(kitydo.kindGrDesc,''),'#V_KIND_GRP_DESC#',' - '))
						ELSE ',' + dbo.getKindGroupDescriptions(kitydo.docTyId, folderType_param.formatted_json, kindGroup_param.formatted_json)
					END
				ELSE
					''
			END
			+
			CASE
				WHEN ECM_PACREF_DB.pacId IS NOT NULL
				THEN
				',\"pacId\":\"'+ECM_PACREF_DB.pacId+'\"'
				ELSE
				''
			END
			+
			CASE
				WHEN ECM_PACREF_DB.pacDesc IS NOT NULL
				THEN
					CASE
						WHEN pac_param.formatted_json is null or pac_param.formatted_json = ''
							THEN
							',\"pacDescription_fr\":\"'+ ISNULL(RTRIM(ECM_PACREF_DB.pacDesc),'') + '\",\"pacDescription_de\":\"' + ISNULL(RTRIM(ECM_PACREF_DB.pacDesc),'') +
							'\",\"pacDescription_it\":\"' + ISNULL(RTRIM(ECM_PACREF_DB.pacDesc),'') + '\",\"pacDescription_en\":\"' + ISNULL(RTRIM(ECM_PACREF_DB.pacDesc),'') + '\"'
						ELSE ',' + pac_param.formatted_json
					END
				ELSE
					''
			END
			+
			CASE
				WHEN
					ECM_PACREF_DB.pacDesc IS NOT NULL AND ECM_PACREF_DB.pacDesc <> ''
				THEN
					CASE
						WHEN pac_param.formatted_json is null or pac_param.formatted_json = ''
							THEN ',' + dbo.getDefaultDescriptions('origin_', ISNULL(RTRIM(ECM_PACREF_DB.pacDesc), ''))
						ELSE ',' + REPLACE(pac_param.formatted_json, 'pacDescription', 'origin')
					END
				ELSE
					CASE
					WHEN ECM_PACREF_DB.baseDesc IS NOT NULL
					THEN
						CASE
							WHEN database_param.formatted_json is null or database_param.formatted_json = ''
								THEN ',' + dbo.getDefaultDescriptions('origin_', ISNULL(RTRIM(ECM_PACREF_DB.baseDesc), ''))
							ELSE ',' + REPLACE(database_param.formatted_json, 'pacDescription', 'origin')
						END
					ELSE
						''
					END
			END
			+
			CASE
				WHEN ecm_daddl.orgId IS NOT NULL OR ecm_daddl.orgId <> ''
				THEN
					',\"organizationId\":\"' + ecm_daddl.orgId + '\"'
				ELSE
					CASE
						WHEN ECM_PACREF_DB.orgId IS NOT NULL
						THEN
						',\"organizationId\":\"' + ECM_PACREF_DB.orgId + '\"'
						ELSE
						''
					END
			END

				+
			CASE
				WHEN org_param.param_data IS NOT NULL OR org_param.param_data <> ''
				THEN
					CASE
						WHEN org_param.formatted_json is null or org_param.formatted_json = ''
						THEN ''
						ELSE ',' + REPLACE(dbo.escapeSpecialCharacters(org_param.formatted_json), '\\\"', '\"')
					END
				ELSE
				    CASE
                    	WHEN org_param1.param_data IS NOT NULL OR org_param1.param_data <> ''
                    	THEN
                    		CASE
                    			WHEN org_param1.formatted_json is null or org_param1.formatted_json = ''
                    			THEN ''
                    			ELSE ',' + REPLACE(dbo.escapeSpecialCharacters(org_param1.formatted_json), '\\\"', '\"')
                    		END
                    	ELSE
                    		''
                    END
			END
			+
			CASE
			WHEN
				documentKind!='V'
			THEN
				CASE
				WHEN link_temp.json_version is null OR  link_temp.json_version = ''
				THEN ',\"isRelevantVersion\":true'
				ELSE ',\"isRelevantVersion\":false'
				END
			ELSE
				CASE
				WHEN
					relevant_version.document_id is null or relevant_version.document_id = ''
				THEN
					',\"isRelevantVersion\":false'
				ELSE
					',\"isRelevantVersion\":true'
				END
			END
			+

			CASE
			WHEN documentKind = 'V'
			THEN
				CASE
				WHEN version_temp.dynamic_key_pair IS NOT NULL
				THEN ','+ REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(version_temp.dynamic_key_pair,'&amp;','&' ),'&lt;','<'),'&gt;','>'),'&quot;','"'),'&apos;','''')
				ELSE ''
				END
			ELSE
				CASE
				WHEN keyword_temp.dynamic_key_pair IS NOT NULL
				THEN ','+ REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(keyword_temp.dynamic_key_pair,'&amp;','&' ),'&lt;','<'),'&gt;','>'),'&quot;','"'),'&apos;','''')
				ELSE ''
				END
			END
			+
			CASE
			WHEN documentKind = 'V'
			THEN
				CASE
				WHEN version_temp.keyword_master_search_type IS NOT NULL
				THEN ',\"searchDataType\":['+ version_temp.keyword_master_search_type + ']'
				ELSE ''
				END
			ELSE
				CASE
				WHEN keyword_temp.search_type IS NOT NULL
				THEN ',\"searchDataType\":['+ keyword_temp.search_type + ']'
				ELSE ''
				END
			END
			+
			CASE
				WHEN kitydo.kindDesc IS NULL THEN
					',\"typeDescription_fr\":\"'+ ISNULL(RTRIM(basicinfo_temp.typeDescription),'') + '\",\"typeDescription_de\":\"' + ISNULL(RTRIM(basicinfo_temp.typeDescription),'') +
					'\",\"typeDescription_it\":\"' + ISNULL(RTRIM(basicinfo_temp.typeDescription),'') + '\",\"typeDescription_en\":\"' + ISNULL(RTRIM(basicinfo_temp.typeDescription),'') + '\"'
				ELSE
					CASE
						WHEN kind_param.formatted_json is null or kind_param.formatted_json = '' THEN
							 ',\"typeDescription_fr\":\"'+ ISNULL(RTRIM(kitydo.kindDesc),'') + '\",\"typeDescription_de\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') +
							 '\",\"typeDescription_it\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') + '\",\"typeDescription_en\":\"' + ISNULL(RTRIM(kitydo.kindDesc),'') + '\"'
						ELSE ',' + REPLACE(kind_param.formatted_json, 'kindDescription_', 'typeDescription_')
					END
			END
			+ ',\"newExchangeInputDocument\":'+
			CASE
				WHEN (SELECT DDr68A FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DD1rA = basicinfo_temp.document_id) = 'N' AND documentKind != 'V'
				THEN 'true'
				ELSE 'false'
			END
			+ ',\"updateExchangeInputDocument\":'+
			CASE
				WHEN (SELECT DDr68A FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DD1rA = basicinfo_temp.document_id) = 'U'
				THEN 'true'
				ELSE 'false'
			END
			+ ',\"eventGroupId\":\"'+ ISNULL(ecm_daddl.eventGroupId,'') + '\"'
			--#64814 - Yousign
			+ ',\"workflowStatus\":\"' + ISNULL(ecm_daddl.workflowStatus,'') + '\"'
			+ ',\"signatureProcessStatus\":\"' + LTRIM(ISNULL(signatureProcess.status,'')) + '\"'
            --issues/118: Document signature
            + CASE WHEN ecm_daddl.isSigned = 1 THEN ',\"isSigned\": true' ELSE ',\"isSigned\": false' END
			+ ',\"defaultDescriptionId\":\"'+ ISNULL(ECM_DOCDSC.id,'') + '\"'
			+ '}',
			-- part 4
			'","objectSecurityUserNameList":[' +
			CASE
				WHEN sec_user_name_temp.json IS NULL
				THEN ''
				ELSE sec_user_name_temp.json
			END +
			'],"objectSecurityClasses":[' +
			--securityClassList1 BD
			'[],' +
			--securityClassList2 DEP
			'[],' +
			--securityClassList3 KDDOC
			'[],'+
			--securityClassList4 FLRDOC
			'[],'+
			-- securityClassList5 DOC
			CASE
				WHEN documentKind = 'V'
				THEN
					'[' + dbo.getDistinctSecurityClass (
							SUBSTRING((
							SELECT DISTINCT ',"'+ CONVERT(VARCHAR(100),dsc.sec_class)+'"'
								FROM
									DDSECCLASS dsc WITH (READUNCOMMITTED)
							WHERE
									dsc.obj_type= 'DOC' AND
									dsc.obj_id = version_temp.master_document_id
							FOR XML PATH('')
							),2,214483647)
						) + '],'
				ELSE
					'[' + dbo.getDistinctSecurityClass (
								SUBSTRING((
								SELECT DISTINCT ',"'+ CONVERT(VARCHAR(100),dsc.sec_class)+'"'
									FROM
										DDSECCLASS dsc WITH (READUNCOMMITTED)
								WHERE
										dsc.obj_type= 'DOC' AND
										dsc.obj_id = basicinfo_temp.document_id
								FOR XML PATH('')
								),2,214483647)
							) + '],'
			END
			+
			--securityClassList6 PAC
			'[],'+
			--securityClassList7 ORG
			'[],'+
			--securityClassList8 FLRDOC
			'[]],"objectSecurityBusinessObjects":[' +
			--applicationBusinessObjectSecurityList1
			'[' + dbo.getDistinctSecurityClass (
					SUBSTRING((
					SELECT ',"'+ CONVERT(VARCHAR(1020),'/' +esbo.softwareCode + '/' + esbo.objectType + '/' + esbo.objectSubType + '/' + esbo.objectId + '/')+'"'
						FROM
							ecm_secbo esbo WITH (READUNCOMMITTED)
					WHERE
							esbo.documentId = basicinfo_temp.document_id AND esbo.listNumber = 1
					FOR XML PATH('')
					),2,214483647)
				) + '],'
			+
			--applicationBusinessObjectSecurityList2
			'[' + dbo.getDistinctSecurityClass (
					SUBSTRING((
					SELECT ',"'+ CONVERT(VARCHAR(1020),'/' +esbo.softwareCode + '/' + esbo.objectType + '/' + esbo.objectSubType + '/' + esbo.objectId + '/')+'"'
						FROM
							ecm_secbo esbo WITH (READUNCOMMITTED)
					WHERE
							esbo.documentId = basicinfo_temp.document_id AND esbo.listNumber = 2
					FOR XML PATH('')
					),2,214483647)
				) + ']'
			+
			'],"objectKeyValues":[' +

			CASE
				WHEN version_desc.json is null
				THEN ''
				ELSE
				CASE
					WHEN
						documentKind = 'V'
					THEN
						CASE
						WHEN relevant_version.document_id is null or relevant_version.document_id = ''
						THEN
							''
						ELSE
							'"' + version_desc.json
						END
				END
			END
			+
			CASE
				WHEN documentKind = 'V' and relevant_version.document_id is not null and relevant_version.document_id !=''
				THEN ' ' + ISNULL(version_desc.department,'') + ' ' + ISNULL(version_desc.status,'') + ' ' + ISNULL(version_desc.nature,'')	+ '"'
				ELSE ''
			END
			+
			CASE WHEN keyword_temp.folder_keyword_json is not null
					THEN
						CASE WHEN documentKind = 'V' and relevant_version.document_id is not null and relevant_version.document_id !=''
							THEN ',' + keyword_temp.folder_keyword_json
							ELSE  keyword_temp.folder_keyword_json + ','
						END
				WHEN version_temp.folder_keyword_master_json is not null
					THEN
						CASE WHEN documentKind = 'V' and relevant_version.document_id is not null and relevant_version.document_id !=''
							THEN ',' + version_temp.folder_keyword_master_json
							ELSE version_temp.folder_keyword_master_json + ','
						END
				ELSE ''
			END
			+
			CASE
				WHEN documentKind = 'V'
				THEN
					CASE
						WHEN version_temp.keyword_master_json IS NULL
							OR version_temp.keyword_master_json =''
						THEN
							CASE
								WHEN folder_for_version_temp.objectKeyValuesJson IS NULL
								THEN ''
								ELSE
									CASE
										WHEN relevant_version.document_id is not null and relevant_version.document_id !=''
										THEN ',' + folder_for_version_temp.objectKeyValuesJson
										ELSE folder_for_version_temp.objectKeyValuesJson
									END
							END
						ELSE
							CASE
								WHEN folder_for_version_temp.objectKeyValuesJson IS NULL
									OR folder_for_version_temp.objectKeyValuesJson = ''
								THEN
									CASE
										WHEN relevant_version.document_id is not null and relevant_version.document_id !=''
										THEN ',' + version_temp.keyword_master_json
										ELSE version_temp.keyword_master_json
									END
								ELSE
									CASE
										WHEN relevant_version.document_id is not null and relevant_version.document_id !=''
										THEN ',' + version_temp.keyword_master_json + ',' + folder_for_version_temp.objectKeyValuesJson
										ELSE version_temp.keyword_master_json + ',' + folder_for_version_temp.objectKeyValuesJson
								END
							END
					END
				ELSE
					CASE
						WHEN keyword_temp.json IS NULL OR keyword_temp.json =''
						THEN
							CASE
								WHEN folder_temp.objectKeyValuesJson is null OR folder_temp.objectKeyValuesJson = ''
								THEN ''
								ELSE folder_temp.objectKeyValuesJson
							END
						ELSE
							CASE
								WHEN folder_temp.objectKeyValuesJson IS NULL OR folder_temp.objectKeyValuesJson = ''
								THEN keyword_temp.json
								ELSE keyword_temp.json + ',' + folder_temp.objectKeyValuesJson
							END
					END
			END
			+ ']}}'
			FROM #BASICDOC basicinfo_temp
			LEFT JOIN #KEYWORDV keyword_temp ON basicinfo_temp.document_id = keyword_temp.document_id
			LEFT JOIN #ECM_PACREF ON basicinfo_temp.dbDocumentType = #ECM_PACREF.BASE AND basicinfo_temp.departmentId	= #ECM_PACREF.depId
			-- ajout du depid sur la recherche modification du 01/03/2023 par armand
			LEFT JOIN #ECM_PACREF ECM_PACREF_DB ON basicinfo_temp.dbDocumentType = ECM_PACREF_DB.BASE AND
													( ECM_PACREF_DB.depId = departmentId OR
													( ECM_PACREF_DB.depId is null and  departmentId = '' ) OR
													( ECM_PACREF_DB.depId = '' and  departmentId is null ) )
			LEFT JOIN #TFOLDER_BY_DOCUMENT folder_temp ON basicinfo_temp.document_id = folder_temp.document_id
			LEFT JOIN #RELNTVERSV relevant_version ON basicinfo_temp.document_id = relevant_version.document_id
			LEFT JOIN TVISA visa_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = visa_temp.document_id
			LEFT JOIN TCOMMENT comment_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = comment_temp.document_id
			LEFT JOIN ARG1CPP text_extract  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = text_extract.DD1rA
			LEFT JOIN TSECUNAME sec_user_name_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = sec_user_name_temp.document_id
			LEFT JOIN #VERSION version_temp ON basicinfo_temp.document_id = version_temp.document_id
			LEFT JOIN #TFOLDER_BY_DOCUMENT folder_for_version_temp ON version_temp.master_document_id = folder_for_version_temp.document_id
			LEFT JOIN TLINK link_temp  WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = link_temp.document_id
			LEFT JOIN #VERSDESC version_desc ON version_temp.master_document_id = version_desc.master_document_id
			LEFT JOIN KITYDOV kitydo WITH (READUNCOMMITTED) ON basicinfo_temp.docTyId = kitydo.docTyId
			LEFT JOIN ecm_daddl ecm_daddl WITH (READUNCOMMITTED) ON basicinfo_temp.document_id = ecm_daddl.documentId
			LEFT JOIN ECM_DOCDSC ECM_DOCDSC WITH (READUNCOMMITTED) ON ecm_daddl.defaultDescriptionId = ECM_DOCDSC.id
			LEFT JOIN ECM_EXPR signatureProcess WITH (READUNCOMMITTED) on signatureProcess.documentId = basicinfo_temp.document_id
			LEFT JOIN ORG_PARAM_V org_param WITH (READUNCOMMITTED) ON org_param.param_id = ecm_daddl.orgId
			LEFT JOIN ORG_PARAM_V org_param1 WITH (READUNCOMMITTED) ON org_param1.param_id = ECM_PACREF_DB.orgId and org_param1.param_type = 'ORGANIZATION' -- use for old document from customer do not have ecm_daddl
			LEFT JOIN #ECM_PARAM kind_param ON kind_param.param_id = kitydo.kindId and kind_param.param_type = 'KINDDOCUMENT'
			LEFT JOIN ecm_param kindGroup_param WITH (READUNCOMMITTED) ON kindGroup_param.param_id = kitydo.kindGrId and kindGroup_param.param_type = 'KINDGROUP'
			LEFT JOIN #ECM_PARAM pac_param ON pac_param.param_id = ECM_PACREF_DB.pacId and pac_param.param_type = 'PAC'
			LEFT JOIN #ECM_PARAM database_param ON database_param.param_id = ECM_PACREF_DB.BASE AND database_param.param_type = 'DATABASE'
			LEFT JOIN ecm_param folderType_param WITH (READUNCOMMITTED) ON folderType_param.param_id in (select fldTyId from ecm_kitydo WITH (READUNCOMMITTED) where kindId in (select kindId from KITYDOV WITH (READUNCOMMITTED) where docTyId = kitydo.docTyId) and docTyId = kitydo.docTyId) and folderType_param.param_type = 'FOLDERTYPE'
			WHERE basicinfo_temp.document_id >= @batch_start AND basicinfo_temp.document_id <= @batch_end

			if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12'

            BEGIN TRAN
                SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )

                UPDATE ARAPREP
                SET processTimeStamp = @V_PROCESS_TIME_STAMP
                WHERE APASVN >= @batch_start AND APASVN <= @batch_end
            COMMIT

            BEGIN TRAN
                -- gitlab#130 - apply semaphore
                SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                BEGIN
                    INSERT INTO TOBJDESC
                        select
                            SESSION_ID,
                            BATCH_ID,
                            INDEXATION_ID,
                            CONCAT(part1, part2, part3, part4),
                            CONCAT(cast(replace(cast(part2 as varchar(max)), '\"', '"') as text),
                                   cast(replace(replace(cast(part3 as varchar(max)), '\"', '"'), '\\"', '\\\"') as text))
                        from #TOBJDESC_SEG

                    UPDATE INDEXATION_BATCH SET COMPUTED = 1 WHERE CURRENT OF batch_cursor
                END
            COMMIT

			DROP TABLE #VARELNTVNV
			DROP TABLE #MVARELNTVV
			DROP TABLE #LVRELNTVNV
			DROP TABLE #RELNTVERSV

			FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end
			SET @FETCH_STATUS = @@FETCH_STATUS

			WHILE ( @FETCH_STATUS = 0 AND @batch_id % @CPU_NR != @CPU_TO_USE )
			BEGIN
				FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end
				SET @FETCH_STATUS = @@FETCH_STATUS
			END

       END
	END

	if @V_IS_READ_SINGLE_DOCUMENT = 0
		BEGIN
			CLOSE batch_cursor
			DEALLOCATE batch_cursor

			IF ( @V_ACTION = 'PROCESSOR' )
				BEGIN
					IF EXISTS ( SELECT * FROM ARG0CPP WITH (READUNCOMMITTED) WHERE DDr68A = 'L' ) -- The processor has been restarted
						DELETE FROM ARG0CPP WHERE DDr68A IN ( 'S', 'L' )

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12c'

					BEGIN TRAN
					SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12d'

					UPDATE ARG0CPP
					   SET DDr68A = 'I',
					       errDetail = NULL
					 --FROM ECM_DOCIDX
					 WHERE --ECM_DOCIDX.SESSION_ID = @SESSION_ID AND
						   --DOCUMENT_ID = DD1rA AND
						   DD1RA IN (SELECT DOCUMENT_ID FROM ECM_DOCIDX WHERE SESSION_ID = @SESSION_ID) and
						   ( DDr67A <= @INDEXATION_START OR DDr67A is null )

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12e'

					DELETE FROM ECM_DOCIDX WHERE SESSION_ID = @SESSION_ID

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12f'

					SELECT @DOCUMENT_TO_INDEX = COUNT(*) FROM ARG0CPP WHERE DDr68A IN ( 'R', 'M', 'N' ) AND DD1rA NOT IN ( SELECT DOCUMENT_ID FROM ECM_DOCIDX )
					COMMIT

					if ( @V_ISDEBUGGING_DETAILED = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12g'
				END
		END
    ELSE
        BEGIN
            IF (@V_ACTION != 'EXPORTJSON')
                BEGIN
                    BEGIN TRAN
                    SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )
                    -- Update processTimeStamp for current version
                    UPDATE ARAPREP
                    SET processTimeStamp = @V_PROCESS_TIME_STAMP
                    WHERE APASVN = @batch_start

                    IF (@V_ACTION != 'CONTINUE')
                        BEGIN
                            -- Update for related versions to R
                            UPDATE ARG0CPP
                            SET DDr68A = 'N'
                            FROM ARBMREP T1 WITH (READUNCOMMITTED),
                                 ARBMREP T2 WITH (READUNCOMMITTED)
                            WHERE T1.BMASVN = DD1rA AND
                                    T1.BMASVN <> @batch_start AND
                                    T1.BMG7NA = T2.BMG7NA AND
                                    T2.BMASVN = @batch_start
                        END
                    COMMIT
                END
        END

    END

	if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '13'

END
GO

--PART : exportFolder part
----------------------------------------------------------------------------------
--              THIS FILE CONTAINS THREE PARTS:									--
--  + PART 1: THE TABLES USE FOR ECM FOLDER INDEXATION					    	--
--  + PART 2: THE FUNCTIONS USED FOR PROCESSING FOLDER INDEXATION DATA			--
--  + PART 3: THE STORE PROCEDURE USES FOR READING ALL FOLDER INFOMATION      	--
-- Notes:
--	whenever you run the "exportfolder" procedure with different language		--
--	and/or different environment, please run this script again to deleted		--
--	old views.																	--
----------------------------------------------------------------------------------

----------------------------------------------------------------------------------
-- PART 1: CREATE TABLES IS USED FOR ECM FOLDER INDEXATION            			--
----------------------------------------------------------------------------------
-- Create "object descriptor" temporary table
IF EXISTS( SELECT * FROM sys.tables WHERE name = 'TFLDDESC')
	DROP TABLE [dbo].[TFLDDESC]

IF NOT EXISTS( SELECT * FROM sys.tables WHERE name = 'TFLDDESC')
BEGIN
	CREATE TABLE [dbo].[TFLDDESC] (
		[SESSION_ID] varchar(100) NOT NULL,
		[BATCH_ID] int NOT NULL,
		[id] varchar(400) NOT NULL ,
		[descriptor] text NULL,
		[object_attributes] text
)

	CREATE NONCLUSTERED INDEX IX_01 on TFLDDESC (SESSION_ID)
	CREATE NONCLUSTERED INDEX IX_02 on TFLDDESC (SESSION_ID,id)
END

IF EXISTS( SELECT * FROM sys.tables WHERE name = 'ecm_folder_event_security')
	DROP TABLE [dbo].[ecm_folder_event_security]
GO

----------------------------------------------------------------------------------
-- PART 2: CREATE FUNCTIONS USED TO PROCESS FOLDER INDEXATION DATA     		--
----------------------------------------------------------------------------------
-- /**
--  * FUNCTION *getFldStatusDesc*
--  * return the folder status description by folder status code
--  * Input:
--  * 		statusCode 			: folder status code
--  * 		lang 				: language
--  *
--  * Output:
--  *		folder status description string
--  *
--  */

IF OBJECT_ID (N'dbo.getFldStatusDesc', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getFldStatusDesc
GO
CREATE FUNCTION dbo.getFldStatusDesc(@STATUS_CODE VARCHAR(1), @LANG VARCHAR(2))
RETURNS VARCHAR(50)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(50)

	IF (@LANG = 'en' OR @LANG = 'EN')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)
					WHEN '0' THEN 'Processing'
					WHEN '1' THEN 'Closed'
					WHEN '2' THEN 'Temporary'
					WHEN 'A' THEN 'Active'
					WHEN 'B' THEN 'Blocked'
					WHEN 'C' THEN 'Circulating'
					WHEN 'T' THEN 'Processed'
					WHEN 'W' THEN 'Waiting'
					WHEN 'L' THEN 'New'
					ELSE ''
				END
		END
	ELSE IF (@LANG = 'fr' OR @LANG = 'FR')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)
					WHEN '0' THEN 'En cours'
					WHEN '1' THEN 'Bouclé'
                    WHEN '2' THEN 'Temporaire'
                    WHEN 'A' THEN 'Actif'
                    WHEN 'B' THEN 'Bloqué'
                    WHEN 'C' THEN 'En circulation'
                    WHEN 'T' THEN 'Traité'
					WHEN 'W' THEN 'En attente'
					WHEN 'L' THEN 'Nouveau'
					ELSE ''
				END
		END
	ELSE IF (@LANG = 'de' OR @LANG = 'DE')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)

					WHEN '0' THEN 'Laufend'
					WHEN '1' THEN 'Gelockt'
					WHEN '2' THEN 'Temporär'
					WHEN 'A' THEN 'Aktiv'
					WHEN 'B' THEN 'Gesperrt'
					WHEN 'C' THEN 'In Umlauf'
					WHEN 'T' THEN 'Behandelt'
					WHEN 'W' THEN 'Anhängig'
					WHEN 'L' THEN 'Neu'
					ELSE ''
				END
		END
	ELSE IF (@LANG = 'it' OR @LANG = 'IT')
		BEGIN
			SELECT @V_RESULT =
				CASE (@STATUS_CODE)

					WHEN '0' THEN 'In corso'
					WHEN '1' THEN 'Riccio'
					WHEN '2' THEN 'Temporaneo'
					WHEN 'A' THEN 'Attivo'
					WHEN 'B' THEN 'Bloccato'
					WHEN 'C' THEN 'In circolazione'
					WHEN 'T' THEN 'Trattato'
					WHEN 'W' THEN 'In attesa'
					WHEN 'L' THEN 'Nuovo'
					ELSE ''
				END
		END
	ELSE
		SET @V_RESULT = ''

	RETURN @V_RESULT
END
GO

-- /**
--  * FUNCTION *getFolderStatusDescriptions*
--  * return four folder status descriptions based on status code
--  * Input:
--  * 		status_code
--  * Output:
--  *		return descriptions based on language
--  * For example: select dbo.getFolderStatusDescriptions('C') => return
--  \"statusDescription_fr\":\"Aucun\",\"statusDescription_de\":\"Keine\",\"referencingStatusDescription_it\":\"No\",\"referencingStatusDescription_en\":\"Aucun\"
--  */
IF OBJECT_ID (N'dbo.getFolderStatusDescriptions', N'FN') IS NOT NULL
    DROP FUNCTION dbo.getFolderStatusDescriptions
GO
CREATE FUNCTION dbo.getFolderStatusDescriptions(@STATUS_CODE VARCHAR(1))
RETURNS VARCHAR(255)
WITH EXECUTE AS CALLER
AS
BEGIN
	DECLARE @V_RESULT VARCHAR(255)
	DECLARE @PREFIX_DESCRIPTION VARCHAR(18)
	SELECT @PREFIX_DESCRIPTION = 'statusDescription_'

	SELECT @V_RESULT = '\"' + @PREFIX_DESCRIPTION + 'fr\":\"' + dbo.getFldStatusDesc(@STATUS_CODE, 'fr') + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'de\":\"' + dbo.getFldStatusDesc(@STATUS_CODE, 'de') + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'it\":\"' + dbo.getFldStatusDesc(@STATUS_CODE, 'it') + '\",'
	SELECT @V_RESULT = @V_RESULT + '\"' + @PREFIX_DESCRIPTION + 'en\":\"' + dbo.getFldStatusDesc(@STATUS_CODE, 'en') + '\"'
	RETURN @V_RESULT
END
GO
