-- PART 3: CREATE STORE PROCEDURE USED TO READ ALL FOLDER INFOMATION   			--
--

-- /*	Example:
--  * 		For single exportation:
--  * 			declare @OBJECT_DESCRIPTOR VARCHAR(MAX)
--  * 			EXEC exportFolder @OBJECT_DESCRIPTOR = @OBJECT_DESCRIPTOR output,@DATABASEID = 'AZD01',@FOLDERID='PDTNAVDOC', @SEC_ENVIRONMENT='', @ENVIRONMENT='Default',@LANG='fr'
--  *			select @OBJECT_DESCRIPTOR
--  *
--  *		For mass exportation(exported data found in table TFLDDESC)
--  * 			declare @OBJECT_DESCRIPTOR VARCHAR(MAX)
--  * 			EXEC exportFolder @OBJECT_DESCRIPTOR = @OBJECT_DESCRIPTOR output,@DATABASEID = '_ALL_',@FOLDERID='_ALL_', @SEC_ENVIRONMENT='', @ENVIRONMENT='Default',@LANG='fr'
--  *
--  * 		For exporting data to file system:
--  * 			exec xp_cmdshell 'bcp "select descriptor from xlinedta003_ecm4.dbo.TFLDDESC" queryout \\vntiws03\TI-5Star\descriptors_fld.txt -w -T -r \n'
--  */
----------------------------------------------------------------------------------
-- ******************* get child folders *******************
--Notes:
-- parent category is L when one of children has L. except one case:
--	 parent category is still F when one of children has L and is LEAF.
IF EXISTS(select * FROM sys.views where name = 'T_FLD_C_LV')
	exec('DROP VIEW T_FLD_C_LV')

exec('CREATE VIEW T_FLD_C_LV AS (SELECT
			FOLDER.EZBUNU id, dbo.escapeXMLCharacters(SUBSTRING((

			SELECT '',''+ CONVERT(VARCHAR(100),FOLDER_TMP.EZBUNU)
				FROM
					ARGHREP LINK_TMP WITH (READUNCOMMITTED) ,
					AREZCPP FOLDER_TMP WITH (READUNCOMMITTED)
			WHERE
					LINK_TMP.GHAWCD = FOLDER.EZAWCD AND
					LINK_TMP.GHIUNA = FOLDER.EZF8TX AND
					FOLDER_TMP.EZAWCD = LINK_TMP.GHQ1CD AND
					FOLDER_TMP.EZF8TX = LINK_TMP.GHIWNA
			FOR XML PATH('''')
			),2,214483647)) json,
			dbo.escapeXMLCharacters((SELECT CASE
					WHEN ECM_FADDL.category IS NULL
						THEN ''''
						ELSE
							ECM_FADDL.category
					END
				FROM
					ARGHREP LINK_TMP WITH (READUNCOMMITTED) ,
					AREZCPP FOLDER_TMP WITH (READUNCOMMITTED) ,
					ECM_FADDL WITH (READUNCOMMITTED)
			WHERE
					LINK_TMP.GHAWCD = FOLDER.EZAWCD AND
					LINK_TMP.GHIUNA = FOLDER.EZF8TX AND
					FOLDER_TMP.EZAWCD = LINK_TMP.GHQ1CD AND
					FOLDER_TMP.EZF8TX = LINK_TMP.GHIWNA AND
					ECM_FADDL.folderId = FOLDER_TMP.EZBUNU
			FOR XML PATH(''''))) catalog
			FROM AREZCPP FOLDER WITH (READUNCOMMITTED) )')

-- ******************* get parent of folders *******************
IF EXISTS(select * FROM sys.views where name = 'T_FLD_P_LV')
	exec('DROP VIEW T_FLD_P_LV')

	exec('CREATE VIEW T_FLD_P_LV AS (SELECT
					FOLDER.EZBUNU id, dbo.escapeXMLCharacters(SUBSTRING((

					SELECT '',''+ CONVERT(VARCHAR(100),FOLDER_TMP.EZBUNU)
						FROM
							ARGHREP LINK_TMP WITH (READUNCOMMITTED) ,
							AREZCPP FOLDER_TMP WITH (READUNCOMMITTED)
					WHERE
							LINK_TMP.GHQ1CD= FOLDER.EZAWCD AND
							LINK_TMP.GHIWNA= FOLDER.EZF8TX AND
							FOLDER_TMP.EZAWCD = LINK_TMP.GHAWCD AND
							FOLDER_TMP.EZF8TX = LINK_TMP.GHIUNA
					FOR XML PATH('''')

					),2, 214483647)) json,
					dbo.escapeXMLCharacters(SUBSTRING((

					SELECT '','' + ''\"'' + CONVERT(VARCHAR(100),FOLDER_TMP.EZBUNU) + ''#'' + CONVERT(VARCHAR(100),LINK_TMP.GHD7NU)+ ''\"''
						FROM
							ARGHREP LINK_TMP WITH (READUNCOMMITTED) ,
							AREZCPP FOLDER_TMP WITH (READUNCOMMITTED)
					WHERE
							LINK_TMP.GHQ1CD= FOLDER.EZAWCD AND
							LINK_TMP.GHIWNA= FOLDER.EZF8TX AND
							FOLDER_TMP.EZAWCD = LINK_TMP.GHAWCD AND
							FOLDER_TMP.EZF8TX = LINK_TMP.GHIUNA AND
							LINK_TMP.GHD7NU IS NOT NULL AND GHD7NU!=''''
					FOR XML PATH('''')

					),2, 214483647)) json2

					FROM AREZCPP FOLDER WITH (READUNCOMMITTED) )')

-- ******************* get security classes of folders *******************
-- Select distinct object id from DDSECCLASS to insert into T_DB --
IF EXISTS(select * FROM sys.views where name = 'T_DB')
	exec('DROP VIEW T_DB')

-- Get security classes for folder--
IF EXISTS(select * FROM sys.views where name = 'T_FLD_DDSECCLASS')
	exec('DROP VIEW T_FLD_DDSECCLASS')

-- Get security classes 2 for folder
IF EXISTS(select * FROM sys.views where name = 'T_FLD_FLR02')
	exec('DROP VIEW T_FLD_FLR02')

IF EXISTS(select * FROM sys.views where name = 'T_FLD_SEC2')
	exec('DROP VIEW T_FLD_SEC2')

-- ******************* get comments of folders with new comment table DDrjdT*******************
IF EXISTS(select * FROM sys.views where name = 'T_FLD_COMMENT_HELPER')
	exec('DROP VIEW T_FLD_COMMENT_HELPER')

exec('CREATE VIEW T_FLD_COMMENT_HELPER AS (SELECT DD10A database_id, DD9A folder_id, ''\"'' + dbo.escapeSpecialCharacters(TSCLOB) + ''\"'''+
					' json FROM DDrjdT WITH (READUNCOMMITTED) , DDCLOB WITH (READUNCOMMITTED) WHERE DDrjdT.DDpp7A = DDCLOB.TSCID)')

IF EXISTS(select * FROM sys.views where name = 'T_FLD_COMMENT')
	exec('DROP VIEW T_FLD_COMMENT')

exec('CREATE VIEW T_FLD_COMMENT AS (
	SELECT DISTINCT database_id, folder_id,
		dbo.escapeXMLCharacters(SUBSTRING((SELECT '',''+json
			FROM T_FLD_COMMENT_HELPER t2 WITH (READUNCOMMITTED)
			WHERE t1.folder_id = t2.folder_id AND t1.database_id = t2.database_id
			FOR XML PATH('''')),2,214483647)) as json
FROM T_FLD_COMMENT_HELPER t1 WITH (READUNCOMMITTED) )')

-- ******************* get comments of folders with old comment table ARBUREP*******************
IF EXISTS(select * FROM sys.views where name = 'FCOM_HP_V1')
	exec('DROP VIEW FCOM_HP_V1')

exec('CREATE VIEW FCOM_HP_V1 AS (SELECT t1.BUAWCD database_id, t1.BUAQTX folder_id,
		        ''\"''  +dbo.escapeSpecialCharacters(dbo.escapeXMLCharacters(substring((SELECT '' ''+ RTRIM(t2.BUHPNA) FROM ARBUREP t2 WITH (READUNCOMMITTED)
		        WHERE t2.BUAWCD = t1.BUAWCD AND t2.BUAQTX = t1.BUAQTX AND t1.BUKDCD = t2.BUKDCD AND t1.BUAUVN=t2.BUAUVN AND t1.BUABDT=t2.BUABDT order by t2.BUUCNB ASC
		        FOR XML PATH ('''')),2,214483647))) +''\"''  AS json
			FROM ARBUREP AS t1 WITH (READUNCOMMITTED)
			GROUP BY t1.BUAWCD, t1.BUAQTX,t1.BUKDCD,t1.BUAUVN,t1.BUABDT)')

IF EXISTS(select * FROM sys.views where name = 'FLD_COM_V1')
	exec('DROP VIEW FLD_COM_V1')

exec('CREATE VIEW FLD_COM_V1 AS (
	SELECT DISTINCT database_id, folder_id,
		dbo.escapeXMLCharacters(SUBSTRING((SELECT '',''+json
			FROM FCOM_HP_V1 t2 WITH (READUNCOMMITTED)
			WHERE t1.folder_id = t2.folder_id AND t1.database_id = t2.database_id
			FOR XML PATH('''')),2,214483647)) as json
FROM FCOM_HP_V1 t1 WITH (READUNCOMMITTED) )')

SET QUOTED_IDENTIFIER OFF
GO
SET ANSI_NULLS ON
GO

EXEC ('IF EXISTS (SELECT * FROM sysobjects WHERE id = object_id(N''exportFolder'') AND OBJECTPROPERTY(id, N''IsProcedure'') = 1)
		BEGIN
			DROP PROCEDURE exportFolder
	END')

GO

CREATE PROCEDURE exportFolder
	@DATABASEID VARCHAR(10) = '',    		-- The identifier of database.If given value is '_ALL_', export all XECM folders
	@FOLDERID VARCHAR(40) = '',				-- The business identifier of folder.If given value is '_ALL_', export all XECM folders
	@SEC_ENVIRONMENT VARCHAR(10),			-- Temporary variable, keep it for now to avoid the change JAVA code in XOST where it called by XECMDataImportProcessor
	@ENVIRONMENT VARCHAR(500), 				--	active environment: Example: Default, XlinedtaJ30
 	@LANG VARCHAR(2) = 'en',				-- language code. Available: 'en','fr','EN','FR','de','DE'. Default: en
 	@ACTION VARCHAR(10) = 'CONTINUE',		-- An argument to let procedure continue (or not) from the last mass exportation. Available: 'RESTART' or 'CONTINUE'. Default: CONTINUE
 	@SESSION_ID VARCHAR(100) = 'ALL',		-- Unique ID to identify the indexation processor call and avoid to mix indexations
    @MAXIMUM_DESCRIPTOR_SIZE INT = 0,		-- Maximum descriptor in TFLDDESC at a time
	@OBJECT_DESCRIPTOR VARCHAR(MAX) OUTPUT	-- The object descriptors will be returned.
											-- If given @FOLDERID is '_ALL_' or given @DATABASEID is '_ALL':
											-- (mean mass indexation) ,no ouptput returns
AS
BEGIN
	--BEGIN TRY -- uncomment to enable try catch block

	-- declare variables
   -- Script version name: 3.5.0 23q1
           -- The version mentioned here doesn't necessarily match the EAR version
           -- Check the "Minimal required script version number" section within the ReadMe.html file distributed with the project to know if the procedure has to be updated
   -- Script last modificationDate(dd/mm/yyyy): 24/04/2022 09:34
	DECLARE @V_LANG VARCHAR(2) = @LANG
	DECLARE @V_ACTION VARCHAR(10)
 	DECLARE @V_CLIENTHOSTNAME VARCHAR(50) = @ENVIRONMENT
	DECLARE @V_CREATEDON VARCHAR(50)
	DECLARE @V_BYSTRING VARCHAR(50)
	DECLARE @V_CHANGEDON VARCHAR(50)
	DECLARE @V_DYNAMICSQL VARCHAR(MAX)
	DECLARE @V_SECOND_DYNAMICSQL VARCHAR(MAX)
	DECLARE @V_THIRD_DYNAMICSQL VARCHAR(MAX)
	DECLARE @V_FOURTH_DYNAMICSQL VARCHAR(MAX)
	DECLARE @V_FIFTH_DYNAMICSQL VARCHAR(MAX)
	DECLARE @V_IS_READ_SINGLE_FOLDER BIT = 0
	DECLARE @V_MAX_STRING_LENGTH int = 214483647 --max integer
	DECLARE @V_MAX_STRING_LENGTH_STR VARCHAR(100) = cast(@V_MAX_STRING_LENGTH as varchar(100)) --max integer
	DECLARE @V_ISDEBUGGING BIT = 0 -- set to 1 to make debug procedure
	DECLARE @HAS_FOLDER_TYPE BIT = 0
	DECLARE @IS_PAC_MODE BIT = 0
	DECLARE @FOLDER_TECHNICAL_ID VARCHAR(50)
	DECLARE @INDEXATION_START DATETIME
	DECLARE @PRIORITY TINYINT = 1 -- @V_ACTION = 'RESTART' OR @V_ACTION = 'CONTINUE'
	DECLARE @FOLDER_TO_INDEX INT = 1
	DECLARE @Semaphore INT
	DECLARE @TimeZone VARCHAR(50)
    EXEC master.dbo.xp_regread 'HKEY_LOCAL_MACHINE','SYSTEM\CurrentControlSet\Control\TimeZoneInformation','TimeZoneKeyName',@TimeZone OUT
	-- to increase performance, don't return the count
	SET NOCOUNT ON

	SET language English -- fix for issue invalid date (month and day is switch together in French language -- make export process always run with english)

	--set default action
	SET @V_ACTION = UPPER(@ACTION)
	IF @V_ACTION != 'RESTART' AND @V_ACTION != 'CONTINUE' AND @V_ACTION != 'PROCESSOR' AND @V_ACTION != 'EXPORTJSON'
	SET @V_ACTION = 'CONTINUE'

	-- set the flag is read single folder or read all folders( for mass indexation)
	SET @V_IS_READ_SINGLE_FOLDER = CASE WHEN @DATABASEID = '_ALL_' OR @FOLDERID = '_ALL_' THEN 0 ELSE 1 END

	-- set technical id if read single folder
	SET @FOLDER_TECHNICAL_ID = CASE WHEN @V_IS_READ_SINGLE_FOLDER = 0 THEN 0 ELSE (SELECT CONVERT(VARCHAR(50),EZBUNU) FROM AREZCPP WITH (READUNCOMMITTED) WHERE EZAWCD = @DATABASEID AND EZF8TX= @FOLDERID ) END

	-- check has folder type
	SET @HAS_FOLDER_TYPE = CASE WHEN (SELECT COUNT(*) FROM ecm_fldtyp WITH (READUNCOMMITTED)) > 0 THEN 1 ELSE 0 END

	-- check PAC mode
	SET @IS_PAC_MODE = CASE WHEN (SELECT COUNT(*) FROM ecm_pacref WITH (READUNCOMMITTED) WHERE orgId IS NOT NULL AND orgId <> '') > 0 THEN 1 ELSE 0 END

	-- begin initializing variables by the language code
	IF @V_LANG != 'en' AND @V_LANG != 'EN' AND @V_LANG != 'fr' AND @V_LANG != 'FR' AND @V_LANG != 'de' AND @V_LANG != 'DE'
		SET @V_LANG = 'en'

	IF @V_LANG = 'en' OR @V_LANG = 'EN'
		BEGIN
			SET @V_CREATEDON  = 'Created on'
			SET @V_BYSTRING		= 'by'
			SET @V_CHANGEDON  = 'Changed on'
		END

	IF  @V_LANG = 'fr' OR @V_LANG = 'FR'
		BEGIN
			SET @V_CREATEDON  = 'Créé le'
			SET @V_BYSTRING 	= 'par'
			SET @V_CHANGEDON 	= 'Modifié par'
		END

	IF  @V_LANG = 'de' OR @V_LANG = 'DE'
		BEGIN
			SET @V_CREATEDON  = 'Erstellt am'
			SET @V_BYSTRING 	= 'von'
			SET @V_CHANGEDON 	= 'Geändert von'
		END

	IF  @V_LANG = 'it' OR @V_LANG = 'IT'
		BEGIN
			SET @V_CREATEDON  = 'Creato il'
			SET @V_BYSTRING 	= 'da'
			SET @V_CHANGEDON 	= 'Modificato da'
		END

	IF(@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT NULL, '1'
	-- end initialize variables by the language code

	IF ( @V_ACTION = 'PROCESSOR' )
		BEGIN
			IF ( SELECT COUNT(*) FROM ECM_FLDIDX WITH (READUNCOMMITTED) WHERE SESSION_ID = @SESSION_ID ) > 0  -- A mass indexation is already running
				SET @FOLDER_TO_INDEX = 0
		END

	-- create work tables
	-- create folder work tables
	-- Create a table to contain list of folder ids to export
	CREATE TABLE #T_FLD_ID (
		folder_id			VARCHAR(12) 	 NULL,
		database_id 		VARCHAR(5) 		 NULL,
		business_id 		VARCHAR(40) 	 NULL,
		processOperation	VARCHAR(6)		 NULL
	)
	-- create a table containing basic information of folder
	CREATE TABLE #T_FLD_BASIC (
		folder_id			VARCHAR(40) 	 NULL,
		database_id 		VARCHAR(40) 	 NULL,
		business_id 		VARCHAR(40) 	 NULL,
		json 				VARCHAR(MAX) 	 NULL,
		json2				VARCHAR(MAX) 	 NULL,
		json3				VARCHAR(MAX) 	 NULL
	)

	CREATE TABLE #TPARFLD_HELPER (
		databaseid 			VARCHAR(5) 		 NULL,
		folderid 			VARCHAR(50) 	 NULL,
		parentdb 			VARCHAR(5) 		 NULL,
		parentfld 			VARCHAR(50)		 NULL)
	CREATE TABLE #TPARFLD_HELPER1 (
		databaseid 			VARCHAR(5) 		 NULL,
		folderid 			VARCHAR(50) 	 NULL,
		parentdb 			VARCHAR(5) 		 NULL,
		parentfld 			VARCHAR(50) 	 NULL,
		parentfld_pac 		VARCHAR(50) 	 NULL,
		parentJson 			VARCHAR(MAX) 	 NULL,
		numberofparent 		INT)
	CREATE TABLE #TPARFLD (
		databaseid 			VARCHAR(50) 	 NULL,
		folderid 			VARCHAR(50) 	 NULL,
		json 				VARCHAR(MAX) 	 NULL,
		objectKeyValuesJson VARCHAR(MAX) 	 NULL)
	CREATE TABLE #T_FLD_DDSECCLASS (
			folder_id 			VARCHAR(40) 		 NULL,
			first_sec_class 	VARCHAR(MAX)		 NULL)
	CREATE NONCLUSTERED INDEX IX_01 on #T_FLD_BASIC (folder_id)
	CREATE NONCLUSTERED INDEX IX_02 on #T_FLD_BASIC (database_id, business_id)
	CREATE NONCLUSTERED INDEX IX_06 on #TPARFLD_HELPER (databaseid,folderid)
	CREATE NONCLUSTERED INDEX IX_07 on #TPARFLD_HELPER1 (databaseid,folderid)
	CREATE NONCLUSTERED INDEX IX_08 on #TPARFLD (databaseid,folderid)
	CREATE NONCLUSTERED INDEX T_FLD_DDSECCLASS_IX1 on #T_FLD_DDSECCLASS (folder_id)
	CREATE TABLE #FOLDER_KEYWORD_ML (
		folder_id				VARCHAR(40) NULL,
		datatype_id 			CHAR(5) NULL,
		json					VARCHAR( MAX ) NULL,
		dynamic_datatype		VARCHAR(300) NULL,
		dynamic_datatype2		VARCHAR(300) NULL,
		dynamic_keyword_value	VARCHAR(300) NULL,
		lang_en					VARCHAR(5) NULL,
		value_en				VARCHAR(300) NULL,
		lang_fr					VARCHAR(5) NULL,
		value_fr				VARCHAR(300) NULL,
		lang_de					VARCHAR(5) NULL,
		value_de				VARCHAR(300) NULL,
		lang_it					VARCHAR(5) NULL,
		value_it				VARCHAR(300) NULL
	)

	CREATE NONCLUSTERED INDEX IX_01 on #FOLDER_KEYWORD_ML (folder_id)

	CREATE TABLE #FOLDER_KEYWORD (
		folder_id				VARCHAR(40) NULL,
		json					VARCHAR(MAX) NULL,
		dynamic_key_pair		VARCHAR(MAX) NULL,
		dynamic_key_pair2		VARCHAR(MAX) NULL
	)

	CREATE INDEX #FOLDER_KEYWORD_IX1 ON #FOLDER_KEYWORD
	(
		folder_id ASC
	)
	------------------------------------------------------------------------------

	--#### Begin of handle update status for children folders #############################################################################
	CREATE TABLE #TCHILDRENSFLD_HELPER (
		parentdb 			VARCHAR(5) 		 NULL,
		parentfld 			VARCHAR(50)		 NULL,
		databaseid 			VARCHAR(5) 		 NULL,
		folderid 			VARCHAR(50) 	 NULL)

	CREATE TABLE #TCHILDRENSFLD_HELPER1 (
		parentdb 			VARCHAR(5) 		 NULL,
		parentfld 			VARCHAR(50) 	 NULL,
		databaseid 			VARCHAR(5) 		 NULL,
		folderid 			VARCHAR(50) 	 NULL,
		numberofparent 		INT)

	CREATE NONCLUSTERED INDEX IX_001 on #TCHILDRENSFLD_HELPER ( databaseid, folderid )
	CREATE NONCLUSTERED INDEX IX_002 on #TCHILDRENSFLD_HELPER1 ( databaseid, folderid )

	IF ( @V_IS_READ_SINGLE_FOLDER = 1 AND @V_ACTION <> 'EXPORTJSON' )
	BEGIN
		--handle update status for children folders.
		--get first direct children
		BEGIN TRAN
			SELECT @Semaphore = id FROM semaphore_folder WITH( HOLDLOCK, TABLOCKX )

			INSERT INTO #TCHILDRENSFLD_HELPER
			SELECT DISTINCT GHAWCD PARENT_DB ,
							GHIUNA PARENT_FLD,
							GHQ1CD CHILD_DB,
							GHIWNA CHILD_FLD
			  FROM ARGHREP WITH (READUNCOMMITTED)
			 WHERE GHAWCD = @DATABASEID AND
				   GHIUNA = @FOLDERID AND
				   NOT EXISTS ( SELECT * FROM ECM_FLDIDX WHERE database_id = @DATABASEID and business_id = @FOLDERID )
		COMMIT
	END

	-- for mass importation and for indexation processor, truncate the indexation table and prepare the intervals of folders for indexation
	-- for individual indexation, the indexation table is not used

	DECLARE @batch_id int
    DECLARE @Semaphore_indexation_batch INT

	WHILE @FOLDER_TO_INDEX > 0
	BEGIN
	IF @V_IS_READ_SINGLE_FOLDER = 0
		BEGIN
			-- Mass indexation or processor indexation
			IF ( @V_ACTION = 'RESTART')
				BEGIN
					DELETE FROM TFLDDESC WHERE SESSION_ID = @SESSION_ID
					DELETE FROM INDEXATION_BATCH WHERE SESSION_ID = @SESSION_ID
				END

			IF ( @V_ACTION = 'CONTINUE' AND @SESSION_ID is NULL )
						SET @SESSION_ID = 'ALL'

			IF ( @V_ACTION = 'PROCESSOR' )
				BEGIN
					SET @PRIORITY = 2

					IF EXISTS ( SELECT * FROM ecm_idx_f WITH (READUNCOMMITTED) WHERE status = 'S' ) AND NOT EXISTS ( SELECT * FROM ecm_idx_f WITH (READUNCOMMITTED) WHERE status = 'L' ) -- The processor is stopped
						RETURN

                    BEGIN TRAN
                        -- gitlab#130 - clean up data
                        SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                        DELETE FROM TFLDDESC WHERE BATCH_ID IN (SELECT BATCH_ID FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 1)
                        DELETE FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 1
                    COMMIT

					BEGIN TRAN
						SELECT @Semaphore = id FROM semaphore_folder WITH( HOLDLOCK, TABLOCKX )

						INSERT INTO ECM_FLDIDX
						SELECT TOP 1000 @SESSION_ID, folderId, databaseId, busnsFldId, status
						  FROM ecm_idx_f
						 WHERE status IN ('R', 'M', 'N', 'C' ) AND
							   NOT EXISTS ( SELECT * FROM ECM_FLDIDX WHERE FOLDER_ID = ecm_idx_f.folderId )

						SELECT @INDEXATION_START = MAX( modifDate ) FROM ecm_idx_f, ECM_FLDIDX WHERE SESSION_ID = @SESSION_ID AND ecm_idx_f.folderId = ECM_FLDIDX.FOLDER_ID

						--handle update status for children folders.
						--get first direct children
						INSERT INTO #TCHILDRENSFLD_HELPER
						SELECT DISTINCT GHAWCD PARENT_DB ,
										GHIUNA PARENT_FLD,
										GHQ1CD CHILD_DB,
										GHIWNA CHILD_FLD
						  FROM ARGHREP WITH (READUNCOMMITTED),
							   ECM_FLDIDX
						 WHERE GHAWCD = database_id AND
							   GHIUNA = business_id AND
							   STATUS <> 'C' AND
							   SESSION_ID = @SESSION_ID

						SELECT @FOLDER_TO_INDEX = COUNT(*) FROM ecm_idx_f WHERE status IN ( 'R', 'M', 'N', 'C' ) AND NOT EXISTS ( SELECT * FROM ECM_FLDIDX WHERE folderId = FOLDER_ID )
					COMMIT
				END
					ELSE SET @FOLDER_TO_INDEX = 0

			IF ( @V_ACTION = 'RESTART' OR @V_ACTION = 'PROCESSOR' )
				BEGIN
					DECLARE @FIRST_FOLDER_TECH_ID numeric(15)
					DECLARE @LAST_FOLDER_TECH_ID  numeric(15)
					DECLARE @NUM_OF_FOLDER_IN_BATCH	int
					DECLARE @FOLDER_POSITION bigint

					SELECT @FIRST_FOLDER_TECH_ID = null
					SELECT @FOLDER_POSITION = 1
					SELECT @NUM_OF_FOLDER_IN_BATCH = 1000

					IF ( @V_ACTION = 'RESTART' )
						DECLARE folder_cursor CURSOR FOR SELECT EZBUNU FROM AREZCPP ORDER BY EZBUNU
					ELSE
 						DECLARE folder_cursor CURSOR FOR SELECT FOLDER_ID FROM ECM_FLDIDX WHERE ECM_FLDIDX.SESSION_ID = @SESSION_ID ORDER BY FOLDER_ID

					OPEN folder_cursor

					FETCH folder_cursor INTO @LAST_FOLDER_TECH_ID

					WHILE @@FETCH_STATUS = 0
						BEGIN
							IF ( @FOLDER_POSITION = @NUM_OF_FOLDER_IN_BATCH )
								BEGIN
									INSERT INTO INDEXATION_BATCH (SESSION_ID, BATCH_START, BATCH_END, PRIORITY, COMPUTED, SOLR_STATUS, HOST_NAME, TIMESTAMP ) VALUES ( @SESSION_ID, CAST(@FIRST_FOLDER_TECH_ID AS VARCHAR(12)), CAST(@LAST_FOLDER_TECH_ID AS VARCHAR(12)), @PRIORITY, 0, 0, null, null )

									SELECT @FOLDER_POSITION = 0

									FETCH folder_cursor INTO  @LAST_FOLDER_TECH_ID

									SELECT @FIRST_FOLDER_TECH_ID = @LAST_FOLDER_TECH_ID

									SELECT @LAST_FOLDER_TECH_ID = null

									SELECT @FOLDER_POSITION = @FOLDER_POSITION + 1
								END
							ELSE
								BEGIN
									IF ( @FIRST_FOLDER_TECH_ID is null )
										SELECT @FIRST_FOLDER_TECH_ID = @LAST_FOLDER_TECH_ID

									FETCH folder_cursor INTO @LAST_FOLDER_TECH_ID

									SELECT @FOLDER_POSITION = @FOLDER_POSITION + 1
								END
						END

					CLOSE folder_cursor
					DEALLOCATE folder_cursor

					IF (@FIRST_FOLDER_TECH_ID is not null AND @LAST_FOLDER_TECH_ID is not null)
						INSERT INTO INDEXATION_BATCH (SESSION_ID, BATCH_START, BATCH_END, PRIORITY, COMPUTED, SOLR_STATUS, HOST_NAME, TIMESTAMP ) VALUES ( @SESSION_ID,CAST(@FIRST_FOLDER_TECH_ID AS VARCHAR(12)), CAST(@LAST_FOLDER_TECH_ID AS VARCHAR(12)), @PRIORITY, 0, 0, null, null )
				END
				IF(@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT NULL, '2'
		END
			ELSE SET @FOLDER_TO_INDEX = 0

	IF ( @V_ACTION <> 'EXPORTJSON' )
		BEGIN
			-- Set value for column numberofparent #TCHILDRENSFLD_HELPER
			INSERT INTO #TCHILDRENSFLD_HELPER1
			SELECT DISTINCT parentdb, parentfld, databaseid, folderid, 1
			  FROM #TCHILDRENSFLD_HELPER

			-- get all children folders
			BEGIN
				DECLARE @instancesToFetchVar int
				SELECT @instancesToFetchVar = 1
				WHILE ( @instancesToFetchVar = 1 )
				BEGIN
					IF EXISTS(SELECT numberofparent FROM #TCHILDRENSFLD_HELPER1 WHERE numberofparent = 1)
					BEGIN
						TRUNCATE TABLE #TCHILDRENSFLD_HELPER

						INSERT INTO #TCHILDRENSFLD_HELPER
						SELECT DISTINCT databaseid, folderid, GHQ1CD, GHIWNA
						  FROM #TCHILDRENSFLD_HELPER1
						  JOIN ARGHREP WITH (READUNCOMMITTED) ON databaseid = GHAWCD AND folderid = GHIUNA
						 WHERE numberofparent = 1

						DELETE #TCHILDRENSFLD_HELPER
						  FROM #TCHILDRENSFLD_HELPER1
						 WHERE #TCHILDRENSFLD_HELPER.parentdb = #TCHILDRENSFLD_HELPER1.parentdb AND
							   #TCHILDRENSFLD_HELPER.parentfld = #TCHILDRENSFLD_HELPER1.parentfld AND
							   #TCHILDRENSFLD_HELPER.databaseid = #TCHILDRENSFLD_HELPER1.databaseid AND
							   #TCHILDRENSFLD_HELPER.folderid = #TCHILDRENSFLD_HELPER1.folderid

						UPDATE #TCHILDRENSFLD_HELPER1 SET numberofparent = 0 WHERE numberofparent = 1

						INSERT INTO #TCHILDRENSFLD_HELPER1
						SELECT DISTINCT parentdb, parentfld, databaseid, folderid, 1
						  FROM #TCHILDRENSFLD_HELPER TCHILDRENSFLD_HELPER

						UPDATE #TCHILDRENSFLD_HELPER1 SET numberofparent = 0 WHERE numberofparent = 1 AND parentdb = databaseid AND parentfld = folderid

						SELECT @instancesToFetchVar = 1
					END
					ELSE
						SELECT @instancesToFetchVar = 0
				END
			END

			BEGIN TRAN
				SELECT @Semaphore = id FROM semaphore_folder WITH( HOLDLOCK, TABLOCKX )

				-- update indexation status for all children folders
				UPDATE ecm_idx_f SET status = 'C' FROM #TCHILDRENSFLD_HELPER1 WHERE ecm_idx_f.databaseId = #TCHILDRENSFLD_HELPER1.databaseid AND ecm_idx_f.busnsFldId = #TCHILDRENSFLD_HELPER1.folderid
			COMMIT
		END
	--#### End of handle update status for children folders #############################################################################

	--	process each batch
	DECLARE @batch_start VARCHAR(400)
	DECLARE @batch_end VARCHAR(400)
	DECLARE @FETCH_STATUS INT
    DECLARE @REMAIN_PROCESSING_DESCRIPOR INT

	IF @V_IS_READ_SINGLE_FOLDER = 0
		BEGIN
			IF ( @V_ACTION = 'PROCESSOR' )
				DECLARE batch_cursor CURSOR LOCAL FOR
					SELECT BATCH_ID, BATCH_START, BATCH_END FROM INDEXATION_BATCH WHERE SESSION_ID = @SESSION_ID and PRIORITY >= 2 and COMPUTED = 0 FOR UPDATE OF COMPUTED
			ELSE
				DECLARE batch_cursor CURSOR LOCAL FOR
					SELECT BATCH_ID, BATCH_START, BATCH_END FROM INDEXATION_BATCH WHERE SESSION_ID = @SESSION_ID AND PRIORITY = 1 and COMPUTED = 0 ORDER BY BATCH_ID DESC FOR UPDATE OF COMPUTED

			OPEN batch_cursor

			FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end

			SET @FETCH_STATUS = @@FETCH_STATUS

		END
	ELSE
		BEGIN
			DELETE FROM TFLDDESC WHERE SESSION_ID = @SESSION_ID
			SET @batch_start = (SELECT CAST(EZBUNU AS CHAR(12)) FROM AREZCPP WITH (READUNCOMMITTED) WHERE EZAWCD = @DATABASEID AND EZF8TX = @FOLDERID)
			SET @batch_end = @batch_start
			SET @FETCH_STATUS = 0
		END

	WHILE @FETCH_STATUS = 0
		BEGIN
			if (@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '3'

            IF @V_IS_READ_SINGLE_FOLDER = 0 AND @MAXIMUM_DESCRIPTOR_SIZE > 0
                BEGIN
                    SELECT @REMAIN_PROCESSING_DESCRIPOR = count(*) FROM TFLDDESC WITH (READUNCOMMITTED)
                    WHILE @REMAIN_PROCESSING_DESCRIPOR > @MAXIMUM_DESCRIPTOR_SIZE
                        BEGIN
                            WAITFOR DELAY '00:00:30'

                            BEGIN TRAN
                                -- gitlab#203
                                SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                                IF ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '3a1'

                                DELETE FROM TFLDDESC WHERE BATCH_ID IN (SELECT BATCH_ID FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 1)
                                DELETE FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 1 AND ISNUMERIC(BATCH_START) = 1
                            COMMIT

                            SELECT @REMAIN_PROCESSING_DESCRIPOR = count(*) FROM TFLDDESC WITH (READUNCOMMITTED)
                        END
                END

			TRUNCATE TABLE #TPARFLD_HELPER1
			TRUNCATE TABLE #TPARFLD_HELPER
			TRUNCATE TABLE #TPARFLD
			TRUNCATE TABLE #T_FLD_DDSECCLASS
			TRUNCATE TABLE #T_FLD_BASIC
			TRUNCATE TABLE #T_FLD_ID
			TRUNCATE TABLE #FOLDER_KEYWORD_ML
			TRUNCATE TABLE #FOLDER_KEYWORD

	--Insert list folder Id need to be exported into temporary table
	IF ( @V_IS_READ_SINGLE_FOLDER = 0 )
		BEGIN
			IF ( @V_ACTION = 'PROCESSOR' )
				INSERT INTO #T_FLD_ID
				SELECT DISTINCT FOLDER_ID,database_id,business_id, CASE WHEN STATUS = 'N' THEN 'CREATE' ELSE 'UPDATE' END AS STATUS FROM ECM_FLDIDX WHERE SESSION_ID = @SESSION_ID AND FOLDER_ID >= @batch_start AND FOLDER_ID <= @batch_end
			ELSE -- @V_ACTION = 'RESTART' OR 'CONTINUE'
				INSERT INTO #T_FLD_ID
				SELECT DISTINCT EZBUNU, EZAWCD, EZF8TX, 'UPDATE' AS STATUS FROM AREZCPP WITH (READUNCOMMITTED) WHERE EZBUNU >= @batch_start AND EZBUNU <= @batch_end
		END
	ELSE
		BEGIN
			INSERT INTO #T_FLD_ID
			SELECT DISTINCT EZBUNU, EZAWCD, EZF8TX, 'UPDATE' AS STATUS FROM AREZCPP WITH (READUNCOMMITTED) WHERE EZBUNU >= @batch_start AND EZBUNU <= @batch_end
		END

	if (@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '4'

	-- begin handling parent folder descriptors
	-- get first parent folders which are in folder table
	IF ( @V_ACTION <> 'EXPORTJSON' )
	BEGIN
		INSERT INTO #TPARFLD_HELPER
		SELECT DISTINCT GHQ1CD CHILD_DB, GHIWNA CHILD_FLD, GHAWCD PARENT_DB, GHIUNA PARENT_FLD
		  FROM ARGHREP FOLDER_LINK WITH (READUNCOMMITTED), #T_FLD_ID FOLDER_ID
		 WHERE FOLDER_LINK.GHQ1CD = FOLDER_ID.database_id AND FOLDER_LINK.GHIWNA = FOLDER_ID.business_id

		IF (@V_IS_READ_SINGLE_FOLDER = 1)
		BEGIN
			-- update indexation status for direct parents folders if the folder is not in status C
			BEGIN TRAN
				SELECT @Semaphore = id FROM semaphore_folder WITH( HOLDLOCK, TABLOCKX )

				UPDATE ecm_idx_f SET status = 'C'
				FROM (SELECT parentdb, parentfld
						FROM ecm_idx_f JOIN #TPARFLD_HELPER on ecm_idx_f.databaseId = #TPARFLD_HELPER.databaseid AND ecm_idx_f.busnsFldId = #TPARFLD_HELPER.folderid and status <> 'C') parentfld
				WHERE ecm_idx_f.databaseId = parentfld.parentdb AND ecm_idx_f.busnsFldId = parentfld.parentfld
			COMMIT
		END
	END

	-- get json of parent folder in above table #TPARFLD_HELPER
	INSERT INTO #TPARFLD_HELPER1
		SELECT DISTINCT databaseid,TPARFLD_HELPER.folderid , parentdb ,parentfld ,
		CASE
			WHEN
				left(parentfld, 3) = TFLDTYP_HELPER.typeID
			THEN
				RTRIM(substring(parentfld,4,40))
			ELSE
				RTRIM(parentfld)
		END parentfld_pac,
		'{'+
		CASE
			WHEN @HAS_FOLDER_TYPE = 0
			THEN dbo.getDefaultDescriptions('type_', '') + ','
			ELSE
				CASE
					WHEN
						TFLDTYP_HELPER0.typeNme IS NOT NULL AND TFLDTYP_HELPER0.type IS NOT NULL
					THEN
						'\"typeId\":\"'+TFLDTYP_HELPER0.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER0.typeID+'\",' +
						CASE
							WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
								THEN dbo.getDefaultDescriptions('type_', TFLDTYP_HELPER0.type)
							ELSE REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
						END + ','
					WHEN @IS_PAC_MODE = 1
					THEN
						CASE
							WHEN
								TFLDTYP_HELPER.typeNme IS NOT NULL AND TFLDTYP_HELPER.type IS NOT NULL
							THEN
								'\"typeId\":\"'+TFLDTYP_HELPER.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER.typeID+'\",' +
								CASE
									WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
										THEN dbo.getDefaultDescriptions('type_', TFLDTYP_HELPER.type)
									ELSE REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
								END + ','
							WHEN
								TFLDTYP_HELPER2.typeNme IS NOT NULL AND TFLDTYP_HELPER2.type IS NOT NULL
							THEN
								'\"typeId\":\"'+TFLDTYP_HELPER2.typeNme+'\",\"pacTypeId\":\"\",' +
								CASE
									WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
										THEN dbo.getDefaultDescriptions('type_', TFLDTYP_HELPER2.type)
									ELSE REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
								END + ','
							WHEN
								TFLDTYP_HELPER3.typeNme IS NOT NULL AND TFLDTYP_HELPER3.type IS NOT NULL
							THEN
								'\"typeId\":\"'+TFLDTYP_HELPER3.typeNme+'\",\"pacTypeId\":\"\",' +
								CASE
									WHEN folderType_param.formatted_json IS NULL OR folderType_param.formatted_json = ''
										THEN dbo.getDefaultDescriptions('type_', TFLDTYP_HELPER3.type)
									ELSE REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
								END + ','
						ELSE
							'\"typeId\":\"\",\"pacTypeId\":\"\",' + dbo.getDefaultDescriptions('type_', 'Facture') + ','
						END
					ELSE
						dbo.getDefaultDescriptions('type_', '') + ','
				END
			END
					+'\"technicalId\":\"'+UPPER(@ENVIRONMENT) + '-' + convert(varchar(100),EZBUNU)+'\",\"id\":\"'+convert(varchar(100),EZBUNU)+'\",\"databaseId\":\"' + RTRIM(parentdb) + '\",\"businessId\":\"' +
					CASE
						WHEN
							left(parentfld, 3) = TFLDTYP_HELPER.typeID
						THEN
							RTRIM(substring(dbo.escapeSpecialCharacters(parentfld),4,40))
						ELSE
							RTRIM(dbo.escapeSpecialCharacters(parentfld))
					END
					+ '\",\"pacId\":\"' + ISNULL(PACREF_HELPERV.PACID,ISNULL(TPACREF_DB.PacId,''))
					+ '\",\"organizationId\":\"' + ISNULL(PACREF_HELPERV.orgId,ISNULL(TPACREF_DB.OrgId,''))
					+ '\",' +
					CASE
						WHEN organization_param.formatted_json is null or organization_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('organizationDescription_', dbo.escapeSpecialCharacters(ISNULL(PACREF_HELPERV.orgDesc, ISNULL(TPACREF_DB.OrgDesc,''))))
						ELSE
							REPLACE(dbo.escapeSpecialCharacters(organization_param.formatted_json), '\\\"', '\"')
					END
					+ ',' +
					CASE
						WHEN database_param.formatted_json is null or database_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('databaseDescription_', CASE
																						WHEN PACREF_HELPERV.PacDesc IS NULL
																							THEN
																								CASE
																									WHEN TPACREF_DB.PacDesc IS NULL
																										THEN dbo.escapeSpecialCharacters(RTRIM(AOAONA))
																									ELSE dbo.escapeSpecialCharacters(RTRIM(TPACREF_DB.PacDesc))
																								END
																						ELSE dbo.escapeSpecialCharacters(RTRIM(PACREF_HELPERV.PacDesc))
																					END)
						ELSE
							REPLACE(dbo.escapeSpecialCharacters(database_param.formatted_json), '\\\"', '\"')
					END
					+ ',' +
					dbo.getMultipleLanguageFields('description_',
										-- fr
										dbo.formatFolderDescription(CASE
																		WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
																			THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
																		ELSE
																			REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(folderType_param.formatted_json, 'type_', 'fr')), '\\\"', '\"')
																	END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
												ELSE CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
												ELSE CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
												ELSE CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN @IS_PAC_MODE = 0 AND left(EZCANA, 5) <> '!USER'
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZCANA)))
												ELSE ''
											END
											, '#V_FLDDESC#',' - '),
										-- de
										dbo.formatFolderDescription(CASE
																		WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
																			THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
																		ELSE
																			REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(folderType_param.formatted_json, 'type_', 'de')), '\\\"', '\"')
																	END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
												ELSE CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
												ELSE CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
												ELSE CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN @IS_PAC_MODE = 0 AND left(EZCANA, 5) <> '!USER'
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZCANA)))
												ELSE ''
											END
											, '#V_FLDDESC#',' - '),
										-- it
										dbo.formatFolderDescription(CASE
																		WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
																			THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
																		ELSE
																			REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(folderType_param.formatted_json, 'type_', 'it')), '\\\"', '\"')
																	END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
												ELSE CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
												ELSE CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
											END
											+ '#V_FLDDESC#' +
											CASE
												WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
												THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
												ELSE CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
											END
