					+
					CASE WHEN DD8gaA is null OR DD8gaA='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(DD8gaA)) + ' ' END +
					CASE WHEN DD8gbA is null OR DD8gbA='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(DD8gbA)) + ' ' END +
					CASE WHEN DD8gcA is null OR DD8gcA='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(DD8gcA)) END +
					'\",\"isBlocked\":\"'+
					CASE WHEN additionalAttribute.isBlocked IS NOT NULL AND additionalAttribute.isBlocked = '1'
					THEN 'true'
