																									THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
																								ELSE
																									REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(folderType_param.formatted_json, 'type_', 'it')), '\\\"', '\"')
																							END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN  DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
																				THEN
																					RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
																				ELSE
																					CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
																				THEN
																					RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
																				ELSE
																					CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
																				THEN
																					RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
																				ELSE
																					CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN @IS_PAC_MODE = 0 AND left(EZCANA, 5) <> '!USER'
																				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZCANA)))
																				ELSE ''
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN
																					left(parentfld, 3) = TFLDTYP_HELPER.typeID
																				THEN
																					RTRIM(substring(dbo.escapeSpecialCharacters(parentfld),4,40))
																				ELSE
																					RTRIM(dbo.escapeSpecialCharacters(parentfld))
																			END
																			, '#V_FLDDESC#',' - '),
																	-- en
																	dbo.formatFolderDescription(CASE
																									WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
																										THEN RTRIM(ISNULL(TFLDTYP_HELPER0.type,case when @IS_PAC_MODE = 1 then ISNULL(TFLDTYP_HELPER.type,ISNULL(TFLDTYP_HELPER2.type,ISNULL(TFLDTYP_HELPER3.type,'Facture'))) ELSE '' END))
																									ELSE
																										REPLACE(dbo.escapeSpecialCharacters(dbo.getDescriptionByLanguage(folderType_param.formatted_json, 'type_', 'en')), '\\\"', '\"')
																								END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
																				THEN
																					RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
																				ELSE
																					CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
																				THEN
																					RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
																				ELSE
																					CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
																				THEN
																					RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
																				ELSE
																					CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN @IS_PAC_MODE = 0 AND left(EZCANA, 5) <> '!USER'
																				THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZCANA)))
																				ELSE ''
																			END
																			+ '#V_FLDDESC#' +
																			CASE
																				WHEN
																					left(parentfld, 3) = TFLDTYP_HELPER.typeID
																				THEN
																					RTRIM(substring(dbo.escapeSpecialCharacters(parentfld),4,40))
																				ELSE
																					RTRIM(dbo.escapeSpecialCharacters(parentfld))
																			END
																			, '#V_FLDDESC#',' - '))
												+
												',\"searchText\":\"' +
												CASE WHEN EZH0TX IS NOT NULL AND DATALENGTH(EZH0TX) >= 3 AND left(EZH0TX, 3) = TFLDTYP_HELPER.typeID
													THEN rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZH0TX, DATALENGTH(EZH0TX)- 3))))+ ' '
													ELSE
													CASE WHEN EZH0TX is null OR EZH0TX='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZH0TX)) + ' ' END
												END
												+
												CASE WHEN DD8gaA is null OR DD8gaA='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(DD8gaA)) + ' ' END +
												CASE WHEN DD8gbA is null OR DD8gbA='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(DD8gbA)) + ' ' END +
												CASE WHEN DD8gcA is null OR DD8gcA='' THEN '' ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(DD8gcA)) END +
												'\",\"isBlocked\":\"'+
												CASE WHEN additionalAttribute.isBlocked IS NOT NULL AND additionalAttribute.isBlocked = '1'
												THEN 'true'
												ELSE 'false'
												END
												+ '\",\"businessDataRuleId\":\"'+ ISNULL(CONVERT(VARCHAR(10), additionalAttribute.ruleId), '')
												+'\"}',1
				FROM #TPARFLD_HELPER TPARFLD_HELPER JOIN AREZCPP  WITH (READUNCOMMITTED) ON EZAWCD = parentdb AND EZF8TX =parentfld
				JOIN ARAOREP  WITH (READUNCOMMITTED) ON AREZCPP.EZAWCD = ARAOREP.AOAWCD
				LEFT JOIN ARAJREP  WITH (READUNCOMMITTED) ON AREZCPP.DD46A = ARAJREP.AJAOCD
				LEFT JOIN PACREF_HELPERV  WITH (READUNCOMMITTED) ON PACREF_HELPERV.BASE = AREZCPP.EZAWCD AND (PACREF_HELPERV.depId = AREZCPP.DD46A OR
									(PACREF_HELPERV.depId is null and  AREZCPP.DD46A ='') OR
									(PACREF_HELPERV.depId = '' and  AREZCPP.DD46A is null))
				LEFT JOIN ECM_FADDL additionalAttribute  WITH (READUNCOMMITTED) ON convert(char(20),AREZCPP.EZBUNU) = additionalAttribute.folderId
				LEFT JOIN TPACREF_DB TPACREF_DB  WITH (READUNCOMMITTED) ON TPACREF_DB.baseId = AREZCPP.EZAWCD
				LEFT JOIN FLDTYPV TFLDTYP_HELPER0  WITH (READUNCOMMITTED) ON additionalAttribute.folderType = TFLDTYP_HELPER0.typeNme AND
										AREZCPP.EZAWCD = TFLDTYP_HELPER0.base  AND
										additionalAttribute.folderType IS NOT NULL AND additionalAttribute.folderType <> ''
				LEFT JOIN FLDTYPV TFLDTYP_HELPER  WITH (READUNCOMMITTED) ON
											DATALENGTH(AREZCPP.EZF8TX) >= 3 AND
											left(AREZCPP.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
											AREZCPP.EZAWCD = TFLDTYP_HELPER.base
				LEFT JOIN FLDTYPV TFLDTYP_HELPER2  WITH (READUNCOMMITTED) ON
													TFLDTYP_HELPER.base IS NULL AND -- NOT FOUND BY TYPEID
													AREZCPP.EZAWCD = TFLDTYP_HELPER2.base AND
													DATALENGTH(AREZCPP.EZB7NA) >= 6 AND
													LEFT(AREZCPP.EZB7NA, 1) = '!' AND
													LEFT(AREZCPP.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
				LEFT JOIN FLDTYPV TFLDTYP_HELPER3  WITH (READUNCOMMITTED) ON
													TFLDTYP_HELPER.base IS NULL AND 				-- NOT FOUND BY TYPEID
													TFLDTYP_HELPER2.base IS NULL AND 	-- NOT FOUND BY PREFIXDS1
													DATALENGTH(AREZCPP.EZB7NA) >= 1 AND
													LEFT(AREZCPP.EZB7NA, 1) != '!' AND
													AREZCPP.EZAWCD = TFLDTYP_HELPER3.base AND
													TFLDTYP_HELPER3.typeID =''
				LEFT JOIN ecm_param organization_param WITH (READUNCOMMITTED) ON organization_param.param_id = TPACREF_DB.OrgId and organization_param.param_type = 'ORGANIZATION'
				LEFT JOIN ecm_param database_param WITH (READUNCOMMITTED) ON database_param.param_id = AREZCPP.EZAWCD and database_param.param_type = 'DATABASE'
				LEFT JOIN ecm_param folderType_param WITH (READUNCOMMITTED) ON folderType_param.param_id = ISNULL(TFLDTYP_HELPER0.typeNme,CASE WHEN @IS_PAC_MODE = 1 THEN ISNULL(TFLDTYP_HELPER.typeNme,ISNULL(TFLDTYP_HELPER2.typeNme,ISNULL(TFLDTYP_HELPER3.typeNme,'Facture'))) ELSE '' END) and folderType_param.param_type = 'FOLDERTYPE'
				UPDATE #TPARFLD_HELPER1 SET numberofparent = 0 WHERE numberofparent = 1 AND parentdb = databaseid AND parentfld = folderid
				SELECT @instancesToFetch = 1
			END
			ELSE
				SELECT @instancesToFetch = 0
		END
	END
	if (@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '6'

	TRUNCATE TABLE #TPARFLD_HELPER
	
	-- correction armand du 02/03/2023
	INSERT INTO #TPARFLD
            select databaseId,
				  folderid,
				  STRING_AGG( CONVERT( VARCHAR(MAX), parentJson ), ',' ),
				  STRING_AGG( '"#PARENTFOLDER#' + CONVERT( VARCHAR(MAX), parentdb ) + '#' + parentfld_pac + '"', ',' )
			from #TPARFLD_HELPER1 t1
            group by databaseId, folderid
	-- fin correction  armand du 02/03/2023
	
	TRUNCATE TABLE #TPARFLD_HELPER1

	if (@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '7'
	-- end handle parent folder descriptors

	-- ******************* get folder/document security class and insert to temporary table**********************
	INSERT INTO #T_FLD_DDSECCLASS
		SELECT dsc.obj_id,
		substring((SELECT distinct ',"'+sec_class +'"'
			FROM DDSECCLASS dsc2 WITH (READUNCOMMITTED)
			WHERE dsc.obj_id = dsc2.obj_id and dsc2.obj_type= 'FLR'
			FOR XML PATH('')),2,214483647) flr
		FROM
				DDSECCLASS dsc WITH (READUNCOMMITTED),
				AREZCPP folder WITH (READUNCOMMITTED)
		WHERE
				dsc.obj_id = folder.EZBUNU
				and obj_type in ('FLR')
		group by  dsc.obj_id

	if (@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '8'
	-- ******************* end get folder/document security class and inert to temprary table**********************

	if (@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '9'
	-- ******************* end get folder security class  base on object type TFLR and folder type id and inert to temporary table**********************

	-- ******************* build folder keywords (type: Folder)*******************
	CREATE TABLE #KWDEV_FLD
	(
		kwdid VARCHAR(5),
		kwdlbl VARCHAR(200)
	)

	INSERT INTO #KWDEV_FLD SELECT t1.kwdid, (select top(1) t2.KwdLbl from ecm_KwDe t2  WITH (READUNCOMMITTED) where t1.kwdid=t2.kwdid) kwdlbl FROM KWDEIDV t1 WITH (READUNCOMMITTED)

	CREATE NONCLUSTERED INDEX #KWDEV_IX1 ON #KWDEV_FLD
	(
		kwdid ASC,
		kwdlbl ASC
	)

	-- build folder keywords in ECM_FKWD table
	INSERT INTO #FOLDER_KEYWORD_ML
		SELECT
			fkw.technical_id,
			fkw.datatype_id,
			'"#' + RTRIM(fkw.datatype_id) + '#' +
			RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)))
			+ '"' +
			CASE WHEN ARALREP.ALAUCD = '01'
				THEN ',"#' + RTRIM(fkw.datatype_id) + '#' + CAST((CAST(dbo.escapeSpecialCharacters(fkw.value) AS BIGINT)) AS VARCHAR) + '","' + CAST((CAST(dbo.escapeSpecialCharacters(fkw.value) AS BIGINT)) AS VARCHAR)+'"'
				ELSE ''
			END
			+ ',"{' +
			CASE WHEN KWDEV.kwdlbl is null
				THEN dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(dataType_param.formatted_json), '\\\"', '"'), dbo.escapeSpecialCharacters(ARALREP.ALAMNA))
				ELSE dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(dataType_param.formatted_json), '\\\"', '"'), dbo.escapeSpecialCharacters(KWDEV.kwdlbl))
			END
			+ ',\"value\":\" ' + -- add a space character before keyword value to search with fullText index
			RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)))
			-- add a space character after keyword value to search with fullText index
			+ ' \"}","' + isnull(ARALREP.ALAUCD,'') + '"' json
			,
			CASE
				WHEN ARALREP.ALATCD IS NOT NULL
				THEN
					CASE
						WHEN  ARALREP.ALAUCD ='01'
						THEN  '\"Keyword.' + RTRIM(ARALREP.ALATCD) + '_lng\"'
						WHEN  ARALREP.ALAUCD ='02'
						THEN  '\"Keyword.' + RTRIM(ARALREP.ALATCD) + '_str\"'
						WHEN  CAST(ARALREP.ALAUCD AS INT) > 2 AND CAST(ARALREP.ALAUCD AS INT) < 9
						THEN  '\"Keyword.' + RTRIM(ARALREP.ALATCD) + '_dat\"'
						WHEN  CAST(ARALREP.ALAUCD AS INT) = 9
						THEN  '\"Keyword.' + RTRIM(ARALREP.ALATCD) + '_cur\"'
						ELSE ''
					END
				ELSE ''
			END dynamic_datatype,
			CASE
				WHEN ARALREP.ALATCD IS NOT NULL
				THEN
					CASE
						WHEN  ARALREP.ALAUCD ='01'
						THEN  '\"Keyword' + RTRIM(ARALREP.ALATCD) + '_lng\"'
						WHEN  ARALREP.ALAUCD ='02'
						THEN  '\"Keyword' + RTRIM(ARALREP.ALATCD) + '_str\"'
						WHEN  CAST(ARALREP.ALAUCD AS INT) > 2 AND CAST(ARALREP.ALAUCD AS INT) < 9
						THEN  '\"Keyword' + RTRIM(ARALREP.ALATCD) + '_dat\"'
						WHEN  CAST(ARALREP.ALAUCD AS INT) = 9
						THEN  '\"Keyword' + RTRIM(ARALREP.ALATCD) + '_cur\"'
						ELSE ''
					END
				ELSE ''
			END dynamic_datatype2,
			CASE WHEN ARALREP.ALATCD IS NOT NULL
				THEN
					CASE WHEN ARALREP.ALAUCD = '01'
							THEN '\"' + CAST(CAST(fkw.value AS NUMERIC) AS VARCHAR(20)) + '\"'
						WHEN CAST(ARALREP.ALAUCD AS INT) > 2 AND CAST(ARALREP.ALAUCD AS INT) < 9
							THEN '\"' + dbo.convertKeywordDate(fkw.value, ARALREP.ALAUCD) + '\"'
						ELSE '\"' + dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)) + '\"'
					END
			END	dynamic_keyword_value,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
				THEN 'en'
				ELSE ''
			END AS lang_en,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN '\"' + dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)) + '\"'
				ELSE ''
			END AS value_en,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN 'fr'
				ELSE ''
			END AS lang_fr,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN '\"' + dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)) + '\"'
				ELSE ''
			END AS value_fr,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN 'de'
				ELSE ''
			END AS lang_de,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN '\"' + dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)) + '\"'
				ELSE ''
			END AS value_de,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN 'it'
				ELSE ''
			END AS lang_it,
			CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD = '02'
				THEN '\"' + dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)) + '\"'
				ELSE ''
			END AS value_it
		FROM ECM_FKWD fkw WITH (READUNCOMMITTED)
			LEFT JOIN ecm_param dataType_param WITH (READUNCOMMITTED) ON dataType_param.param_id = fkw.datatype_id and dataType_param.param_type = 'DATATYPE'
			LEFT JOIN #KWDEV_FLD KWDEV ON fkw.datatype_id = KWDEV.kwdid,
			ARALREP WITH (READUNCOMMITTED),
			#T_FLD_ID FOLDER_ID
		WHERE ARALREP.ALATCD = fkw.datatype_id and fkw.is_close_value = 0 AND FOLDER_ID.folder_id = fkw.technical_id

	-- build folder keywords in ECM_KWLST table
	if EXISTS (SELECT top 1 is_close_value FROM ECM_FKWD WITH (READUNCOMMITTED) WHERE is_close_value = 1 AND technical_id IN (SELECT folder_id FROM #T_FLD_ID))
		INSERT INTO #FOLDER_KEYWORD_ML
			SELECT
				fkw.technical_id,
				clkw.kwid,
				CASE WHEN clkw.lstDesc IS NOT NULL
					THEN
						CASE WHEN clkw.formatted_json IS NULL OR clkw.formatted_json =''
							THEN
								-- add space to support full text search
								'"#' + RTRIM(clkw.kwid) + '#' + '{' + dbo.getDefaultDescriptions('description_', ' ' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(clkw.lstDesc))) + ' ') + '}",'
							ELSE
								'"#' + RTRIM(clkw.kwid) + '#' + '{' + dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(clkw.formatted_json), '\\\"', '"'), dbo.escapeSpecialCharacters(clkw.lstDesc)) + '}",'
						END
					ELSE ''
				END
				+ '"#' + RTRIM(clkw.kwid) + '#' +
				CASE WHEN clkw.lstDesc IS NOT NULL
					THEN
						RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(clkw.lstid)))
					ELSE RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)))
				END
				+ '","{' +
				CASE WHEN KWDEV.kwdlbl is null
					THEN dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(dataType_param.formatted_json), '\\\"', '"'), dbo.escapeSpecialCharacters(ARALREP.ALAMNA))
					ELSE dbo.getDataTypeDescriptions(REPLACE(dbo.escapeSpecialCharacters(dataType_param.formatted_json), '\\\"', '"'), dbo.escapeSpecialCharacters(KWDEV.kwdlbl))
				END
				+ ',\"value\":\" ' + -- add a space character before keyword value to search with fullText index
				CASE WHEN clkw.lstid IS NOT NULL
					THEN dbo.escapeSpecialCharacters(clkw.lstid)
					ELSE RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value)))
				END
				+ ' \"}","' + isnull(ARALREP.ALAUCD,'') + '"' json
				,
				CASE
					WHEN ARALREP.ALATCD IS NOT NULL
					THEN
						CASE WHEN  ARALREP.ALAUCD ='02'
							THEN  '\"Keyword.' + RTRIM(ARALREP.ALATCD) + '_str\"'
							ELSE ''
						END
					ELSE ''
				END dynamic_datatype,
				CASE
					WHEN ARALREP.ALATCD IS NOT NULL
					THEN
						CASE WHEN  ARALREP.ALAUCD = '02'
							THEN  '\"Keyword' + RTRIM(ARALREP.ALATCD) + '_str\"'
							ELSE ''
						END
					ELSE ''
				END dynamic_datatype2,
				CASE WHEN ARALREP.ALATCD IS NOT NULL
					THEN '\"' + dbo.escapeSpecialCharacters(clkw.lstid) + '\"'
					ELSE ''
				END	dynamic_keyword_value,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN 'en'
					ELSE ''
				END AS lang_en,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN
						CASE WHEN clkw.lstDesc IS NOT NULL
							THEN
								CASE
									WHEN clkw.formatted_json IS NULL or clkw.formatted_json = ''
									THEN '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(clkw.lstDesc))) + '\"'
									ELSE '\"' + dbo.getDescriptionByLanguage(clkw.formatted_json, 'description_', 'en')+ '\"'
								END
							ELSE '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value))) + '\"'
						END
					ELSE ''
				END AS value_en,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN 'fr'
					ELSE ''
				END AS lang_fr,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN
						CASE WHEN clkw.lstDesc IS NOT NULL
							THEN
								CASE
									WHEN clkw.formatted_json IS NULL or clkw.formatted_json = ''
									THEN '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(clkw.lstDesc))) + '\"'
									ELSE '\"' + dbo.getDescriptionByLanguage(clkw.formatted_json, 'description_', 'fr')+'\"'
								END
							ELSE '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value))) + '\"'
						END
					ELSE ''
				END AS value_fr,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN 'de'
					ELSE ''
				END AS lang_de,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN
						CASE WHEN clkw.lstDesc IS NOT NULL
							THEN
								CASE
									WHEN clkw.formatted_json IS NULL or clkw.formatted_json = ''
									THEN '\"'  + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(clkw.lstDesc))) + '\"'
									ELSE '\"' + dbo.getDescriptionByLanguage(clkw.formatted_json, 'description_', 'de')+'\"'
								END
							ELSE '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value))) + '\"'
						END
					ELSE ''
				END AS value_de,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN 'it'
					ELSE ''
				END AS lang_it,
				CASE WHEN ARALREP.ALATCD IS NOT NULL AND ARALREP.ALAUCD ='02'
					THEN
						CASE WHEN clkw.lstDesc IS NOT NULL
							THEN
								CASE
									WHEN clkw.formatted_json IS NULL or clkw.formatted_json = ''
									THEN '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(clkw.lstDesc))) + '\"'
									ELSE '\"' + dbo.getDescriptionByLanguage(clkw.formatted_json, 'description_', 'it')+'\"'
								END
							ELSE '\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(fkw.value))) + '\"'
						END
					ELSE ''
				END AS value_it
			FROM ECM_KWLST clkw WITH (READUNCOMMITTED)
				LEFT JOIN ECM_FKWD fkw WITH (READUNCOMMITTED) on fkw.datatype_id = clkw.kwid and fkw.value = clkw.lstid and fkw.is_close_value = 1
				LEFT JOIN ecm_param dataType_param WITH (READUNCOMMITTED) ON dataType_param.param_id = clkw.kwid and dataType_param.param_type = 'DATATYPE'
				LEFT JOIN #KWDEV_FLD KWDEV ON clkw.kwid = KWDEV.kwdid,
				ARALREP WITH (READUNCOMMITTED),
				#T_FLD_ID FOLDER_ID
			WHERE ARALREP.ALATCD = fkw.datatype_id AND FOLDER_ID.folder_id = fkw.technical_id

	-- build multiple languages for string and close keywords
	SELECT folder_id, datatype_id,
		CASE WHEN lang_key  = 'en'
			THEN json
			ELSE ''
		END as json,
		CASE WHEN lang_key is null or lang_key = ''
		THEN dynamic_datatype
		ELSE
			SUBSTRING(lang_table.dynamic_datatype, 0,
				CASE WHEN LEN(lang_table.dynamic_datatype) = 0
					THEN LEN(lang_table.dynamic_datatype)
				ELSE LEN(lang_table.dynamic_datatype)-1
				END) + '_' + lang_table.lang_key + '\"'
		END as dynamic_datatype,
		CASE WHEN lang_key = 'en'
			THEN dynamic_datatype2
			ELSE ''
		END as dynamic_datatype2,
		CASE WHEN lang_key is null or lang_key = ''
			THEN dynamic_keyword_value
			ELSE lang_value
		END as dynamic_keyword_value,
		CASE WHEN lang_key = 'en'
			THEN dynamic_keyword_value
			ELSE ''
		END as dynamic_keyword_value2
	INTO #FOLDER_KEYWORD1
	FROM
		(SELECT *
		FROM #FOLDER_KEYWORD_ML
			CROSS APPLY (VALUES (lang_en, value_en),
								(lang_fr, value_fr),
								(lang_de, value_de),
								(lang_it, value_it)) AS mul_lang (lang_key, lang_value)
		WHERE mul_lang.lang_key <> '') lang_table

	INSERT INTO #FOLDER_KEYWORD1
		SELECT folder_id, datatype_id, json, dynamic_datatype, dynamic_datatype2, dynamic_keyword_value, dynamic_keyword_value
		FROM #FOLDER_KEYWORD_ML
		WHERE lang_en = ''

	CREATE INDEX #FOLDER_KEYWORD1_IX1 ON #FOLDER_KEYWORD1
	(
		folder_id ASC
	)

	SELECT
		folder_id,
		dbo.escapeXMLCharacters(substring((SELECT ','+json
			FROM #FOLDER_KEYWORD1 t2
			WHERE t1.folder_id = t2.folder_id and t2.datatype_id!='!GNDO'
				and t2.json is not null and t2.json != ''
			FOR XML PATH('')),2,214483647)) json,
		t1.dynamic_datatype dynamic_datatype,
		'[' + dbo.escapeXMLCharacters(substring((SELECT distinct ',' + t2.dynamic_keyword_value
												FROM #FOLDER_KEYWORD1 t2
												WHERE t1.folder_id = t2.folder_id AND
													t1.dynamic_datatype = t2.dynamic_datatype and
													t2.dynamic_keyword_value IS NOT NULL AND
													t2.dynamic_keyword_value !='' AND
													t1.datatype_id <> ''
												FOR XML PATH('')),2,214483647))
		+']' dynamic_keyword_value,
		t1.dynamic_datatype2 dynamic_datatype2,
		'[' + dbo.escapeXMLCharacters(substring((SELECT distinct ',' + t2.dynamic_keyword_value2
												FROM #FOLDER_KEYWORD1 t2
												WHERE t1.folder_id = t2.folder_id AND
													t1.dynamic_datatype2 = t2.dynamic_datatype2 and
													t2.dynamic_keyword_value2 IS NOT NULL AND
													t2.dynamic_keyword_value2 !='' AND
													t1.datatype_id <> ''
												FOR XML PATH('')),2,214483647))
		+']' dynamic_keyword_value2
		INTO #FOLDER_KEYWORD2
	from #FOLDER_KEYWORD1 t1
	GROUP BY folder_id, t1.dynamic_datatype, t1.dynamic_datatype2, t1.datatype_id
	ORDER BY t1.dynamic_datatype, t1.dynamic_datatype2

	INSERT INTO #FOLDER_KEYWORD
		SELECT folder_id,
			dbo.escapeXMLCharacters(json) json,
			dbo.escapeXMLCharacters(substring((SELECT ',' + t2.dynamic_datatype + ':' + t2.dynamic_keyword_value
												FROM #FOLDER_KEYWORD2 t2
												WHERE t1.folder_id = t2.folder_id AND t2.dynamic_keyword_value IS NOT NULL AND t2.dynamic_keyword_value !=''
												FOR XML PATH('')),2,214483647)) dynamic_key_pair,
			dbo.escapeXMLCharacters(substring((SELECT ',' + t2.dynamic_datatype2 + ':' + t2.dynamic_keyword_value2
												FROM #FOLDER_KEYWORD2 t2
												WHERE t1.folder_id = t2.folder_id AND t2.dynamic_keyword_value2 IS NOT NULL AND t2.dynamic_keyword_value2 !=''
												FOR XML PATH('')),2,214483647)) dynamic_key_pair2
		FROM #FOLDER_KEYWORD2 t1
		GROUP BY folder_id, json
	-- ******************* end of building folder keywords ********************

