					THEN dbo.getDefaultDescriptions('origin_', dbo.escapeSpecialCharacters(RTRIM(TPACREF_DB.PacDesc)))
				ELSE REPLACE(REPLACE(dbo.escapeSpecialCharacters(pac_param.formatted_json), 'pacDescription', 'origin'), '\\\"', '\"')
			END
		ELSE
			CASE
				WHEN TPACREF_DB.BaseDesc IS NOT NULL
				THEN
					CASE
						WHEN database_param.formatted_json is null or database_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('origin_', dbo.escapeSpecialCharacters(RTRIM(TPACREF_DB.BaseDesc)))
						ELSE REPLACE(REPLACE(dbo.escapeSpecialCharacters(database_param.formatted_json), '\\\"', '\"'), 'databaseDescription', 'origin')
					END
				ELSE
					dbo.getDefaultDescriptions('origin_', '')
			END
	END
	+
	',\"organizationId\":\"'  +
	CASE
	WHEN TPACREF_DB.OrgId IS NOT NULL
		THEN dbo.escapeSpecialCharacters(RTRIM(TPACREF_DB.OrgId))
	ELSE
		''
	END
	+
	'\",'  +
	CASE
		WHEN TPACREF_DB.OrgDesc IS NOT NULL
			THEN
				CASE
					WHEN organization_param.formatted_json is null or organization_param.formatted_json = ''
						THEN dbo.getDefaultDescriptions('organizationDescription_', dbo.escapeSpecialCharacters(RTRIM(TPACREF_DB.OrgDesc)))
					ELSE
						REPLACE(dbo.escapeSpecialCharacters(organization_param.formatted_json), '\\\"', '\"')
				END
			ELSE
				dbo.getDefaultDescriptions('organizationDescription__', '')
	END
	+
	',\"searchText1\":\"'  +
	CASE WHEN folder.EZH0TX IS NOT NULL AND DATALENGTH(folder.EZH0TX) >= 3 AND left(folder.EZH0TX, 3) = TFLDTYP_HELPER.typeID
		THEN rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(folder.EZH0TX, DATALENGTH(folder.EZH0TX)- 3))))
		ELSE dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(folder.EZH0TX))
	END
	+
	'\",\"searchText2\":\"'  +  dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(folder.DD8gaA)) +
	'\",\"searchText3\":\"'  +  dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(folder.DD8gbA)) +
	'\",\"searchText4\":\"'  +  dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(folder.DD8gcA)) +
	'\",\"searchText\":\"'  +  dbo.escapeSpecialCharacters(LTRIM(RTRIM(
	CASE WHEN EZH0TX IS NOT NULL AND DATALENGTH(EZH0TX) >= 3 AND left(EZH0TX, 3) = TFLDTYP_HELPER.typeID
		THEN dbo.escapeDescriptionSpecialCharacters(rtrim(RIGHT(EZH0TX, DATALENGTH(EZH0TX)- 3)))
	ELSE
	CASE WHEN EZH0TX is null OR EZH0TX='' THEN '' ELSE dbo.escapeDescriptionSpecialCharacters(EZH0TX) END
	END
	+ ' ' + CASE WHEN folder.DD8gaA IS NULL THEN '' ELSE dbo.escapeDescriptionSpecialCharacters(folder.DD8gaA) END + ' ' + CASE WHEN folder.DD8gbA IS NULL THEN '' ELSE dbo.escapeDescriptionSpecialCharacters(folder.DD8gbA) END + ' ' + CASE WHEN folder.DD8gcA IS NULL THEN '' ELSE dbo.escapeDescriptionSpecialCharacters(folder.DD8gcA) END))) +
	'\",\"phoneNumber\":\"'+dbo.escapeSpecialCharacters(ISNULL(EZW2NA,'')) +
	'\",\"faxNumber\":\"'+dbo.escapeSpecialCharacters(ISNULL(EZW3NA,''))+
	'\",\"telexNumber\":\"'+dbo.escapeSpecialCharacters(ISNULL(EZW4NA,''))+
	'\"' + dbo.convertDateField('openingDate',folder.EZCXDT) +
	',\"statusId\":\"'+ ISNULL(EZN9ST,'')+
	'\",' + dbo.getFolderStatusDescriptions(RTRIM(ISNULL(EZN9ST, ''))) + '' +
	CASE WHEN @HAS_FOLDER_TYPE = 0
		THEN ',\"typeId\":\"\",' + dbo.getDefaultDescriptions('type_', '')
	ELSE
		CASE
			WHEN TFLDTYP_HELPER0.typeNme IS NOT NULL AND TFLDTYP_HELPER0.type IS NOT NULL
				THEN ',\"typeId\":\"'+TFLDTYP_HELPER0.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER0.typeID+'\",' +
					CASE
						WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('type_', dbo.escapeDescriptionSpecialCharacters(TFLDTYP_HELPER0.type))
						ELSE
							REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
					END
			WHEN @IS_PAC_MODE = 1 AND TFLDTYP_HELPER.typeNme IS NOT NULL AND TFLDTYP_HELPER.type IS NOT NULL
				THEN ',\"typeId\":\"'+TFLDTYP_HELPER.typeNme+'\",\"pacTypeId\":\"'+TFLDTYP_HELPER.typeID+'\",' +
					CASE
						WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('type_', dbo.escapeDescriptionSpecialCharacters(TFLDTYP_HELPER.type))
						ELSE
							REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
					END
			WHEN @IS_PAC_MODE = 1 AND TFLDTYP_HELPER2.typeNme IS NOT NULL AND TFLDTYP_HELPER2.type IS NOT NULL
				THEN ',\"typeId\":\"'+TFLDTYP_HELPER2.typeNme+'\",\"pacTypeId\":\"\",' +
					CASE
						WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('type_', dbo.escapeDescriptionSpecialCharacters(TFLDTYP_HELPER2.type))
						ELSE
							REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
					END
			WHEN @IS_PAC_MODE = 1 AND TFLDTYP_HELPER3.typeNme IS NOT NULL AND TFLDTYP_HELPER3.type IS NOT NULL
				THEN ',\"typeId\":\"'+TFLDTYP_HELPER3.typeNme+'\",\"pacTypeId\":\"\",' +
					CASE
						WHEN folderType_param.formatted_json is null or folderType_param.formatted_json = ''
							THEN dbo.getDefaultDescriptions('type_', dbo.escapeDescriptionSpecialCharacters(TFLDTYP_HELPER3.type))
						ELSE
							REPLACE(dbo.escapeSpecialCharacters(folderType_param.formatted_json), '\\\"', '\"')
					END
			WHEN @IS_PAC_MODE = 1
				THEN ',\"typeId\":\"\",' + dbo.getDefaultDescriptions('type_', 'Facture')
			ELSE ',\"typeId\":\"\", ' + dbo.getDefaultDescriptions('type_', '')
		END
	END
	+ ',\"labelFolderId\":\"' + ISNULL(TFLDTYP_HELPER.label_folder_id,ISNULL(TFLDTYP_HELPER2.label_folder_id,ISNULL(TFLDTYP_HELPER3.label_folder_id,''))) + '\"'
	+ ',\"labelDescription1\":\"' + ISNULL(TFLDTYP_HELPER.label_description_1,ISNULL(TFLDTYP_HELPER2.label_description_1,ISNULL(TFLDTYP_HELPER3.label_description_1,''))) + '\"'
	+ ',\"labelDescription2\":\"' + ISNULL(TFLDTYP_HELPER.label_description_2,ISNULL(TFLDTYP_HELPER2.label_description_2,ISNULL(TFLDTYP_HELPER3.label_description_2,''))) + '\"'
	+ ',\"labelDescription3\":\"' + ISNULL(TFLDTYP_HELPER.label_description_3,ISNULL(TFLDTYP_HELPER2.label_description_3,ISNULL(TFLDTYP_HELPER3.label_description_3,''))) + '\"'
	+ case when fldkw.FIDT is not null AND fldkw.FIDT !='' then dbo.getFolderKeywordDescriptor(FIDT,FIDT_TYPE,dbo.escapeDescriptionSpecialCharacters(substring(folder.EZF8TX,4,40))) else '' end
	+ case when fldkw.DS1 is not null AND fldkw.DS1 !='' AND EZB7NA is not null AND DATALENGTH(RTRIM(EZB7NA)) > 0 then
				CASE WHEN
					DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
				THEN
					dbo.getFolderKeywordDescriptor(DS1,DS1_TYPE,dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6)))
				ELSE
					CASE WHEN left(EZB7NA, 5) <> '!USER' THEN dbo.getFolderKeywordDescriptor(DS1,DS1_TYPE,dbo.escapeDescriptionSpecialCharacters(EZB7NA)) ELSE '' END
				END
	 else '' end
	+ case when fldkw.DS2 is not null AND fldkw.DS2 !='' AND EZB8NA is not null AND DATALENGTH(RTRIM(EZB8NA)) > 0 then
				CASE WHEN
					DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
				THEN
					dbo.getFolderKeywordDescriptor(DS2,DS2_TYPE,dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6)))

				ELSE
					CASE WHEN left(EZB8NA, 5) <> '!USER' THEN dbo.getFolderKeywordDescriptor(DS2,DS2_TYPE,dbo.escapeDescriptionSpecialCharacters(EZB8NA)) ELSE '' END
				END
	 else '' end
	+ case when fldkw.DS3 is not null AND fldkw.DS3 !='' AND EZB9NA is not null AND DATALENGTH(RTRIM(EZB9NA)) > 0 then
				CASE WHEN
					DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
				THEN
					dbo.getFolderKeywordDescriptor(DS3,DS3_TYPE,dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6)))

				ELSE
					CASE WHEN left(EZB9NA, 5) <> '!USER' THEN dbo.getFolderKeywordDescriptor(DS3,DS3_TYPE,dbo.escapeDescriptionSpecialCharacters(EZB9NA)) ELSE '' END
				END
	 else '' end
	+ ',\"isBlocked\": \"'+
	CASE WHEN additionalAttribute.isBlocked IS NOT NULL AND additionalAttribute.isBlocked = '1'
	THEN 'true'
	ELSE 'false'
	END
	+ '\"'
	+ ',\"businessDataRuleId\":\"'+ ISNULL(CONVERT(VARCHAR(10), additionalAttribute.ruleId), '')
	+ '\"'
	+ CASE WHEN additionalAttribute.expirationDate IS NULL THEN '' ELSE ',\"expirationDate\":\"'+ format((CONVERT(datetime, RTRIM(additionalAttribute.expirationDate)) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff') + 'Z' + '\"' END
	+ ',\"conservation\":{\"delay\": \"'+ RTRIM(ISNULL(conservationAttribute.delay,''))
	+ '\",\"finalFate\":\"'+ RTRIM(ISNULL(conservationAttribute.finalFate,'')) + '\"'
	 + CASE WHEN conservationAttribute.endDate IS NULL THEN '' ELSE ',\"endDate\":\"'+ format((CONVERT(datetime, RTRIM(conservationAttribute.endDate)) at time zone @TimeZone) AT TIME ZONE 'UTC','yyyy-MM-ddTHH:mm:ss.fff')+ 'Z' + '\"' END
	+ ',\"supportedType\":\"'+ RTRIM(ISNULL(conservationAttribute.mediaType,''))
	+ '\"}'
	+ CASE
		WHEN EZB8NA is not null and left(EZB8NA, 5) = '!USER'
		THEN ',\"rh_gen\":[\"' + REPLACE(RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 5)))), ',' ,'\",\"') + '\"]'
		ELSE ''
	END +
	CASE
		WHEN EZB9NA is not null and left(EZB9NA, 5) = '!USER'
		THEN ',\"manager_gen\":[\"' + REPLACE(RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 5)))), ',', '\",\"') + '\"]'
		ELSE ''
	END +
	CASE
		WHEN EZCANA is not null and left(EZCANA, 5) = '!USER'
		THEN ',\"employee_gen\":\"' + RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZCANA, DATALENGTH(EZCANA)- 5)))) + '\"'
		ELSE ''
	END +
	',\"comments\":[' +  ISNULL(t_fld_comment.json,'')  +
	'],\"children\":['+
		ISNULL(LEVEL_CHILDREN.json,'')
	+'], \"parents\":['+
		ISNULL(LEVEL_PARENT.json,'')
	+'],\"objectKeyValues\":[' +
		dbo.buildFolderObjectKeyValues(LTRIM(RTRIM(ISNULL(LEVEL_PARENT.json2,''))),dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix(1,
		CASE
		WHEN
			left(folder.EZF8TX, 3) = TFLDTYP_HELPER.typeID
		THEN
			dbo.escapeDescriptionSpecialCharacters(substring(folder.EZF8TX,4,40))
		ELSE
			dbo.escapeDescriptionSpecialCharacters(RTRIM(folder.EZF8TX))
	END,
	CASE
		WHEN
			DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
		THEN
			rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
		ELSE
			CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
	END,
	CASE
		WHEN
			DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
		THEN
			rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
		ELSE
			CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
	END,
	CASE
		WHEN
			DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
		THEN
			rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
		ELSE
			CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
	END,
	CASE WHEN left(folder.EZCANA, 5) <> '!USER' THEN folder.EZCANA ELSE '' END ))
	+'],\"docSecurityClasses\":[],\"ancestors\":['+ isnull(parent_folder_temp.json,'')+']'
	+
	CASE WHEN fkw.dynamic_key_pair <> ''
		THEN ',' + fkw.dynamic_key_pair
		ELSE ''
	END
	+
	CASE WHEN fkw.dynamic_key_pair2 <> ''
		THEN ',' + fkw.dynamic_key_pair2
		ELSE ''
	END
	+ '}' , +
	'","objectSecurityClasses":[[' + ISNULL(t_fld_ddsecclass.first_sec_class,'')+ '],[],[]],' +
	'"objectKeyValues":[' +
		dbo.buildFolderObjectKeyValues(isnull(fkw.json, ''),dbo.buildFolderBusinessIdAndDescription1234WithoutZeroPrefix(0,
			CASE
			WHEN
				left(folder.EZF8TX, 3) = TFLDTYP_HELPER.typeID
			THEN
				dbo.escapeDescriptionSpecialCharacters(substring(folder.EZF8TX,4,40))
			ELSE
				dbo.escapeDescriptionSpecialCharacters(RTRIM(folder.EZF8TX))
		END,
		CASE
			WHEN
				DATALENGTH(EZB7NA) >= 6 and left(EZB7NA, 6) in (TFLDTYP_HELPER.prefixDs1,TFLDTYP_HELPER2.prefixDs1)
			THEN
				rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB7NA, DATALENGTH(EZB7NA)- 6))))
			ELSE
				CASE WHEN left(EZB7NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB7NA))) ELSE '' END
		END,
		CASE
			WHEN
				DATALENGTH(EZB8NA) >= 6 and left(EZB8NA, 6) in (TFLDTYP_HELPER.prefixDs2,TFLDTYP_HELPER2.prefixDs2)
			THEN
				rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB8NA, DATALENGTH(EZB8NA)- 6))))
			ELSE
				CASE WHEN left(EZB8NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB8NA))) ELSE '' END
		END,
		CASE
			WHEN
				DATALENGTH(EZB9NA) >= 6 and left(EZB9NA, 6) in (TFLDTYP_HELPER.prefixDs3,TFLDTYP_HELPER2.prefixDs3)
			THEN
				rtrim(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(RIGHT(EZB9NA, DATALENGTH(EZB9NA)- 6))))
			ELSE
				CASE WHEN left(EZB9NA, 5) <> '!USER' THEN RTRIM(dbo.escapeSpecialCharacters(dbo.escapeDescriptionSpecialCharacters(EZB9NA))) ELSE '' END
		END,
		CASE WHEN left(folder.EZCANA, 5) <> '!USER' THEN folder.EZCANA ELSE '' END ))
	+ ']'
	json
	FROM #T_FLD_ID FOLDER_ID
	LEFT JOIN AREZCPP folder WITH (READUNCOMMITTED) on folder.EZBUNU = FOLDER_ID.folder_id
	LEFT JOIN ECM_FADDL additionalAttribute  WITH (READUNCOMMITTED) ON convert(char(20),folder.EZBUNU) = additionalAttribute.folderId
	LEFT JOIN ECM_FCONS conservationAttribute  WITH (READUNCOMMITTED) ON convert(char(20),folder.EZBUNU) = conservationAttribute.folderId
	LEFT JOIN T_FLD_P_LV LEVEL_PARENT WITH (READUNCOMMITTED)  ON LEVEL_PARENT.id = folder.EZBUNU
	LEFT JOIN T_FLD_C_LV LEVEL_CHILDREN  WITH (READUNCOMMITTED) ON LEVEL_CHILDREN.id = folder.EZBUNU
	LEFT JOIN ARAOREP db  WITH (READUNCOMMITTED) ON folder.EZAWCD = db.AOAWCD
	LEFT JOIN ARAJREP dept  WITH (READUNCOMMITTED) ON folder.DD46A = dept.AJAOCD
	LEFT JOIN PACREF_HELPERV  WITH (READUNCOMMITTED) ON PACREF_HELPERV.BASE = folder.EZAWCD AND (PACREF_HELPERV.depId = folder.DD46A OR
							(PACREF_HELPERV.depId is null and  folder.DD46A ='') OR
							(PACREF_HELPERV.depId = '' and  folder.DD46A is null))
	LEFT JOIN TPACREF_DB TPACREF_DB  WITH (READUNCOMMITTED) ON TPACREF_DB.baseId = folder.EZAWCD
	LEFT JOIN FLDKWV fldkw WITH (READUNCOMMITTED) ON DATALENGTH(folder.EZF8TX) >= 3 AND left(folder.EZF8TX, 3) = fldkw.typeID AND folder.EZAWCD= fldkw.baseId and fldkw.orgId = TPACREF_DB.OrgId
	LEFT JOIN FLDTYPV TFLDTYP_HELPER0  WITH (READUNCOMMITTED) ON additionalAttribute.folderType = TFLDTYP_HELPER0.typeNme AND
								folder.EZAWCD = TFLDTYP_HELPER0.base AND
								additionalAttribute.folderType IS NOT NULL AND additionalAttribute.folderType <> ''
	LEFT JOIN FLDTYPV TFLDTYP_HELPER  WITH (READUNCOMMITTED) ON
									DATALENGTH(folder.EZF8TX) >= 3 AND
									left(folder.EZF8TX, 3) = TFLDTYP_HELPER.typeID AND
									folder.EZAWCD = TFLDTYP_HELPER.base
	LEFT JOIN FLDTYPV TFLDTYP_HELPER2  WITH (READUNCOMMITTED) ON
										TFLDTYP_HELPER.base IS NULL AND
										folder.EZAWCD = TFLDTYP_HELPER2.base AND
										DATALENGTH(folder.EZB7NA) >= 6 AND
										LEFT(folder.EZB7NA, 1) = '!' AND
										LEFT(folder.EZB7NA, 6) = TFLDTYP_HELPER2.prefixDs1
	LEFT JOIN FLDTYPV TFLDTYP_HELPER3  WITH (READUNCOMMITTED) ON
										TFLDTYP_HELPER.base IS NULL AND
										TFLDTYP_HELPER2.base IS NULL AND
										DATALENGTH(folder.EZB7NA) >= 1 AND
										LEFT(folder.EZB7NA, 1) != '!' AND
										folder.EZAWCD = TFLDTYP_HELPER3.base AND
										TFLDTYP_HELPER3.typeID =''
	LEFT JOIN T_FLD_COMMENT t_fld_comment WITH (READUNCOMMITTED) ON folder.EZAWCD = t_fld_comment.database_id AND folder.EZF8TX = t_fld_comment.folder_id
	LEFT JOIN #TPARFLD parent_folder_temp ON parent_folder_temp.databaseid = folder.EZAWCD AND parent_folder_temp.folderid = folder.EZF8TX
	LEFT JOIN #T_FLD_DDSECCLASS t_fld_ddsecclass ON convert(char(50),folder.EZBUNU) = t_fld_ddsecclass.folder_id
	LEFT JOIN ecm_param folderType_param WITH (READUNCOMMITTED) ON folderType_param.param_id = RTRIM(ISNULL(TFLDTYP_HELPER0.typeNme,
																											case when @IS_PAC_MODE = 1
																											then ISNULL(TFLDTYP_HELPER.typeNme, ISNULL(TFLDTYP_HELPER2.typeNme, ISNULL(TFLDTYP_HELPER3.typeNme, 'Facture'))) else ''
																											end )) AND folderType_param.param_type = 'FOLDERTYPE'
	LEFT JOIN ecm_param database_param WITH (READUNCOMMITTED) ON database_param.param_id = folder.EZAWCD AND database_param.param_type = 'DATABASE'
	LEFT JOIN ecm_param organization_param WITH (READUNCOMMITTED) ON organization_param.param_id = TPACREF_DB.OrgId AND organization_param.param_type = 'ORGANIZATION'
	LEFT JOIN ecm_param pac_param WITH (READUNCOMMITTED) ON pac_param.param_id = TPACREF_DB.PacId AND pac_param.param_type = 'PAC'
	LEFT JOIN #FOLDER_KEYWORD fkw ON folder.EZBUNU = fkw.folder_id
	OPTION (FORCE ORDER)

	drop table #KWDEV_FLD
	drop table #FOLDER_KEYWORD1
	drop table #FOLDER_KEYWORD2

	IF(@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '11'

	-- ******************* return final result *******************
	IF(@V_IS_READ_SINGLE_FOLDER = 1)
		BEGIN
			SET @FETCH_STATUS = 1
			SELECT @OBJECT_DESCRIPTOR = (SELECT '{"objectDescriptors":{' + basicinfo.json + basicinfo.json2 + basicinfo.json3 + '}}'
			FROM #T_FLD_BASIC basicinfo )
		END
	ELSE
		BEGIN
		    BEGIN TRAN
                -- gitlab#130 - apply semaphore
                SELECT @Semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

                INSERT INTO TFLDDESC
                    SELECT @SESSION_ID,@batch_id, 'XECM-FOLDER--'+UPPER(@V_CLIENTHOSTNAME)+'-'+ cast(basicinfo.folder_id as varchar(100)),
                           '{"objectDescriptors":{' + basicinfo.json + basicinfo.json2 + basicinfo.json3 + '}}', REPLACE(basicinfo.json2, '\"', '"')
                    FROM
                        #T_FLD_BASIC basicinfo

                UPDATE INDEXATION_BATCH SET COMPUTED = 1 WHERE CURRENT OF batch_cursor
            COMMIT

			if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '12'

			FETCH batch_cursor INTO @batch_id, @batch_start, @batch_end
				SET @FETCH_STATUS = @@FETCH_STATUS
		END
	END

	if @V_IS_READ_SINGLE_FOLDER = 0
		BEGIN
			if ( @V_ISDEBUGGING = 1 ) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '13'

			CLOSE batch_cursor
			DEALLOCATE batch_cursor
		END

	-- index document inside indexed folders
	IF @V_ACTION <> 'EXPORTJSON'
		BEGIN
			BEGIN TRAN
			SELECT @Semaphore = id FROM semaphore_document WITH( HOLDLOCK, TABLOCKX )

			IF @V_IS_READ_SINGLE_FOLDER = 1
				BEGIN
					UPDATE  ARG0CPP
					   SET  DDr68A = 'N',
					        errDetail = NULL
					  --FROM  ARARREP WITH (READUNCOMMITTED)
					  WHERE DDr68A IN ('I', 'F', 'E') AND
						    --ARARREP.ARASVN = ARG0CPP.DD1rA AND
						    --ARARREP.ARAPCD = @DATABASEID AND
						    --ARARREP.ARAETX = @FOLDERID and
						    DD1RA in (select arasvn from ARARREP where ARARREP.ARAPCD = @DATABASEID 
						    									   AND ARARREP.ARAETX = @FOLDERID)
						  	AND
							(
							   ARG0CPP.DD1RA in ( select distinct ARASVN  FROM ARARREP 
																 
																 LEFT JOIN AREZCPP ON  AREZCPP.EZAWCD = ARARREP.ARAPCD
																				   and AREZCPP.EZF8TX = ARARREP.ARAETX 
																 LEFT JOIN AREZCPP_REF ON  AREZCPP_REF.EZAWCD = ARARREP.ARAPCD
																				   and AREZCPP_REF.EZF8TX = ARARREP.ARAETX
																 where AREZCPP_REF.EZCANA <> AREZCPP.EZCANA 
																				   OR AREZCPP_REF.ezb7na <> AREZCPP.ezb7na 
																				   OR AREZCPP_REF.ezb8na <> AREZCPP.ezb8na 
																				   OR AREZCPP_REF.ezb9na <> AREZCPP.ezb9na
																				   AND ARARREP.ARAPCD = @DATABASEID 
																				   AND ARARREP.ARAETX = @FOLDERID)
								)											   
																			   
						   
					DELETE FROM AREZCPP_REF where AREZCPP_REF.EZBUNU NOT IN (select distinct EZBUNU from AREZCPP)
					DELETE FROM AREZCPP_REF where AREZCPP_REF.EZBUNU IN (select distinct folder_id from #T_FLD_ID)
					INSERT INTO AREZCPP_REF  SELECT distinct * FROM AREZCPP WITH (READUNCOMMITTED)  where AREZCPP.EZBUNU IN (select distinct folder_id from #T_FLD_ID)
					
					
				END
				ELSE IF ( @V_ACTION = 'PROCESSOR' )
				BEGIN
					UPDATE ARG0CPP
					   SET DDr68A = 'N',
					       errDetail = NULL
					  FROM ARARREP WITH (READUNCOMMITTED),
						   ECM_FLDIDX
					
					 WHERE DDr68A IN ('I', 'F', 'E') AND
						   ARARREP.ARASVN = ARG0CPP.DD1rA AND
						   ARARREP.ARAPCD = database_id AND
						   ARARREP.ARAETX = business_id AND
						   SESSION_ID = @SESSION_ID and
						   (
								ARG0CPP.DD1RA in ( select distinct ARASVN  FROM ARARREP 
															 
														     LEFT JOIN AREZCPP ON  AREZCPP.EZAWCD = ARARREP.ARAPCD
											                                   and AREZCPP.EZF8TX = ARARREP.ARAETX 
							                                 LEFT JOIN AREZCPP_REF ON  AREZCPP_REF.EZAWCD = ARARREP.ARAPCD
												                               and AREZCPP_REF.EZF8TX = ARARREP.ARAETX
							                                 where AREZCPP_REF.EZCANA <> AREZCPP.EZCANA 
											                                   OR AREZCPP_REF.ezb7na <> AREZCPP.ezb7na 
											                                   OR AREZCPP_REF.ezb8na <> AREZCPP.ezb8na 
											                                   OR AREZCPP_REF.ezb9na <> AREZCPP.ezb9na
																			   AND ARARREP.ARAPCD = database_id 
																			   AND ARARREP.ARAETX = business_id
																			   AND SESSION_ID = @SESSION_ID)
							)

					DELETE FROM AREZCPP_REF where AREZCPP_REF.EZBUNU NOT IN (select distinct EZBUNU from AREZCPP)
					DELETE FROM AREZCPP_REF where AREZCPP_REF.EZBUNU IN (select distinct folder_id from #T_FLD_ID)
					INSERT INTO AREZCPP_REF  SELECT distinct * FROM AREZCPP WITH (READUNCOMMITTED)  where AREZCPP.EZBUNU IN (select distinct folder_id from #T_FLD_ID)
					
				END
			COMMIT
		END


	IF ( @V_ACTION = 'PROCESSOR' )
		BEGIN
			IF EXISTS ( SELECT * FROM ecm_idx_f WITH (READUNCOMMITTED) WHERE status = 'L' ) -- The processor has been restarted
				DELETE FROM ecm_idx_f WHERE status IN ( 'S', 'L' )

			BEGIN TRAN
				SELECT @Semaphore = id FROM semaphore_folder WITH( HOLDLOCK, TABLOCKX )

				UPDATE ecm_idx_f
				   SET status = 'I',
					   errDetail = NULL
				  FROM ECM_FLDIDX
				 WHERE ECM_FLDIDX.SESSION_ID = @SESSION_ID AND
					   FOLDER_ID = folderId AND
					   ( modifDate <= @INDEXATION_START OR modifDate is null )

				DELETE FROM ECM_FLDIDX WHERE SESSION_ID = @SESSION_ID

				SELECT @FOLDER_TO_INDEX = COUNT(*) FROM ecm_idx_f WHERE status IN ( 'R', 'M', 'N', 'C' ) AND NOT EXISTS ( SELECT * FROM ECM_FLDIDX WHERE folderId = FOLDER_ID )
			COMMIT
		END

	TRUNCATE TABLE #TCHILDRENSFLD_HELPER
	TRUNCATE TABLE #TCHILDRENSFLD_HELPER1

	END

	IF(@V_ISDEBUGGING = 1) INSERT INTO DEBUG (BATCH_ID, STEP) SELECT @batch_id, '14'

-- uncomment to enable try..catch block
-- 	/*END TRY
