------------------------------------------------------------------------------------------------
-- CREATE STORE PROCEDURE USED TO RETURN A ROW FROM INDEXATION_BATCH READY TO BE SENT TO SOLR --
------------------------------------------------------------------------------------------------
-- /*


SET QUOTED_IDENTIFIER OFF
GO
SET ANSI_NULLS ON
GO

EXEC ('IF EXISTS (SELECT * FROM sysobjects WHERE id = object_id(N''findNextIndexationBatch'') AND OBJECTPROPERTY(id, N''IsProcedure'') = 1)
		BEGIN
			DROP PROCEDURE findNextIndexationBatch
		END')
GO

CREATE PROCEDURE findNextIndexationBatch
	@hostName VARCHAR(255) = NULL,			-- The server's name looking for a row from INDEXATION_BATCH
    @processorBatchOnly INT = 0,            -- #193 - allow to pickup the computed batches belong to action PROCESSOR only until all the batches of mass indexation are calculated
	@batchId INT OUTPUT,
	@priority INT OUTPUT
AS
BEGIN
   -- Script version name: 3.5.0 23q1
         -- The version mentioned here doesn't necessarily match the EAR version
         -- Check the "Minimal required script version number" section within the ReadMe.html file distributed with the project to know if the procedure has to be updated
   -- Script last modificationDate(dd/mm/yyyy): 24/04/2022 09:34

	BEGIN TRAN
	DECLARE @semaphore_indexation_batch INT
	SELECT @semaphore_indexation_batch = id FROM semaphore_indexation_batch WITH( HOLDLOCK, TABLOCKX )

	SELECT @batchId = 0
	SELECT @priority = 0
    IF(@processorBatchOnly = 1)
        BEGIN
            SELECT TOP 1 @batchId = BATCH_ID, @priority = PRIORITY FROM INDEXATION_BATCH WHERE SESSION_ID <> 'XECM4PROCESSORIDX' AND COMPUTED = 1 AND SOLR_STATUS = 0 AND HOST_NAME IS NULL ORDER BY PRIORITY DESC, BATCH_ID
        END
    ELSE
        BEGIN
	        SELECT TOP 1 @batchId = BATCH_ID, @priority = PRIORITY FROM INDEXATION_BATCH WHERE COMPUTED = 1 AND SOLR_STATUS = 0 AND HOST_NAME IS NULL ORDER BY PRIORITY DESC, BATCH_ID
        END

	UPDATE INDEXATION_BATCH SET HOST_NAME = @hostName, TIMESTAMP = getdate() WHERE BATCH_ID = @batchId
	COMMIT
END
GO
;

